function escapeSqlValue(value = "") {
  return String(value).replace(/'/g, "''");
}

function upperKeysLocal(obj = {}) {
  const out = {};
  Object.keys(obj || {}).forEach(key => {
    out[String(key).toUpperCase()] = obj[key];
  });
  return out;
}

function queryComentariosOGA_SQL({ idOga = null, idComentario = null, username = null, origen = null, includeInactive = false } = {}) {
  const comentarios = [];
  const conditions = [];
  if (idOga) conditions.push(`id_oga='${escapeSqlValue(idOga)}'`);
  if (idComentario) conditions.push(`id_comentario='${escapeSqlValue(idComentario)}'`);
  if (username) conditions.push(`autor_comentario_usuario='${escapeSqlValue(username)}'`);
  if (origen) conditions.push(`origen='${escapeSqlValue(origen)}'`);
  if (!includeInactive) {
    conditions.push(`sn_activo=1`);
  }
  const condicion = conditions.length ? conditions.join(" AND ") : "1=1";

  try {
    $.ajax({
      url: `${OGA_SQL_API_BASE}/query`,
      method: "POST",
      async: false,
      contentType: "application/json",
      data: JSON.stringify({
        campos: "*",
        origen: OGA_SQL_COMMENTS_TABLE,
        condicion
      }),
      success: function (resp) {
        const rows = Array.isArray(resp) ? resp : (resp ? [resp] : []);
        rows.forEach(row => {
          if (!row) return;
          comentarios.push({
            spItemId: row.id || "",
            idComentario: row.id_comentario || "",
            idAmc: row.id_oga || "",
            idPadre: row.id_respuesta || "0",
            comentario: row.comentario || "",
            fechaComentario: row.fecha_comentario || "",
            autorComentarioNombres: row.autor_comentario_nombres || "",
            autorComentarioUsuario: row.autor_comentario_usuario || "",
            documentoAdjunto: row.documento_adjunto || "",
            origen: row.origen || ""
          });
        });
      }
    });
  } catch (e) {
    console.warn("Comentarios OGA SQL exception:", e);
  }

  return comentarios;
}

function insertComentarioOGA_SQL({ data = {}, onSuccess = null, onError = null } = {}) {
  const origen = (data.origen || "").toString().trim().toUpperCase();
  if (origen !== "AMC" && origen !== "CDU") {
    if (typeof onError === "function") {
      onError(null, "validation", "Origen invalido (AMC/CDU)");
    }
    return;
  }
  const payload = {
    tabla: OGA_SQL_COMMENTS_TABLE,
    datos: upperKeysLocal({
      ...data,
      sn_activo: (data && data.sn_activo !== undefined && data.sn_activo !== null) ? data.sn_activo : 1
    })
  };
  $.ajax({
    url: `${OGA_SQL_API_BASE}/insert`,
    method: "POST",
    contentType: "application/json",
    data: JSON.stringify(payload),
    success: function (resp) {
      if (typeof onSuccess === "function") onSuccess(resp);
    },
    error: function (xhr, status, errorThrown) {
      if (typeof onError === "function") onError(xhr, status, errorThrown);
    }
  });
}

function updateComentarioOGA_SQL({ data = {}, condicion = "", onSuccess = null, onError = null } = {}) {
  if (data.origen !== undefined) {
    const origen = (data.origen || "").toString().trim().toUpperCase();
    if (origen !== "AMC" && origen !== "CDU") {
      if (typeof onError === "function") {
        onError(null, "validation", "Origen invalido (AMC/CDU)");
      }
      return;
    }
  }
  const payload = {
    tabla: OGA_SQL_COMMENTS_TABLE,
    datos: upperKeysLocal(data),
    condicion
  };
  $.ajax({
    url: `${OGA_SQL_API_BASE}/update`,
    method: "PUT",
    contentType: "application/json",
    data: JSON.stringify(payload),
    success: function (resp) {
      if (typeof onSuccess === "function") onSuccess(resp);
    },
    error: function (xhr, status, errorThrown) {
      if (typeof onError === "function") onError(xhr, status, errorThrown);
    }
  });
}

function debounce(fn, wait = 300) {
  let timeoutId = null;
  return function (...args) {
    const context = this;
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => fn.apply(context, args), wait);
  };
}

