// Carga perezosa del chatbot flotante para todas las poginas que usen suite.js
(function loadGlobalChatbot() {
  const LOADER_ID = "oga-chatbot-loader";
  if (document.getElementById(LOADER_ID)) return;

  function inject() {
    if (document.getElementById(LOADER_ID)) return;
    const s = document.createElement("script");
    s.id = LOADER_ID;
    s.src = `js/chatbot/chatbot_main.js?v=${Date.now()}`;
    s.async = true;
    s.onload = function () {
      if (window.ogaChatbot && typeof window.ogaChatbot.init === "function") {
        window.ogaChatbot.init();
      }
    };
    document.head.appendChild(s);
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", inject);
  } else {
    inject();
  }
})();

// Loader de funcionalidades estacionales (navidad).
(function loadSeasonalEffects() {
  const LOADER_ID = "oga-seasonal-effects";
  if (document.getElementById(LOADER_ID)) return;

  function inject() {
    if (document.getElementById(LOADER_ID)) return;
    const s = document.createElement("script");
    s.id = LOADER_ID;
    s.src = `js/seasonal_effects.js?v=${Date.now()}`;
    s.async = true;
    document.head.appendChild(s);
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", inject);
  } else {
    inject();
  }
})();

