// Función helper para verificar si un script ya está cargado
function documentIncludesScript(url) {
  const scripts = document.getElementsByTagName('script');
  for (let i = 0; i < scripts.length; i++) {
    if (scripts[i].src.includes(url)) {
      return true;
    }
  }
  return false;
}

// Función para cargar scripts dinámicamente
function loadScript(url) {
  if (documentIncludesScript(url)) {
    return Promise.resolve();
  }

  return new Promise(function (resolve, reject) {
    var script = document.createElement('script');
    script.src = url;
    script.onload = resolve;
    script.onerror = reject;
    document.body.appendChild(script);
  });
}

function setChartDocumentacionOficiales() {
  let percentagesDrawn = 0;
  const owner = getEmployeeCodeByUser();
  const tablasOficialesDesglosado = getTablasOwnerDesglosado(owner);

  if (!tablasOficialesDesglosado) {
    console.warn("[setChartDocumentacionOficiales] No hay usuario o datos de tablas oficiales para graficar.");
    return;
  }

  let tablasDocumentadas = tablasOficialesDesglosado.documentadas || 0;
  let tablasSinDocumentar = tablasOficialesDesglosado.sinDocumentar || 0;
  let chartTooltip = {
    borderWidth: 0.5,
    bodySpacing: 10,
    xPadding: 15,
    yPadding: 15,
    cornerRadius: 0.15,
    displayColors: false,
    backgroundColor: 'rgba(0, 0, 0, 1)', // Cambia a tu color deseado con opacidad 1
    titleFontColor: 'rgba(255, 255, 255, 1)', // Color del título con opacidad 1
    bodyFontColor: 'rgba(255, 255, 255, 1)', // Color del texto del cuerpo con opacidad 1
  };

  // Define el texto que quieres mostrar en el centro
  let centerText = tablasOficialesDesglosado.totalOficiales || 0;
  if (centerText != undefined) {
    centerText = centerText.toString();
  }

  // Registra el plugin personalizado
  const centerTextPlugin = {
    afterDatasetsUpdate: function (chart) { },
    beforeDraw: function (chart) {
      var width = chart.chartArea.right;
      var height = chart.chartArea.bottom;
      var ctx = chart.chart.ctx;
      ctx.restore();

      var activeLabel = chart.data.labels[0];
      var activeValue = chart.data.datasets[0].data[0];
      var dataset = chart.data.datasets[0];
      var meta = dataset._meta[Object.keys(dataset._meta)[0]];
      var total = meta.total;

      var activePercentage = parseFloat(
        ((activeValue / total) * 100).toFixed(1)
      );
      activePercentage = chart.legend.legendItems[0].hidden
        ? 0
        : activePercentage;

      if (chart.pointAvailable) {
        activeLabel = chart.data.labels[chart.pointIndex];
        activeValue =
          chart.data.datasets[chart.pointDataIndex].data[chart.pointIndex];

        dataset = chart.data.datasets[chart.pointDataIndex];
        meta = dataset._meta[Object.keys(dataset._meta)[0]];
        total = meta.total;
        activePercentage = parseFloat(
          ((activeValue / total) * 100).toFixed(1)
        );
        activePercentage = chart.legend.legendItems[chart.pointIndex].hidden
          ? 0
          : activePercentage;
      }

      ctx.font = "1rem" + " Nunito, sans-serif";
      ctx.fillStyle = "#373737";
      ctx.textBaseline = "middle";

      var text = tablasOficialesDesglosado.totalOficiales || "0",
        textX = Math.round((width - ctx.measureText(text).width) / 2),
        textY = height / 2 - 5;
      ctx.fillText(text, textX, textY);

      ctx.font = "0.75rem" + " Nunito, sans-serif";
      ctx.textBaseline = "middle";

      var text2 = "Tablas",
        textX = Math.round((width - ctx.measureText(text2).width) / 2),
        textY = height / 2 + 15;
      ctx.fillText(text2, textX, textY);

      ctx.save();
    },
  };


  let doughnut = document.getElementById("chartDocumentacionOficiales")
  const documentacionCart = new Chart(doughnut, {
    plugins: [centerTextPlugin],
    type: "doughnut",
    data: {
      labels: ["Documentas", "Sin Documentar"],
      datasets: [{
        label: "",
        borderColor: ["#D2006E", "#160F41"],
        backgroundColor: ["#D2006E", "#160F41"],
        borderWidth: 2,
        // data: [valor > 100 ? 0 : valor, valor > 100? 100 : 100 - valor]
        data: [tablasDocumentadas, tablasSinDocumentar]
      }]
    },
    options: {
      elements: {
      },
      plugins: {
        datalabels: {
          display: false
        }
      },
      responsive: true,
      maintainAspectRatio: false,
      cutoutPercentage: 80,
      title: {
        display: false,
        text: "Documentación de tablas",
        fontStyle: "Nunito, sans-serif",
        minFontSize: 28,
        maxFontSize: 28
      },
      layout: {
        padding: {
          bottom: 20
        }
      },
      legend: {
        display: true,
        position: "bottom",
      }
    }
  });
}

