//Obtener todos los Dominios y por separado los derivados, transaccionales y maestros
// Obtener todos los Dominios y por separado los derivados, transaccionales y maestros
async function getDominiosAll() {
  let dominios = [];
  let maestros = [];
  let derivados = [];
  let transaccionales = [];

  try {
    // 1. Obtenemos todos los dominios activos a través del servicio SQL
    dominios = await window.DominiosService.getAll() || [];

    // 2. Clasificamos cada dominio según su tipo
    dominios.forEach(item => {
      // Mapeo flexible para soportar tanto 'Tipo' como 'tipo_dominio' 
      // dependiendo de cómo se llame la columna en tu vista/tabla SQL
      const tipo = (item.Tipo || item.tipo_dominio || "").trim();

      if (tipo === "Dominio Maestro") {
        maestros.push(item);
      } else if (tipo === "Dominio Derivado") {
        derivados.push(item);
      } else if (tipo === "Dominio Transaccional") {
        transaccionales.push(item);
      }
    });

  } catch (error) {
    console.error("[getDominiosAll] Error al obtener y clasificar los dominios:", error);
  }

  return { dominios, maestros, derivados, transaccionales };
}

async function getDominiosAllAPI() {
  const dominios = [];
  const maestros = [];
  const derivados = [];
  const transaccionales = [];

  try {
    const body = {
      campos:
        "md.codigo_Dominio, md.descripcion_dominio, md.Conceptos_Clave, md.descripcion, md.COM, md.IMPACT, md.Tipo, md.Familia_de_Dominios, md.lider_sugerido, md.atributos_basicos, md.id_tipo_dominio, md.id_tipo_familia, md.id_dominio, md.sn_activo, " +
        "(SELECT COUNT(*) FROM procesos_bi.dbo.t_subdominios s WHERE s.id_dominio = md.id_dominio) AS subdominios, " +
        "(SELECT COUNT(*) FROM procesos_bi.dbo.t_estructura_gobierno eg WHERE eg.sn_activo = 1 AND eg.id_subdominio IN (SELECT s.id_subdominio FROM procesos_bi.dbo.t_subdominios s WHERE s.id_dominio = md.id_dominio)) AS cant_estructura, " +
        "(SELECT AVG(CAST(d.porcentaje_avance AS decimal(9,4))) FROM procesos_bi.dbo.t_pasos_dominio_desarrollo d " +
        " WHERE d.sn_aplica = 1 AND d.id_subdominio IN (SELECT s.id_subdominio FROM procesos_bi.dbo.t_subdominios s WHERE s.id_dominio = md.id_dominio) " +
        "   AND d.fecha_carga = (SELECT MAX(d2.fecha_carga) FROM procesos_bi.dbo.t_pasos_dominio_desarrollo d2 WHERE d2.id_subdominio = d.id_subdominio AND d2.id_paso = d.id_paso)) AS porcentaje_avance_dominio, " +
        "CAST(0 AS int) AS cant_atributos, CAST(0 AS int) AS cant_terminos, CAST(0 AS int) AS cant_modelos",
      origen: "procesos_bi.dbo.t_mapa_dominios md",
      condicion: "md.sn_activo = 1"
    };

    const response = await fetch("http://gobinfoana01-2:8510/query", {
      method: "POST",
      headers: {
        accept: "application/json",
        "Content-Type": "application/json"
      },
      body: JSON.stringify(body)
    });

    if (!response.ok) {
      const text = await response.text().catch(() => "");
      throw new Error(`? Error en la petición (${response.status}): ${response.statusText} ${text}`);
    }

    const data = await response.json();

    data.forEach((row) => {
      const dominio = {
        codigo_Dominio: row.codigo_Dominio,
        descripcion_dominio: row.descripcion_dominio,
        Conceptos_Clave: row.Conceptos_Clave,
        descripcion: row.descripcion,
        COM: row.COM,
        IMPACT: row.IMPACT,
        tipo_dominio: row.Tipo,
        Familia_de_Dominios: row.Familia_de_Dominios,
        lider_sugerido: row.lider_sugerido,
        atributos_basicos: row.atributos_basicos,
        id_tipo_dominio: row.id_tipo_dominio,
        id_tipo_familia: row.id_tipo_familia,
        id_dominio: row.id_dominio,
        sn_activo: row.sn_activo,

        porcentaje_avance_dominio: row.porcentaje_avance_dominio,
        cant_atributos: row.cant_atributos,
        cant_terminos: row.cant_terminos,
        cant_modelos: row.cant_modelos,
        cant_estructura: row.cant_estructura,
        subdominios: row.subdominios
      };

      if (dominio.tipo_dominio === "Dominio Maestro" && dominio.sn_activo == 1) maestros.push(dominio);
      if (dominio.tipo_dominio === "Dominio Derivado" && dominio.sn_activo == 1) derivados.push(dominio);
      if (dominio.tipo_dominio === "Dominio Transaccional" && dominio.sn_activo == 1) transaccionales.push(dominio);

      dominios.push(dominio);
    });
  } catch (err) {
    console.error("?? Error obteniendo dominios:", err);
  }

  return { dominios, maestros, derivados, transaccionales };
}



