function getInfoTablasOficialesTemp() {
  let lista = {};

  $().SPServices({
    operation: "GetListItems",
    async: false,
    listName: "Z_METADATA_TABLAS",
    CAMLViewFields: "<ViewFields>\
      <FieldRef Name='txt_desc_tabla' />\
      <FieldRef Name='descripcion_tabla' />\
      <FieldRef Name='usuario_modificacion_descripcion' />\
      <FieldRef Name='fecha_modificacion_descripcion' />\
      <FieldRef Name='descripcion_dominio' />\
      <FieldRef Name='txt_fuente_aprovisionamiento' />\
      <FieldRef Name='txt_servidor' />\
      <FieldRef Name='txt_host' />\
      <FieldRef Name='txt_fuente_esquema' />\
      <FieldRef Name='data_owner' />\
      <FieldRef Name='nombre_data_owner' />\
      <FieldRef Name='usuario_modificacion_do' />\
      <FieldRef Name='fecha_modificacion_do' />\
      <FieldRef Name='data_steward' />\
      <FieldRef Name='nombre_data_steward' />\
      <FieldRef Name='usuario_modificacion_ds' />\
      <FieldRef Name='fecha_modificacion_ds' />\
      <FieldRef Name='clasificacion' />\
      <FieldRef Name='usuario_modificacion_clasif' />\
      <FieldRef Name='fecha_modificacion_clasif' />\
      <FieldRef Name='etiquetas' />\
      <FieldRef Name='usuario_modificacion_etiqueta' />\
      <FieldRef Name='fecha_modificacion_etiqueta' />\
      <FieldRef Name='avance' />\
    </ViewFields>",
    completefunc: function (xData) {
      const upperClean = (v, def = " ") => {
        const s = String(v ?? def)
          .toUpperCase()
          .trim()
          .replaceAll('(', '\\(')
          .replaceAll(')', '\\)')
          .replaceAll('<BR>', '')
          .replaceAll('\\', '');
        return s === "" ? def : s;
      };
      const norm = (v, def = " ") => {
        const decoded = String(v ?? def)
          .replace(/&lt;/gi, '<')
          .replace(/&gt;/gi, '>')
          .replace(/&amp;/gi, '&')
          .replace(/&nbsp;/gi, ' ');
        const stripped = decoded.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
        return stripped === "" ? def : stripped;
      };

      $(xData.responseXML).SPFilterNode("z:row").each(function () {
        const servidor_txt = upperClean($(this).attr("ows_txt_servidor"), " ");
        const esquema_txt = upperClean($(this).attr("ows_txt_fuente_esquema"), "DBO");
        const base_txt = upperClean($(this).attr("ows_txt_host"), " ");
        const tabla_txt = upperClean($(this).attr("ows_txt_desc_tabla"), " ");
        const llaveTablatxt = `${servidor_txt}_${esquema_txt}_${base_txt}_${tabla_txt}`;

        lista[llaveTablatxt] = {
          // llaves normalizadas
          servidor: servidor_txt,
          esquema: esquema_txt,
          base: base_txt,
          tabla: tabla_txt,
          llave_tabla: llaveTablatxt,

          // resto de columnas (trim “suave”)
          descripcion_tabla: norm($(this).attr("ows_descripcion_tabla")),
          usuario_modificacion_descripcion: norm($(this).attr("ows_usuario_modificacion_descripcion")),
          fecha_modificacion_descripcion: norm($(this).attr("ows_fecha_modificacion_descripcion")),
          descripcion_dominio: norm($(this).attr("ows_descripcion_dominio")),
          txt_fuente_aprovisionamiento: norm($(this).attr("ows_txt_fuente_aprovisionamiento")),
          data_owner: norm($(this).attr("ows_data_owner")),
          nombre_data_owner: norm($(this).attr("ows_nombre_data_owner")),
          usuario_modificacion_do: norm($(this).attr("ows_usuario_modificacion_do")),
          fecha_modificacion_do: norm($(this).attr("ows_fecha_modificacion_do")),
          data_steward: norm($(this).attr("ows_data_steward")),
          nombre_data_steward: norm($(this).attr("ows_nombre_data_steward")),
          usuario_modificacion_ds: norm($(this).attr("ows_usuario_modificacion_ds")),
          fecha_modificacion_ds: norm($(this).attr("ows_fecha_modificacion_ds")),
          clasificacion: norm($(this).attr("ows_clasificacion")),
          usuario_modificacion_clasif: norm($(this).attr("ows_usuario_modificacion_clasif")),
          fecha_modificacion_clasif: norm($(this).attr("ows_fecha_modificacion_clasif")),
          etiquetas: norm($(this).attr("ows_etiquetas")),
          usuario_modificacion_etiqueta: norm($(this).attr("ows_usuario_modificacion_etiqueta")),
          fecha_modificacion_etiqueta: norm($(this).attr("ows_fecha_modificacion_etiqueta")),
          avance: norm($(this).attr("ows_avance")),
        };
      });
    }
  });

  // debug opcional
  window.__lastOficialesTemp = lista;
  return lista;
}

function getInfoTablasOficialesTxt() {
  let lista = {};
  const ruta = "http://vamos.bancoguayaquil.com/sitios/informaciongerencial/OGA_Suite/Produccion/datasets-txt/Z_TABLAS_OFICIALES.txt";

  (function () {
    $.ajax({
      url: ruta,
      method: "GET",
      async: false,
      success: function (data) {
        const texto = String(data || "").trim();
        if (!texto) return;

        const lineas = texto.split(/\r?\n/);
        if (lineas.length < 2) return;

        const headers = lineas[0].split("||").map(h => h.trim());
        const idx = (name) => headers.indexOf(name);

        // índices
        const i_txt_desc_tabla = idx("txt_desc_tabla");
        const i_descripcion_tabla = idx("descripcion_tabla");
        const i_usuario_mod_desc = idx("usuario_modificacion_descripcion");
        const i_fecha_mod_desc = idx("fecha_modificacion_descripcion");
        const i_descripcion_dominio = idx("descripcion_dominio");
        const i_txt_fuente_aprov = idx("txt_fuente_aprovisionamiento");
        const i_txt_servidor = idx("txt_servidor");
        const i_txt_host = idx("txt_host");
        const i_txt_fuente_esquema = idx("txt_fuente_esquema");
        const i_data_owner = idx("data_owner");
        const i_nombre_data_owner = idx("nombre_data_owner");
        const i_usuario_mod_do = idx("usuario_modificacion_do");
        const i_fecha_mod_do = idx("fecha_modificacion_do");
        const i_data_steward = idx("data_steward");
        const i_nombre_data_steward = idx("nombre_data_steward");
        const i_usuario_mod_ds = idx("usuario_modificacion_ds");
        const i_fecha_mod_ds = idx("fecha_modificacion_ds");
        const i_clasificacion = idx("clasificacion");
        const i_usuario_mod_clasif = idx("usuario_modificacion_clasif");
        const i_fecha_mod_clasif = idx("fecha_modificacion_clasif");
        const i_etiquetas = idx("etiquetas");
        const i_usuario_mod_etiqueta = idx("usuario_modificacion_etiqueta");
        const i_fecha_mod_etiqueta = idx("fecha_modificacion_etiqueta");
        const i_avance = idx("avance");

        // normalizadores
        const upperClean = (v, def = " ") => {
          const s = String(v ?? def)
            .toUpperCase()
            .trim()
            .replaceAll('(', '\\(')
            .replaceAll(')', '\\)')
            .replaceAll('<BR>', '')
            .replaceAll('\\', '');
          return s === "" ? def : s;
        };
        const norm = (v, def = " ") => {
          const decoded = String(v ?? def)
            .replace(/&lt;/gi, '<')
            .replace(/&gt;/gi, '>')
            .replace(/&amp;/gi, '&')
            .replace(/&nbsp;/gi, ' ');
          const stripped = decoded.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
          return stripped === "" ? def : stripped;
        };

        for (let i = 1; i < lineas.length; i++) {
          const vals = lineas[i].split("||");

          const servidor_txt = upperClean(vals[i_txt_servidor], " ");
          const esquema_txt = upperClean(vals[i_txt_fuente_esquema], "DBO");
          const base_txt = upperClean(vals[i_txt_host], " ");
          const tabla_txt = upperClean(vals[i_txt_desc_tabla], " ");
          const llaveTablatxt = `${servidor_txt}_${esquema_txt}_${base_txt}_${tabla_txt}`;

          lista[llaveTablatxt] = {
            servidor: servidor_txt,
            esquema: esquema_txt,
            base: base_txt,
            tabla: tabla_txt,
            llave_tabla: llaveTablatxt,

            descripcion_tabla: norm(vals[i_descripcion_tabla]),
            usuario_modificacion_descripcion: norm(vals[i_usuario_mod_desc]),
            fecha_modificacion_descripcion: norm(vals[i_fecha_mod_desc]),
            descripcion_dominio: norm(vals[i_descripcion_dominio]),
            txt_fuente_aprovisionamiento: norm(vals[i_txt_fuente_aprov]),
            data_owner: norm(vals[i_data_owner]),
            nombre_data_owner: norm(vals[i_nombre_data_owner]),
            usuario_modificacion_do: norm(vals[i_usuario_mod_do]),
            fecha_modificacion_do: norm(vals[i_fecha_mod_do]),
            data_steward: norm(vals[i_data_steward]),
            nombre_data_steward: norm(vals[i_nombre_data_steward]),
            usuario_modificacion_ds: norm(vals[i_usuario_mod_ds]),
            fecha_modificacion_ds: norm(vals[i_fecha_mod_ds]),
            clasificacion: norm(vals[i_clasificacion]),
            usuario_modificacion_clasif: norm(vals[i_usuario_mod_clasif]),
            fecha_modificacion_clasif: norm(vals[i_fecha_mod_clasif]),
            etiquetas: norm(vals[i_etiquetas]),
            usuario_modificacion_etiqueta: norm(vals[i_usuario_mod_etiqueta]),
            fecha_modificacion_etiqueta: norm(vals[i_fecha_mod_etiqueta]),
            avance: norm(vals[i_avance]),
          };
        }
      },
      error: function (xhr, status, err) {
        console.error("Error leyendo Z_TABLAS_OFICIALES.txt:", status, err);
      }
    });
  })();

  // debug opcional
  window.__lastOficialesTxt = lista;
  return lista;
}

function getInfoTablasOficiales(options = {}) {
  const { comoArray = false, deepMerge = true } = options;

  const baseTXT = (typeof getInfoTablasOficialesTxt === "function") ? (getInfoTablasOficialesTxt() || {}) : {};
  const tempSP = (typeof getInfoTablasOficialesTemp === "function") ? (getInfoTablasOficialesTemp() || {}) : {};

  // Prioriza siempre la lista de SharePoint (tempSP). El TXT solo rellena campos faltantes.
  const mergePreferSP = (spRec = {}, txtRec = {}) => {
    // Considera vacíos los null/undefined/espacios y placeholders comunes que vienen de SP.
    const isMissing = (v) => {
      if (v === undefined || v === null) return true;
      const val = String(v).replace(/\u00A0/g, "").replace(/\s+/g, "").toUpperCase();
      if (val === "") return true;
      if (val === "&NBSP;" || val === "NONE" || val === "NULL") return true;
      return false;
    };

    // Si se pide deepMerge, rellena con TXT solo los campos "vacíos" en SP.
    if (deepMerge) {
      const out = { ...(spRec || {}) };
      for (const k in (txtRec || {})) {
        // Fuerza fallback a TXT para descripcion/clasificacion cuando SP esté vacío.
        if (isMissing(out[k])) {
          out[k] = txtRec[k];
        }
      }
      // Refuerzo específico: si el TXT trae descripcion/clasificacion, úsalo cuando SP está vacío o con placeholder.
      if (!isMissing(txtRec.descripcion_tabla) && isMissing(out.descripcion_tabla)) {
        out.descripcion_tabla = txtRec.descripcion_tabla;
      }
      if (!isMissing(txtRec.clasificacion) && isMissing(out.clasificacion)) {
        out.clasificacion = txtRec.clasificacion;
      }
      return out;
    }
    // Sin deepMerge conserva compatibilidad con el comportamiento anterior.
    return { ...(txtRec || {}), ...(spRec || {}) };
  };

  const fusion = {};
  const llaves = new Set([...Object.keys(baseTXT), ...Object.keys(tempSP)]);

  llaves.forEach((key) => {
    const spRec = tempSP[key];
    const txtRec = baseTXT[key];
    const combinado = mergePreferSP(spRec, txtRec);
    // Asegura alias entre plataforma y txt_fuente_aprovisionamiento para evitar undefined en grillas.
    if (!combinado.plataforma && combinado.txt_fuente_aprovisionamiento) combinado.plataforma = combinado.txt_fuente_aprovisionamiento;
    if (!combinado.txt_fuente_aprovisionamiento && combinado.plataforma) combinado.txt_fuente_aprovisionamiento = combinado.plataforma;
    fusion[key] = combinado;
  });

  // Publicar en globals para que la UI consuma SIEMPRE la versión fusionada (TXT + SP).
  window.tablas_oficiales = fusion;             // mapa fusionado (clave -> registro)
  window.tablas_oficiales_array = Object.values(fusion); // array fusionado

  window.__lastFusionOficiales = fusion; // debug opcional
  return comoArray ? Object.values(fusion) : fusion;
}

