//Funcion para verificar acceso a data users y data citizen
function tieneAcceso(usuarioEspecifico = null) {
  let usuario = usuarioEspecifico ?? obtenerUsuario().current_user;
  //if(usuario === "jcastillo3") return true;

  let correo = `${usuario}@bancoguayaquil.com`;
  let correoMayusculas = correo.toUpperCase();
  let tieneAcceso = false;

  $().SPServices({
    operation: "GetListItems",
    async: false,
    listName: "LONG_LOC_MODEL_ART",
    CAMLQuery: `
      <Query>
        <Where>
          <And>
            <Or>
              <Eq><FieldRef Name="valor8" /><Value Type="Text">${correo}</Value></Eq>
              <Eq><FieldRef Name="valor8" /><Value Type="Text">${correoMayusculas}</Value></Eq>
            </Or>
            <Eq><FieldRef Name="ESTADO" /><Value Type="Text">ACTIVO</Value></Eq>
          </And>
        </Where>
      </Query>`,
    CAMLViewFields: `
      <ViewFields>
        <FieldRef Name='valor1' />
        <FieldRef Name='valor8' />
        <FieldRef Name='ESTADO' />
      </ViewFields>`,
    completefunc: function (xData, Status) {
      $(xData.responseXML).find("z\\:row").each(function () {
        if ($(this).attr("ows_valor8") && $(this).attr("ows_ESTADO") === "ACTIVO") {
          tieneAcceso = true;
        }
      });
    }
  });

  return tieneAcceso;
}

