//Carga de Dominios con animación
//Se utiliza la librería TweenMax, su función TweetMax.staggerTo()
//Se utiliza la librería D3js
function cargarDominios(dominios, avances) {
  // 1. Validación de seguridad por si el arreglo llega vacío
  if (!dominios || dominios.length === 0) return;

  // 2. Acceso directo a propiedades JSON (Mapeo flexible de Tipo)
  let tipo = (dominios[0].Tipo || dominios[0].tipo_dominio || "").trim();
  let activo = dominios[0].sn_activo;

  console.log(" tipo: ", tipo);
  console.log(" validacion SN_ACTIVO: ", activo);
  console.log(" SN_ACTIVO tipo: ", typeof (activo));

  // Reemplazo global de espacios por guiones (mejor práctica para clases CSS)
  let tipoClass = tipo.replace(/ /g, "-");

  // 3. Ordenamiento simplificado (numérico)
  let dominios_ordenados = dominios.sort((a, b) => {
    const fA = Number(a.id_dominio) || 0;
    const fB = Number(b.id_dominio) || 0;
    return fA - fB; // Si fA es mayor, retorna positivo; si es menor, negativo.
  });

  const colores = {
    "Dominio Derivado": "#9FDCEE",
    "Dominio Maestro": "#D2006E",
    "Dominio Transaccional": "#160F41"
  };

  const data = [{
    "boxes": dominios.length
  }];

  const colors = [colores[tipo]];
  let scaleColor = d3.scaleOrdinal()
    .domain(data.map(d => d.year))
    .range(colors);

  let uncount = (data, accessor) =>
    data.reduce((arr, item) => {
      const count = accessor(item)
      for (let i = 0; i < count; i++) {
        arr.push({ ...item })
      }
      return arr
    }, []);

  const boxes = uncount(data, d => d.boxes);

  const nest = d3
    .nest()
    .key(d => d.venue)
    .entries(boxes);

  const graph = d3.select(".Wafflechart." + tipoClass);
  const group = graph
    .selectAll(".container")
    .data(nest)
    .join("div")
    .attr("class", "waffle_container " + tipoClass);

  group
    .selectAll(".box")
    .data(d => d.values)
    .join("div")
    .attr("class", "box " + tipoClass)
    .style("background-color", d => scaleColor(d.year));

  // initiate paused animation
  let anim = new TimelineLite({ paused: true });
  anim.staggerTo((".box." + tipoClass), 0.5, {
    scale: 1,
    ease: "none",
    stagger: {
      amount: -1,
      grid: "auto",
      from: "center",
      axis: null,
    }
  });

  // 4. Agregar nombres y tooltips reemplazando $.each por forEach nativo
  dominios_ordenados.forEach(function (item, index) {
    let caja = document.querySelector(".waffle_container." + tipoClass + ">:nth-child(" + (index + 1) + ")");

    if (!caja) return; // Protección por si D3 no renderizó la caja

    const idDominio = item.id_dominio;
    caja.innerHTML = item.descripcion_dominio || "Sin nombre";
    caja.setAttribute("onclick", `redirigirFichaDominio('${idDominio}')`);

    // Validación de avances (convertimos el idDominio a string por seguridad contra el array 'avances.ids')
    // if (avances && avances.ids && avances.ids.includes(String(idDominio))) {
    if (item.porc_avance > 0) {
      caja.classList.add("activo");

      let porcentajeRaw = item.proc_avance || 0;
      let porcentaje = parseFloat(porcentajeRaw) * 100;

      caja.setAttribute("data-toggle", "tooltip");
      caja.setAttribute("data-placement", "left");
      caja.setAttribute("data-original-title", "Porcentaje de avance: " + porcentaje.toFixed(2) + "%");

    }
  });

  anim.play(0);

  if (tipo === "Dominio Maestro") {
    window.maestro = anim;
  } else if (tipo === "Dominio Derivado") {
    window.deriv = anim;
  } else {
    window.transac = anim;
  }
}

