// Función definitiva para ordenar el glosario: 
// 1° Por prioridad (ascendente, nulos al final) 
// 2° Por orden alfabético (nombre)
function sortGlosario(glosario) {
  // Validación de seguridad
  if (!Array.isArray(glosario)) return [];

  // Función auxiliar para parsear y asegurar la prioridad numérica
  const getPrioridad = (raw) => {
    // Si viene nulo, indefinido o vacío, lo mandamos al fondo (Infinity)
    if (raw === null || raw === undefined || raw === "") return Number.POSITIVE_INFINITY;

    const rawStr = String(raw);

    // Mantiene la lógica por si llega algún dato concatenado heredado (ej. "1;#Prioridad")
    const numericPart = rawStr.includes(";") ? rawStr.split(";").pop() : rawStr;
    const num = Number(numericPart.trim());

    return Number.isNaN(num) ? Number.POSITIVE_INFINITY : num;
  };

  console.log(`[sortGlosario] inicio -> total a ordenar: ${glosario.length}`);

  // Ordenamiento nativo y optimizado
  glosario.sort((a, b) => {
    // 1. Obtener prioridades numéricas
    const pa = getPrioridad(a.prioridad);
    const pb = getPrioridad(b.prioridad);

    // 2. Si las prioridades son distintas, gana la menor (ej. 1 va antes que 2 o Infinity)
    if (pa !== pb) {
      return pa - pb;
    }

    // 3. En caso de empate (misma prioridad o ambos sin prioridad): Orden alfabético
    const nombreA = (a.nombre || "").toLowerCase();
    const nombreB = (b.nombre || "").toLowerCase();

    // localeCompare asegura que "Árbol" y "arbol" se ordenen correctamente en español
    return nombreA.localeCompare(nombreB, 'es', { sensitivity: 'accent' });
  });

  // Muestra de depuración final (primeros 5 elementos)
  const sampleAfter = glosario.slice(0, 5).map((it, idx) => ({
    idx,
    nombre: it.nombre,
    prioridadRaw: it.prioridad,
    prioridad: getPrioridad(it.prioridad)
  }));

  console.log("[sortGlosario] fin -> muestra de los primeros 5 elementos ordenados:", sampleAfter);

  return glosario;
}

function renderMenuDominios() {
  const dominiosMap = window.glosario?.dominios;
  const $container = $('#lista-dominios-container');

  if (!dominiosMap || $container.length === 0) return;

  const dominiosArray = Array.from(dominiosMap.entries())
    .filter(([nombre, cantidad]) => nombre && nombre.trim() !== "")
    .sort((a, b) => b[1] - a[1]);

  let html = '<ul class="list-group list-group-flush">';
  dominiosArray.forEach(([nombre, cantidad]) => {
    html += `
            <li class="list-group-item d-flex justify-content-between align-items-center dominio-item p-2" title="${nombre}" style="cursor: pointer;">
                <span class="dominio-text mr-2">${nombre}</span>
                <span class="badge badge-pill dominio-badge">${cantidad}</span>
            </li>
        `;
  });
  html += '</ul>';

  $container.html(html);

  const $sidebarDominios = $('#sidebar-dominios');
  const $wrapperRecientes = $('#wrapper-recientes');
  const $btnToggle = $('#btn-toggle-dominios');
  const $btnClose = $('#btn-close-dominios');

  // Limpiar eventos anteriores para evitar duplicados si la función se llama varias veces
  $btnToggle.off('click');
  $btnClose.off('click');
  $container.off('click', '.dominio-item');
  $(document).off('click.cerrarDominios'); // Limpiamos el evento del documento

  // Botón para alternar (abrir/cerrar)
  $btnToggle.on('click', function (e) {
    e.preventDefault();

    $sidebarDominios.toggleClass('open');

    if ($sidebarDominios.hasClass('open')) {
      $wrapperRecientes.addClass('d-none'); // Dominios abierto -> Ocultar Recientes
    } else {
      $wrapperRecientes.removeClass('d-none'); // Dominios cerrado -> Mostrar Recientes
    }
  });

  // Botón interno (X) para cerrar
  $btnClose.on('click', function (e) {
    e.preventDefault();
    $sidebarDominios.removeClass('open'); // CORREGIDO: antes decía addClass
    $wrapperRecientes.removeClass('d-none');
  });

  // --- NUEVA LÓGICA: Cerrar al hacer clic fuera ---
  $(document).on('click.cerrarDominios', function (e) {
    // Si el menú está abierto...
    if ($sidebarDominios.hasClass('open')) {
      // Y el clic NO fue dentro del sidebar, NI dentro del botón que lo abre...
      if (!$(e.target).closest('#sidebar-dominios').length &&
        !$(e.target).closest('#btn-toggle-dominios').length) {

        // Entonces, cerramos el menú
        $sidebarDominios.removeClass('open');
        $wrapperRecientes.removeClass('d-none');
      }
    }
  });

  // Selección de un dominio
  $container.on('click', '.dominio-item', function () {
    $('.dominio-item').css('background-color', '');
    $(this).css('background-color', '#eef2f5');

    const dominioSeleccionado = $(this).find('.dominio-text').text().trim();
    console.log("Filtrar glosario por:", dominioSeleccionado);

    window.dominio = dominioSeleccionado;

    let filtrado = searchList(dominioSeleccionado, 'ows_descripcion_dominio', window.aux);
    console.log(`   -> Filtrando la lista principal por el dominio "${dominioSeleccionado}".`);
    console.log(`   -> Resultados para este dominio:`, filtrado.length, 'elementos.');

    printSearchResults(filtrado, { skipUrlFilter: true });

    const searchInput = document.getElementById('glosario-search');
    const buscarBtn = document.getElementById('glosario-buscar');
    if (searchInput) searchInput.outerHTML = searchInput.outerHTML;
    if (buscarBtn) buscarBtn.outerHTML = buscarBtn.outerHTML;

    autocompletado(document.getElementById('glosario-search'), 'ows_nombre_metad', filtrado);

    if (typeof isList !== 'undefined' && !isList) {
      document.getElementById('dropdown-btn').innerText = typeof filtro !== 'undefined' ? filtro : dominioSeleccionado;
    }

    if (typeof closeAllLists === 'function') closeAllLists();

    // Ocultar barra en pantallas pequeñas o tras seleccionar un dominio
    if (window.innerWidth < 768) {
      $sidebarDominios.removeClass('open'); // Usamos removeClass('open') para mantener la consistencia
      $wrapperRecientes.removeClass('d-none');
    }
  });
}

function renderMenuRecientes(n = 5) {
  const todos = window.glosario?.todos || [];
  const container = document.getElementById('lista-recientes-container');
  if (!container || todos.length === 0) return;
  const recientes = todos.slice().sort((a, b) => {
    const dateStrA = a.attr("ows_fec_ultima_actualizacion") || "";
    const dateStrB = b.attr("ows_fec_ultima_actualizacion") || "";

    const dateA = dateStrA ? new Date(dateStrA).getTime() : 0;
    const dateB = dateStrB ? new Date(dateStrB).getTime() : 0;

    return dateB - dateA;
  }).slice(0, n);

  let html = '<div>';
  recientes.forEach(item => {
    const nombre = (item.attr("ows_nombre_metad") || "Sin nombre").replaceAll('<br>', '');
    const tipo = (item.attr("ows_tipo_metad") || "Desc.").toUpperCase();
    const fechaRaw = item.attr("ows_fec_ultima_actualizacion") || "Sin fecha";
    const fecha = fechaRaw.split(" ")[0];
    const itemId = item.attr("ows_ID") || item.attr("ows_id_metad") || "";
    html += `
            <div class="reciente-item" data-id="${itemId}" data-nombre="${nombre}" style="cursor: pointer;">
                <div class="reciente-titulo" title="${nombre}">${nombre}</div>
                <div class="reciente-meta">
                    <span class="reciente-tipo">${tipo}</span>
                    <span><i class="simple-icon-calendar"></i> ${fecha}</span>
                </div>
            </div>
        `;
  });

  html += '</div>';
  container.innerHTML = html;

  const tarjetasRecientes = container.querySelectorAll('.reciente-item');
  tarjetasRecientes.forEach(tarjeta => {
    tarjeta.addEventListener('click', function () {
      const terminoNombre = this.getAttribute('data-nombre');
      console.log("Buscando desde término reciente:", terminoNombre);

      const inputBusqueda = document.getElementById('glosario-search');
      if (inputBusqueda) {
        inputBusqueda.value = terminoNombre;
      }
      let filtrado = searchList(terminoNombre, 'ows_nombre_metad', window.aux || window.glosario.todos, true);
      printSearchResults(filtrado, { skipUrlFilter: true });
    });
  });

  const sidebar = document.getElementById('sidebar-recientes');
  if (sidebar) {
    sidebar.classList.add('open');
  }

  $('#btn-toggle-recientes').off('click').on('click', function (e) {
    e.preventDefault();

    const $wrapperRecientes = $('#wrapper-recientes');
    const $sidebarDominios = $('#sidebar-dominios');

    $wrapperRecientes.toggleClass('d-none');

    // Validamos: Si acabamos de mostrar Recientes, ocultamos Dominios para evitar que la pantalla se apriete
    if ($sidebarDominios.hasClass('open')) {
      $sidebarDominios.removeClass('open');
    }
  });

  // (Opcional) Lógica para el botón con la "X" dentro del panel de recientes
  $('#btn-close-recientes').off('click').on('click', function (e) {
    e.preventDefault();
    $('#wrapper-recientes').addClass('d-none');
  });
}

window.currentGlosarioView = 'card';

function setupGlosarioViews() {
  const btnCard = document.getElementById('glosario-card-view');
  const btnList = document.getElementById('glosario-list-view');

  if (!btnCard || !btnList) return;

  btnCard.addEventListener('click', function () {
    window.currentGlosarioView = 'card';

    btnCard.classList.remove('text-semi-muted');
    btnCard.classList.add('text-primary');

    btnList.classList.remove('text-primary');
    btnList.classList.add('text-semi-muted');

    if (window.currentSearchResults) {
      printSearchResults(window.currentSearchResults, { skipUrlFilter: true });
    } else if (window.glosario && window.glosario.todos) {
      printSearchResults(window.glosario.todos, { skipUrlFilter: true });
    }
  });

  btnList.addEventListener('click', function () {
    window.currentGlosarioView = 'list';

    btnList.classList.remove('text-semi-muted');
    btnList.classList.add('text-primary');

    btnCard.classList.remove('text-primary');
    btnCard.classList.add('text-semi-muted');

    if (window.currentSearchResults) {
      printSearchResults(window.currentSearchResults, { skipUrlFilter: true });
    } else if (window.glosario && window.glosario.todos) {
      printSearchResults(window.glosario.todos, { skipUrlFilter: true });
    }
  });
}

