function printSearchResults(resultados, options = {}) {
  GlosarioApp.printSearchResults(resultados, options);
  return;
  window.currentTerminosSearch = resultados;
  const { skipUrlFilter = false } = options;
  const rawBuscar = skipUrlFilter ? null : getParams("buscar");
  const parametroBusqueda = rawBuscar ? rawBuscar.replace(/\+/g, " ") : rawBuscar;
  console.log("printSearchResults() -> inicio, total:", resultados.length, "parametroBusqueda:", parametroBusqueda);
  if (parametroBusqueda) {
    resultados = resultados.filter(e => calcularSimilitud(e.attr("ows_nombre_metad"), parametroBusqueda) > 80)
    console.log("printSearchResults() -> filtrado por query, total:", resultados.length);
  }
  // Ordenar por prioridad ascendente (sin prioridad al final) antes de paginar/renderizar
  const sortedResults = sortGlosario(resultados.slice());
  console.log("printSearchResults() -> post-sort length:", sortedResults.length);
  window.glosarioExportData = sortedResults.slice();
  updateGlosarioCount(sortedResults.length);
  $('.pagination').pagination({
    dataSource: sortedResults,
    pageSize: 10,
    className: 'paginationjs-theme-bg',
    showSizeChanger: true,
    afterRender: function () {
      document.body.scrollTop = 0;
      document.documentElement.scrollTop = 0;

    },
    callback: function (data, pagination) {
      let html = template(data, pagination.pageSize, window.currentGlosarioView)
      if (!data || data.length === 0) {
        $("#resultados").html(`
          <div class="card text-center p-4 my-3 shadow-sm" style="border: 1px solid #D0D0D0; background: #ffffff;">
            <div style="font-size: 42px; color: #d1007e; margin-bottom: 10px;">
              <i class="fas fa-info-circle"></i>
            </div>
            <h5 class="mt-2 mb-1" style="font-weight: 600; color: #000000;">
              No se encontraron resultados
            </h5>
            <p class="mb-0" style="font-size: 14px; color: #000000;">
              No existen registros que coincidan con los criterios de búsqueda seleccionados.
            </p>
          </div>`);
      } else {
        $("#resultados").html(html);
      }
      hydrateGlosarioCasoUso?.().catch(() => { });
    }


  });
}

async function hydrateGlosarioCasoUso() {
  if (!document || !window.GlosarioApi || typeof window.GlosarioApi.fetchCasoUsoDescripcion !== "function") return;
  const nodes = document.querySelectorAll(".glosario-caso-uso[data-caso-id]");
  if (!nodes.length) return;
  const jobs = [];
  nodes.forEach((node) => {
    const casoId = node.dataset.casoId;
    if (!casoId) return;
    const job = window.GlosarioApi.fetchCasoUsoDescripcion(casoId)
      .then((descripcion) => {
        const texto = descripcion?.toString().trim() || 'Sin descripción registrada';
        node.textContent = `| ${texto}`;
      })
      .catch((error) => {
        console.error('[Glosario] No se pudo cargar el caso de uso', casoId, error);
        node.textContent = `| Sin descripción`;
      });
    jobs.push(job);
  });
  if (jobs.length) {
    await Promise.all(jobs);
  }
}

function updateGlosarioCount(count = 0) {
  const badge = document.getElementById('glosario-count');
  if (!badge) return;
  const total = Number(count) || 0;
  badge.textContent = `${total} ${total === 1 ? 'resultado' : 'resultados'}`;
}

function exportarGlosarioCsv() {
  const registros = (window.glosarioExportData && window.glosarioExportData.length)
    ? window.glosarioExportData
    : (window.glosario?.todos || window.aux || []); // Agregado window.aux como fallback por seguridad

  if (!registros || !registros.length) {
    if (typeof showNotification === "function") {
      showNotification("top", "center", "warning", "No hay datos para descargar.");
    } else {
      alert("No hay datos para descargar.");
    }
    return;
  }

  const decodeHtml = (valor = "") => {
    const parser = document.createElement("textarea");
    parser.innerHTML = valor || "";
    return parser.value || "";
  };

  const limpiar = (valor = "") => (valor || "").toString().replace(/\r?\n|\r/g, " ").trim();

  const escapeCsv = (valor = "") => {
    const decoded = decodeHtml(valor);
    const limpio = limpiar(decoded);
    const necesitaComillas = /[\",;\n]/.test(limpio);
    const contenido = limpio.replace(/\"/g, "\"\"");
    return necesitaComillas ? `"${contenido}"` : contenido;
  };

  const headers = [
    "ID",
    "Nombre",
    "Tipo",
    "Dominio",
    "Subcategoría",
    "Descripción",
    "Características",
    "DatoPersonal",
    "GoldenRecord",
    "ÚltimaActualización"
  ];

  const filas = registros.map(item => {
    // Manejo de valores booleanos para una mejor lectura en Excel
    let textoGoldenRecord = "";
    if (item.golden_record !== null && item.golden_record !== undefined) {
      textoGoldenRecord = item.golden_record ? "Sí" : "No";
    }

    return [
      item.id !== null ? item.id : "",
      (item.nombre || "").toString().replaceAll("<br>", " "),
      item.tipo || "",
      (item.dominios || "").toString().replaceAll(";", " |"),
      item.txt_desc_subcategoria || "",
      item.descripcion || "",
      item.caracteristicas || "",
      item.dato_personal !== null ? item.dato_personal : "",
      textoGoldenRecord,
      item.fecha_modificacion || ""
    ];
  });

  const csvCuerpo = filas.map(fila => fila.map(escapeCsv).join(",")).join("\r\n");
  const csvSinBom = `${headers.join(",")}\r\n${csvCuerpo}`;
  const csvFinal = "\uFEFF" + csvSinBom; // BOM para que Excel respete UTF-8 y tildes

  const nombreDominio = (typeof getParams === 'function' ? getParams("dominio") : "glosario") || "glosario";
  const nombreArchivo = `glosario_${nombreDominio.replace(/\+/g, "_").replace(/\s+/g, "_")}.csv`;

  const blob = new Blob([csvFinal], { type: "text/csv;charset=utf-8;" });
  const url = URL.createObjectURL(blob);

  const enlace = document.createElement("a");
  enlace.href = url;
  enlace.download = nombreArchivo;
  document.body.appendChild(enlace);
  enlace.click();
  document.body.removeChild(enlace);

  setTimeout(() => URL.revokeObjectURL(url), 1000);
}

function parseCsvLinea(linea) {
  const resultado = [];
  let campo = "";
  let enComillas = false;
  for (let i = 0; i < linea.length; i++) {
    const char = linea[i];
    const next = linea[i + 1];
    if (enComillas) {
      if (char === '"' && next === '"') {
        campo += '"';
        i++;
      } else if (char === '"') {
        enComillas = false;
      } else {
        campo += char;
      }
    } else {
      if (char === '"') {
        enComillas = true;
      } else if (char === ',') {
        resultado.push(campo);
        campo = "";
      } else {
        campo += char;
      }
    }
  }
  resultado.push(campo);
  return resultado;
}

function parseCsvGlosario(contenido) {
  const lineas = (contenido || "")
    .replace(/\r\n/g, "\n")
    .replace(/\r/g, "\n")
    .split("\n")
    .filter(l => l.trim() !== "");
  if (!lineas.length) return { headers: [], filas: [] };
  const headers = parseCsvLinea(lineas[0]).map(h => h.trim());
  const filas = lineas.slice(1).map(l => parseCsvLinea(l));
  return { headers, filas };
}

