function quitarAcentos(cadena) {
  if (!cadena) return "";
  const acentos = { 'á': 'a', 'é': 'e', 'í': 'i', 'ó': 'o', 'ú': 'u', 'Á': 'A', 'É': 'E', 'Í': 'I', 'Ó': 'O', 'Ú': 'U' };
  return cadena.split('').map(letra => acentos[letra] || letra).join('').toString();
}

// Función de Búsqueda de terminos/atributos en una lista o arreglo con regex.test()
function searchList(search_value, column, list, isList = true) {
  if (!search_value) search_value = "";
  search_value = String(search_value);

  // Parsing de caracteres especiales para Regex
  if (search_value.includes("(")) search_value = search_value.replaceAll("(", "\\(");
  if (search_value.includes(")")) search_value = search_value.replaceAll(")", "\\)");
  if (search_value.includes("+")) search_value = search_value.replaceAll("+", "\\+");

  if (typeof quitarAcentos === 'function') {
    search_value = quitarAcentos(search_value);
  }

  let regex = new RegExp(search_value, "i");

  if (isList) {
    var results = list.filter(item => {
      // 🌟 ACCESO SEGURO: Soporta objetos nuevos (SQL) y antiguos (SharePoint)
      let rawValue = item && typeof item.attr === 'function' ? item.attr(column) : (item ? item[column] : "");
      const value = rawValue !== null && rawValue !== undefined ? String(rawValue) : "";

      const textoAProbar = typeof quitarAcentos === 'function' ? quitarAcentos(value) : value;
      return regex.test(textoAProbar);
    });

    if (window.segmento && window.dominio) {
      let aux = [];
      if (window.segmento === "datos personales") {
        results.forEach(item => {
          let datoPersonal = typeof item.attr === 'function' ? item.attr("ows_dato_personal") : item.dato_personal;
          if (datoPersonal == "1" || Number(datoPersonal) > 0) {
            let dominiosRaw = typeof item.attr === 'function' ? item.attr("ows_descripcion_dominio") : item.dominios;
            let lista = (dominiosRaw || "").split("; ").map(d => d.trim());
            if (lista.includes(window.dominio)) aux.push(item);
          }
        });
      } else if (window.segmento === "golden") {
        results.forEach(item => {
          let golden = typeof item.attr === 'function' ? item.attr("ows_golden_record") : item.golden_record;
          if (golden == "1" || golden === true || golden === 1) {
            let dominiosRaw = typeof item.attr === 'function' ? item.attr("ows_descripcion_dominio") : item.dominios;
            let lista = (dominiosRaw || "").split("; ").map(d => d.trim());
            if (lista.includes(window.dominio)) aux.push(item);
          }
        });
      } else {
        results.forEach(item => {
          let tipo = typeof item.attr === 'function' ? item.attr("ows_tipo_metad") : item.tipo;
          if (tipo && tipo.toLowerCase() === window.segmento.toLowerCase()) {
            let dominiosRaw = typeof item.attr === 'function' ? item.attr("ows_descripcion_dominio") : item.dominios;
            let lista = (dominiosRaw || "").split("; ").map(d => d.trim());
            if (lista.includes(window.dominio)) aux.push(item);
          }
        });
      }
      results = aux;
    } else if (window.segmento) {
      let aux = [];
      if (window.segmento === "datos personales") {
        results.forEach(item => {
          let datoPersonal = typeof item.attr === 'function' ? item.attr("ows_dato_personal") : item.dato_personal;
          if (datoPersonal == "1" || Number(datoPersonal) > 0) aux.push(item);
        });
      } else if (window.segmento === "golden") {
        results.forEach(item => {
          let golden = typeof item.attr === 'function' ? item.attr("ows_golden_record") : item.golden_record;
          if (golden == "1" || golden === true || golden === 1) aux.push(item);
        });
      } else {
        results.forEach(item => {
          let tipo = typeof item.attr === 'function' ? item.attr("ows_tipo_metad") : item.tipo;
          if (tipo && tipo.toLowerCase() === window.segmento.toLowerCase()) aux.push(item);
        });
      }
      results = aux;
    } else if (window.dominio) {
      let aux = [];
      results.forEach(item => {
        let dominiosRaw = typeof item.attr === 'function' ? item.attr("ows_descripcion_dominio") : item.dominios;
        let lista = (dominiosRaw || "").split("; ").map(d => d.trim());
        if (lista.includes(window.dominio)) aux.push(item);
      });
      results = aux;
    }
  } else {
    let nueva_lista = [];
    list.forEach(element => {
      const valueToTest = (typeof element === 'object' && element.text) ? element.text : String(element);
      if (valueToTest.includes(";")) {
        valueToTest.split("; ").forEach(el => {
          const cleanEl = el.trim();
          if (cleanEl && !nueva_lista.includes(cleanEl)) nueva_lista.push(cleanEl);
        });
      } else {
        const cleanEl = valueToTest.trim();
        if (cleanEl && !nueva_lista.includes(cleanEl)) nueva_lista.push(cleanEl);
      }
    });
    nueva_lista.sort();
    var results = nueva_lista.filter(item => regex.test(item));
  }
  return results;
}

// Función para autocompletado en el input de Glosario.aspx
function autocompletado(inp, columna, arr, isList = true) {
  var currentFocus;

  function renderAutocompleteList(targetInput, rawValue) {
    const searchValue = (rawValue || '').toLowerCase();
    console.log('Filtrando por (input):', searchValue);
    closeAllLists();
    currentFocus = -1;
    const listWrapper = document.createElement('DIV');
    listWrapper.setAttribute('id', targetInput.id + 'autocomplete-list');
    listWrapper.setAttribute('class', 'autocomplete-items');
    targetInput.parentNode.appendChild(listWrapper);

    let resultados = window.searchList(searchValue, columna, arr, isList) || [];

    resultados.forEach(item => {
      let entry = document.createElement('DIV');

      let rawItemValue = "";
      if (isList) {
        rawItemValue = typeof item.attr === 'function' ? item.attr(columna) : item[columna];
      } else {
        rawItemValue = item;
      }

      let displayValue = (rawItemValue !== null && rawItemValue !== undefined ? String(rawItemValue) : "").split('<br>').join('');

      entry.innerHTML = `${displayValue}<input type='hidden' value='${displayValue}'>`;

      entry.addEventListener('click', function () {
        inp.value = this.getElementsByTagName('input')[0].value;
        console.log(`Clic en sugerencia: "${inp.value}" (buscando en columna: ${columna})`);

        let filtro = inp.value;

        // Soporte para los nombres viejos y nuevos
        if (columna === 'ows_nombre_metad' || columna === 'nombre') {
          window.GlosarioApp.printSearchResults(window.searchList(filtro, columna, arr), { skipUrlFilter: true });
        }

        if (columna === 'ows_descripcion_dominio' || columna === 'dominios') {
          window.dominio = filtro;
          let filtrado = window.searchList(filtro, columna, window.aux);

          window.GlosarioApp.printSearchResults(filtrado, { skipUrlFilter: true });

          const elSearch = document.getElementById('glosario-search');
          const elBuscar = document.getElementById('glosario-buscar');
          if (elSearch) elSearch.outerHTML = elSearch.outerHTML;
          if (elBuscar) elBuscar.outerHTML = elBuscar.outerHTML;

          window.autocompletado(document.getElementById('glosario-search'), 'nombre', filtrado);

          const dropdownBtn = document.getElementById('dropdown-btn');
          if (dropdownBtn) {
            if (!isList) {
              const spanLabel = dropdownBtn.querySelector('.label');
              if (spanLabel) {
                spanLabel.textContent = filtro;
              } else {
                // Fallback de seguridad
                dropdownBtn.innerHTML = `
                        <svg viewBox="0 0 24 24" width="24" height="24" stroke="currentColor" stroke-width="2" fill="none" stroke-linecap="round" stroke-linejoin="round" class="css-i6dzq1">
                            <polygon points="22 3 2 3 10 12.46 10 19 14 21 14 12.46 22 3"></polygon>
                        </svg>
                        <span class="label">${filtro}</span>`;
              }
            }
          }
        }

        if (columna === 'caso_de_uso' || columna === 'casos_uso') {
          if (typeof seleccionarCasoUsoPorNombre === 'function') seleccionarCasoUsoPorNombre(filtro);
        }

        closeAllLists();
      });
      listWrapper.appendChild(entry);
    });

    const listElement = document.querySelector('#' + targetInput.id + 'autocomplete-list');
    if (!listElement) return;

    if (resultados.length > 6) {
      listElement.style.overflowY = 'scroll';
      listElement.style.height = '260px';
      if (listElement.firstElementChild) listElement.firstElementChild.style.borderTopRightRadius = 'unset';
      if (listElement.lastElementChild) listElement.lastElementChild.style.borderBottomRightRadius = 'unset';
    } else {
      listElement.style.overflowY = 'unset';
      listElement.style.height = 'unset';
    }
  }

  inp.addEventListener('input', function () {
    renderAutocompleteList(this, this.value);
  });

  inp.addEventListener('focus', function () {
    const target = this;
    setTimeout(() => {
      if (document.activeElement === target) {
        renderAutocompleteList(target, target.value);
      }
    }, 120);
  });

  inp.addEventListener("keydown", function (e) {
    var x = document.getElementById(this.id + "autocomplete-list");
    if (x) x = x.getElementsByTagName("div");

    if (e.keyCode === 40) { // down
      currentFocus++;
      addActive(x);
    } else if (e.keyCode === 38) { // up
      currentFocus--;
      addActive(x);
    } else if (e.keyCode === 13) { // enter
      e.preventDefault();
      if (currentFocus > -1) {
        if (x) x[currentFocus].click();
      } else if (this.value !== '') {
        if (columna === "ows_nombre_metad" || columna === "nombre") {
          window.GlosarioApp.printSearchResults(window.searchList(this.value, columna, arr), { skipUrlFilter: true });
          closeAllLists();
        }
        if (columna === "ows_descripcion_dominio" || columna === "dominios") {
          let matched = false;
          let inputVal = this.value;
          if (arr.includes(inputVal)) {
            window.dominio = inputVal;
            matched = true;
          }
          if (!matched) return false;

          let filtrado = window.searchList(window.dominio, columna, window.aux);
          window.GlosarioApp.printSearchResults(filtrado, { skipUrlFilter: true });

          const elSearch = document.getElementById("glosario-search");
          const elBuscar = document.getElementById("glosario-buscar");
          if (elSearch) elSearch.outerHTML = elSearch.outerHTML;
          if (elBuscar) elBuscar.outerHTML = elBuscar.outerHTML;

          window.autocompletado(document.getElementById("glosario-search"), "nombre", filtrado);

          const dropdownBtn = document.getElementById("dropdown-btn");
          if (dropdownBtn) {
            if (!isList) dropdownBtn.innerText = this.value;
          }
          closeAllLists();
        }
        if (columna === "caso_de_uso" || columna === "casos_uso") {
          if (typeof seleccionarCasoUsoPorNombre === 'function') seleccionarCasoUsoPorNombre(this.value);
          closeAllLists();
        }
      } else {
        if (columna === "ows_nombre_metad" || columna === "nombre") {
          window.GlosarioApp.printSearchResults(window.searchList("", columna, arr), { skipUrlFilter: true });
        }
      }

      if (inp && inp.id === "glosario-search" && typeof syncGlosarioBusquedaUrl === 'function') {
        syncGlosarioBusquedaUrl(this.value);
      }
    }
  });

  function addActive(x) {
    if (!x) return false;
    removeActive(x);
    if (currentFocus >= x.length) currentFocus = 0;
    if (currentFocus < 0) currentFocus = (x.length - 1);
    x[currentFocus].classList.add("autocomplete-active");
    const listContainer = document.querySelector("#" + inp.id + "autocomplete-list > div:nth-child(" + (currentFocus + 1) + ")");
    if (listContainer) listContainer.scrollIntoView({ block: "nearest", inline: "nearest" });
  }

  function removeActive(x) {
    for (var i = 0; i < x.length; i++) {
      x[i].classList.remove("autocomplete-active");
    }
  }

  function closeAllLists(elmnt) {
    var x = document.getElementsByClassName("autocomplete-items");
    for (var i = 0; i < x.length; i++) {
      if (elmnt != x[i] && elmnt != inp) {
        x[i].parentNode.removeChild(x[i]);
      }
    }
  }

  document.addEventListener("click", function (e) {
    closeAllLists(e.target);
  });

  const btnBuscar = document.getElementById("glosario-buscar");
  if (btnBuscar) {
    btnBuscar.addEventListener("click", function (e) {
      const searchVal = document.getElementById("glosario-search").value;

      if (columna === "ows_nombre_metad" || columna === "nombre") {
        window.GlosarioApp.printSearchResults(window.searchList(searchVal, columna, arr), { skipUrlFilter: true });
      }
      if (columna === "ows_descripcion_dominio" || columna === "dominios") {
        let matched = false;
        if (arr.includes(searchVal)) {
          window.dominio = searchVal;
          matched = true;
        }
        if (!matched) return false;

        let filtrado = window.searchList(window.dominio, columna, window.aux);
        window.GlosarioApp.printSearchResults(filtrado, { skipUrlFilter: true });

        document.getElementById("glosario-buscar").outerHTML = document.getElementById("glosario-buscar").outerHTML;
        window.autocompletado(document.getElementById("glosario-search"), "nombre", filtrado);

        const dropdownBtn = document.getElementById("dropdown-btn");
        if (dropdownBtn) {
          if (!isList) dropdownBtn.innerText = searchVal;
        }
      }
      if (columna === "caso_de_uso" || columna === "casos_uso") {
        if (typeof seleccionarCasoUsoPorNombre === 'function') seleccionarCasoUsoPorNombre(searchVal);
      }

      if (inp && inp.id === "glosario-search" && typeof syncGlosarioBusquedaUrl === 'function') {
        syncGlosarioBusquedaUrl(searchVal);
      }
    });
  }
}

function filtrarGlosarioPorCasoUso(casoUso) {
  if (!casoUso) return;
  if (!window.glosario || !window.glosario.todos) {
    console.warn("No hay datos del glosario cargados para filtrar por caso de uso.");
    return;
  }

  const resultados = window.glosario.todos.filter(item => {
    // Soporte para objetos SQL nuevos y SharePoint antiguos
    const descDominio = item.dominios || (typeof item.attr === 'function' ? item.attr("ows_descripcion_dominio") : "") || "";
    const subdominio = item.casos_uso || (typeof item.attr === 'function' ? item.attr("ows_txt_desc_subdominio") : "") || "";

    return descripcionDominioCoincide(descDominio, casoUso.nombre) ||
      coincideSubdominioConCasoUso(subdominio, casoUso);
  });

  console.log(` -> Filtrando glosario por caso de uso "${casoUso.nombre}" (${resultados.length} coincidencias).`);

  // Llamada al método encapsulado en GlosarioApp
  if (window.GlosarioApp && typeof window.GlosarioApp.printSearchResults === 'function') {
    window.GlosarioApp.printSearchResults(resultados, { skipUrlFilter: true });
  } else if (typeof printSearchResults === 'function') {
    printSearchResults(resultados, { skipUrlFilter: true });
  }

  if (resultados.length === 0) {
    console.warn("No se encontraron coincidencias para:", casoUso);
  }

  const dropdown = document.getElementById("dropdown-btn");
  if (dropdown) {
    const spanLabel = dropdown.querySelector('.label');

    if (spanLabel) {
      spanLabel.textContent = casoUso.nombre;
    } else {
      dropdown.innerHTML = `
              <svg viewBox="0 0 24 24" width="24" height="24" stroke="currentColor" stroke-width="2" fill="none" stroke-linecap="round" stroke-linejoin="round" class="css-i6dzq1">
                  <polygon points="22 3 2 3 10 12.46 10 19 14 21 14 12.46 22 3"></polygon>
              </svg>
              <span class="label">${casoUso.nombre}</span>`;
    }
  }
}

function coincideSubdominioConCasoUso(valorSubdominio, casoUso) {
  if (!valorSubdominio || !casoUso) return false;
  const valorNormalizado = valorSubdominio.toString();
  const idBuscado = (casoUso.id ?? "").toString().trim();

  if (valorNormalizado.includes(";#")) {
    const partes = valorNormalizado.split(";#");
    for (let i = 0; i < partes.length; i += 2) {
      const posibleId = (partes[i] || "").trim();
      const posibleNombre = (partes[i + 1] || "").trim();

      if (idBuscado && posibleId === idBuscado) return true;

      if (!/^\d+$/.test(posibleId)) {
        if (nombreCoincideConCaso(posibleId, casoUso.nombre) ||
          nombreCoincideConCaso(posibleNombre, casoUso.nombre)) {
          return true;
        }
      }
    }
    for (let i = 1; i < partes.length; i += 2) {
      if (nombreCoincideConCaso(partes[i], casoUso.nombre)) return true;
    }
    return false;
  }

  const valorLimpio = valorNormalizado.trim();
  if (idBuscado && valorLimpio === idBuscado) return true;
  if (/^\d+$/.test(valorLimpio) && idBuscado) return valorLimpio === idBuscado;

  return nombreCoincideConCaso(valorLimpio, casoUso.nombre);
}

function descripcionDominioCoincide(valor, nombreCaso) {
  if (!valor || !nombreCaso) return false;
  const limpio = valor.toString();
  const nombre = nombreCaso.toString();

  if (limpio.includes(";#")) {
    const partes = limpio.split(";#");
    for (let i = 0; i < partes.length; i++) {
      if (nombreCoincideConCaso(partes[i], nombre)) return true;
    }
  }

  if (limpio.includes(";")) {
    const lista = limpio.split(";").map(s => s.trim());
    return lista.some(entry => nombreCoincideConCaso(entry, nombre));
  }

  return nombreCoincideConCaso(limpio, nombre);
}

function nombreCoincideConCaso(valor, nombreCaso) {
  if (!valor || !nombreCaso) return false;
  const qValor = typeof quitarAcentos === 'function' ? quitarAcentos(valor) : valor;
  const qCaso = typeof quitarAcentos === 'function' ? quitarAcentos(nombreCaso) : nombreCaso;
  return qValor.toLowerCase().includes(qCaso.toLowerCase());
}

function seleccionarCasoUsoPorNombre(nombreCaso) {
  if (!nombreCaso) return;
  const casos = window.casosDeUsoListado || [];
  const encontrado = casos.find(caso => caso.nombre === nombreCaso);

  if (!encontrado) {
    window.casoDeUsoSeleccionado = undefined;
    console.warn(`No se encontró el caso de uso "${nombreCaso}" en la lista disponible.`);
    return;
  }

  window.casoDeUsoSeleccionado = encontrado;
  console.log(` -> Caso de uso seleccionado: "${encontrado.nombre}" (ID: ${encontrado.id}).`);
  filtrarGlosarioPorCasoUso(encontrado);
}

async function nuevoCriterio(criterio) {
  window.criterioGlosario = (criterio || "").toString().toLowerCase();

  const dropdownBtn = document.getElementById("dropdown-btn");
  if (dropdownBtn) {
    const nuevoTexto = typeof mayusc_each_word === 'function' ? mayusc_each_word(criterio) : criterio;
    const spanLabel = dropdownBtn.querySelector('.label');

    if (spanLabel) {
      spanLabel.textContent = nuevoTexto;
    } else {
      dropdownBtn.innerHTML = `
                <svg viewBox="0 0 24 24" width="24" height="24" stroke="currentColor" stroke-width="2" fill="none" stroke-linecap="round" stroke-linejoin="round" class="css-i6dzq1">
                    <polygon points="22 3 2 3 10 12.46 10 19 14 21 14 12.46 22 3"></polygon>
                </svg>
                <span class="label">${nuevoTexto}</span>`;
    }
  }

  if (criterio !== "caso de uso") {
    window.casoDeUsoSeleccionado = undefined;
  }

  if (criterio === "dominio") {
    window.dominio = undefined;
    const elSearch = document.getElementById("glosario-search");
    if (elSearch) elSearch.outerHTML = elSearch.outerHTML;

    if (typeof uniqueColumn === 'function' && typeof autocompletado === 'function') {
      // Actualizado a la nueva columna SQL
      autocompletado(document.getElementById("glosario-search"), "dominios", uniqueColumn(window.aux, "dominios"), false);
    }

  } else if (criterio === "caso de uso") {
    const dominioUrl = decodeURIComponent(typeof getParams === 'function' ? getParams("dominio") || "" : "").trim();
    const dominioSeleccionado = (window.dominio || "").trim();
    const nombreDominio = dominioUrl || dominioSeleccionado;

    let idDominio = null;

    if (nombreDominio) {
      try {
        // Delegamos la búsqueda al nuevo servicio SQL
        const dominioEncontrado = await window.DominiosService.search("descripcion_dominio", nombreDominio, "Text");

        if (dominioEncontrado && dominioEncontrado.id_dominio) {
          idDominio = dominioEncontrado.id_dominio;
        } else {
          console.warn(`No se encontró el dominio con el nombre: ${nombreDominio}`);
        }
      } catch (error) {
        console.error("Error al obtener el ID del dominio desde SQL:", error);
      }
    }
    console.log("ID del Dominio encontrado:", idDominio);

    const condicion = idDominio ? `ID_DOMINIO = ${idDominio}` : "1=1";

    try {
      // Búsqueda de casos de uso vía SQL Server
      const casosDeUso = await window.SqlHelper.query(
        "ID_CASO_USO, DESCRIPCION_CASO_USO",
        "PROCESOS_BI.DBO.T_CASOS_USO_ANALITICA",
        condicion
      );

      window.casosDeUsoListado = (casosDeUso || []).map(caso => ({
        id: caso.ID_CASO_USO,
        nombre: (caso.DESCRIPCION_CASO_USO || "").trim()
      })).filter(caso => caso.nombre.length > 0);

      if (!window.casosDeUsoListado.length) return;

      const casosParaAutocompletar = [...new Set(window.casosDeUsoListado.map(caso => caso.nombre))];

      const elSearch = document.getElementById("glosario-search");
      if (elSearch) elSearch.outerHTML = elSearch.outerHTML;

      if (typeof autocompletado === 'function') {
        autocompletado(document.getElementById("glosario-search"), "casos_uso", casosParaAutocompletar, false);
      }

      const buscarUrlRaw = typeof getParams === 'function' ? getParams("buscar") : null;
      const buscarUrl = buscarUrlRaw ? buscarUrlRaw.replace(/\+/g, " ") : "";

      if (buscarUrl) {
        const input = document.getElementById("glosario-search");
        if (input) input.value = buscarUrl;

        // Llamamos al método desde GlosarioApp
        if (window.GlosarioApp && typeof window.GlosarioApp.ejecutarBusquedaGlosarioDesdeValor === 'function') {
          window.GlosarioApp.ejecutarBusquedaGlosarioDesdeValor(buscarUrl);
        } else if (typeof ejecutarBusquedaGlosarioDesdeValor === 'function') {
          ejecutarBusquedaGlosarioDesdeValor(buscarUrl);
        }
      }

    } catch (error) {
      console.error("Error al cargar los casos de uso:", error);
    }

  } else if (criterio === "todos") {
    window.dominio = undefined;

    if (typeof searchList === 'function') {
      const resultados = searchList(".", "nombre", window.aux);
      if (window.GlosarioApp && typeof window.GlosarioApp.printSearchResults === 'function') {
        window.GlosarioApp.printSearchResults(resultados, { skipUrlFilter: true });
      } else if (typeof printSearchResults === 'function') {
        printSearchResults(resultados, { skipUrlFilter: true });
      }
    }

    const elSearch = document.getElementById("glosario-search");
    if (elSearch) elSearch.outerHTML = elSearch.outerHTML;

    if (typeof autocompletado === 'function') {
      // Actualizado a la nueva columna SQL
      autocompletado(document.getElementById("glosario-search"), "nombre", window.aux);
    }

    if (dropdownBtn) dropdownBtn.classList.remove("filtro-activo");
  }

  const currentInput = document.getElementById("glosario-search");
  const currentValue = currentInput ? currentInput.value : "";
  if (typeof syncGlosarioBusquedaUrl === 'function') syncGlosarioBusquedaUrl(currentValue);
}

function reducirColumnasNivelTabla() {
  let item = $('#campos').DataTable();
  if (window.nivelTabla) {
    item.column(0).visible(false); //Oculta campo
    item.column(1).visible(false); //Oculta código
    item.column(2).visible(false); //Oculta atributo
    item.column(3).visible(false); //Oculta definición atributo
    item.column(9).visible(false); //Oculta tipo de dato
    item.column(10).visible(false); //Oculta largo de dato
    item.column(11).visible(false); //Oculta permite null
  } else {
    item.column(0).visible(true); //Muestra campo
    item.column(1).visible(true); //Muestra código
    item.column(2).visible(true); //Muestra atributo
    item.column(3).visible(true); //Muestra definición atributo
    item.column(9).visible(true); //Muestra tipo de dato
    item.column(10).visible(true); //Muestra largo de dato
    item.column(11).visible(true); //Muestra permite null
  }
}

function listenerSwitch() {

  document.getElementById("switchS3").addEventListener("click", function (e) {
    if ($(this).is(':checked')) { //Si le hice click en vista tablas entonces
      window.forceFirstPageOnTableView = true
      window.vistaTablaSinonimo = true
      window.nivelTabla = true //Marcamos que está activada la vista tablas
      if (window.colapsado) { //En caso esté colapsado abro y cierro 
        //abrirCerrar($('#campos').DataTable()); //abro todas cols
        addDataCollapse() //abro todas cols
        reducirColumnasNivelTabla(); //Dejo solo las variables de las tablas
        window.colapsado = true;
      } else {
        reducirColumnasNivelTabla(); //En caso no esté colapsado, solo muestro variables de tablas   
      }
      //Muestro la columna de clasificación y la de descripción tabla
      $('#campos').DataTable().column(12).visible(true);
      $('#campos').DataTable().column(13).visible(true);
      $('#campos').DataTable().column(14).visible(true);
      //Vuelvo a escribir la tabla para que solo tenga info de tabla
      if (window.campos.length != 0) {
        redrawDataTableBuscadorCampos("campos", arrayCamposDistinct(window.campos))
      }
    } else { //Si le hice clic en vista campos entonces
      window.vistaTablaSinonimo = false
      window.nivelTabla = false
      if (window.colapsado) {
        reducirColumnasNivelTabla(); //Muestro las variables de los campos
        abrirCerrar($('#campos').DataTable());
      } else {
        reducirColumnasNivelTabla();
      }
      //Ocultamos las columnas de clasificación y la de descripción tabla
      $('#campos').DataTable().column(12).visible(false);
      $('#campos').DataTable().column(13).visible(false);
      $('#campos').DataTable().column(14).visible(false);
      //Vuelvo a escribir la tabla para que tenga info a nivel de campos
      if (window.camposdistinct !== undefined && window.camposdistinct.length != 0) {
        redrawDataTableBuscadorCampos("campos", window.campos)
      }
    }
  })
}

function cambiarBusqueda() {
  //Listener para cambiar Switch
  var target = document.querySelector('#dropdown-buscador');
  var observer = new MutationObserver(function (mutations) {
    mutations.forEach(function (mutation) {
      if (mutation.type == "childList") {
        //En caso este colapsado, lo expando para tener todos los datos
        if (window.colapsado) { $("#btncampos").click(); }
      }
    });
  });

  var config = { attributes: true, childList: true, characterData: true };
  observer.observe(target, config);

  document.getElementById("opcionfiltro").addEventListener("click", function (e) {
    let textoactual = document.getElementById("dropdown-buscador").innerText.toLocaleUpperCase().replace(" ", "");
    let textocambiar = document.getElementById("opcionfiltro").innerText.toLocaleUpperCase().replace(" ", "");

    document.getElementById("dropdown-buscador").innerText = capitalizarPrimeraLetra(textocambiar.toLowerCase());
    document.getElementById("opcionfiltro").innerText = capitalizarPrimeraLetra(textoactual.toLowerCase());
    if (document.getElementById("dropdown-buscador").innerText === "Tabla" && !$("#switchS3").is(':checked')) {
      $("#switchS3").click()
    } else if ((document.getElementById("dropdown-buscador").innerText === "Campo" && $("#switchS3").is(':checked')) || document.getElementById("dropdown-buscador").innerText === "Atributo" && $("#switchS3").is(':checked')) {
      $("#switchS3").click()
    }

  });

  document.getElementById("opcionfiltro2").addEventListener("click", function (e) {
    let textoactual = document.getElementById("dropdown-buscador").innerText.toLocaleUpperCase().replace(" ", "");
    let textocambiar = document.getElementById("opcionfiltro2").innerText.toLocaleUpperCase().replace(" ", "");

    document.getElementById("dropdown-buscador").innerText = capitalizarPrimeraLetra(textocambiar.toLowerCase());
    document.getElementById("opcionfiltro2").innerText = capitalizarPrimeraLetra(textoactual.toLowerCase());
    if (document.getElementById("dropdown-buscador").innerText === "Tabla" && !$("#switchS3").is(':checked')) {
      $("#switchS3").click()
    } else if ((document.getElementById("dropdown-buscador").innerText === "Campo" && $("#switchS3").is(':checked')) || document.getElementById("dropdown-buscador").innerText === "Atributo" && $("#switchS3").is(':checked')) {
      $("#switchS3").click()
    }
  });

}

// Funcion de respaldo para limpiar los datos despues de hacer clic en el combo de #dropdown-buscador (No se esta usando)
function limpiarFiltros() {
  if ((window.campo != "" || window.tablab != undefined || window.atributob != undefined) || window.colapsado == true) {
    //Se establece el estilo de fondo, color y borde del elemento con el ID dropdown-buscador.
    //Cuando campo esta lleno o tablab esta definida o atributo este definido o el arbol este colapsado  se ejecuta la opcion de abajo.

    document.querySelector("#dropdown-buscador").style.background = "#D2006E";
    document.querySelector("#dropdown-buscador").style.color = "white";
    document.querySelector("#dropdown-buscador").style.border = "#D2006E";

    // Se ejecuta esta funcion que tiene dentro una accion que se realizara luego del tiempo establecido
    setTimeout(function () {
      //limpia el campo de busqueda
      document.getElementById("campos-search").value = '';
      //Reinicia variables globales
      window.campo = '';
      window.tablab = undefined;
      window.atributob = undefined;

      //Reinicia la tabla
      segmentarTablaCampos(tabla_config = 'campos', servidor = 'TODOS', base = '', esquema = '', tabla = '', recoger_filtro = true);
      //oculta el icono del tacho de basura de la pantalla
      if ($("#campos-buscar").is(":visible")) { $("#campos-buscar").toggle(); }
      //Limpia estilos del elemento dropdown-buscador
      //Elimina estilo de fondo, color y borde establecido en el ID dropdown-buscador.
      document.querySelector("#dropdown-buscador").style.background = "";
      document.querySelector("#dropdown-buscador").style.color = "";
      document.querySelector("#dropdown-buscador").style.border = "";
      //Se ejecuta despues de un retraso de 120 milisegundos
    }, 120);
  }
}

function estandarizarSegmentacion() {
  let segmentador = document.getElementById("segmentar-btn")
  if (!segmentador) return;
  let stringOpcionesSegmentador = ""
  let segmentos = getCatalogoSegmentador()
  let cleanedKeys = []
  let opcionesSegmentador = []
  Object.entries(segmentos).forEach(([key, value]) => {
    let cleanedKey = key.replaceAll(" ", "")
    if (value.length > 1) {
      value = value.sort((a, b) => parseInt(a.subsegmento) - parseInt(b.subsegmento))
      stringOpcionesSegmentador += `
        <a class="dropdown-item d-flex align-items-center" data-toggle="collapse" role="button" aria-expanded="false" aria-controls="submenu${cleanedKey}" id="${cleanedKey}-btn" style="gap:2px;">${key} <i class="simple-icon-arrow-right rotate-icon ml-2" style="margin-bottom:.15rem;"></i></a>\
        <div class="collapse ml-3" id="submenu${cleanedKey}">`
      // value=[value[value.length - 1]]
    }

    value.forEach(e => {
      stringOpcionesSegmentador += `<a class="dropdown-item text-wrap" id="${e.value}">${e.label}</a>`
      opcionesSegmentador.push(e)
    })

    if (value.length > 1) {
      stringOpcionesSegmentador += `</div>`
    }
    cleanedKeys.push(cleanedKey)
  })
  segmentador.nextSibling.nextSibling.innerHTML = stringOpcionesSegmentador


  cleanedKeys.forEach(key => {
    let btnSubmenu = document.getElementById(`${key}-btn`)
    if (btnSubmenu) {
      btnSubmenu.addEventListener('click', function (event) {
        event.stopImmediatePropagation(); // Evita que el dropdown principal se cierre
        $(`#submenu${key}`).collapse("toggle")
        $(btnSubmenu).find('.rotate-icon').toggleClass('rotate');
      });
    }
  })

  opcionesSegmentador.forEach(elemento => {
    let opcionSegmentador = document.getElementById(elemento.value)
    if (opcionSegmentador) {
      opcionSegmentador.addEventListener("click", function (e) {
        segmentar(elemento)
      })
    }
  })
}

function segmentar(segmento) {
  if (!segmento || typeof segmento !== 'object') {
    console.error("? [segmentar] segmento inválido:", segmento);
    return;
  }
  console.log("?? [segmentar] Segmento recibido:", segmento);

  if (segmento.value == "TERMINO") {
    window.tipo = "terminos"
    segmento.value = "terminos"
  } else {
    window.tipo = segmento.value;
  }
  document.getElementById("segmentar-btn").innerText = segmento.label;

  let dominio = document.getElementById("dropdown-btn").innerText;
  if (dominio !== "Filtrar Por " && dominio !== "Todos" && dominio !== "Dominio") {
    window.dominio = dominio;
  } else {
    window.dominio = getParams("dominio");
  }
  console.log("?? [segmentar] Tipode SEGMENTO:", segmento.value);
  console.log("?? [segmentar] Dominio:", window.dominio);
  console.log("?? [segmentar] Tipo:", window.tipo);

  if (segmento.value === "todos") {
    window.glosario.todos = window.aux;
  } else {
    let datos = window.glosario[segmento.value] ?? window.glosario["datos_personales"];
    window.glosario.todos = sortGlosario(datos); // ? SIN .map($(el))
  }

  if (segmento.value === "atributos" || segmento.value === "terminos") {
    segmento.value = singularize(segmento.value.toUpperCase());
  }

  window.segmento = segmento.value === "todos" ? null : segmento.value;

  console.log("?? [segmentar] window.segmento:", window.segmento);
  console.log("?? [segmentar] Cantidad elementos en glosario.todos:", window.glosario.todos.length);
  console.log("?? estos son los glosario.todos:", window.glosario.todos);

  console.log("?? estos son los glosario.todos ANTES: ??", window.glosario.todos);
  if (window.dominio && (window.segmento == "atributos" || window.segmento == "terminos")) {
    console.log("?? [segmentar] Filtrando con searchList por dominio...");
    window.glosario.todos = searchList(window.dominio, "ows_descripcion_dominio", window.glosario.todos);
  }
  console.log("?? estos son los glosario.todos DESPUES: ??", window.glosario.todos);
  console.log("?? [segmentar] Ejecutando autocompletado...");
  autocompletado(document.getElementById("glosario-search"), "ows_nombre_metad", window.glosario.todos);

  console.log("??? [segmentar] Imprimiendo resultados...");
  printSearchResults(window.glosario.todos, { skipUrlFilter: true });
}

function singularize(word) {
  const exceptions = {
    "atributos": "atributo",
    "terminos": "termino",
    "datos_personales": "dato_personal",
    "elementos": "elemento",
    "golden": "golden",
    "usuarios": "usuario"
    // agrega más aquí según necesites
  };

  if (exceptions[word]) return exceptions[word];

  // Reglas básicas para inglés
  if (word.endsWith("ies")) return word.slice(0, -3) + "y";
  if (word.endsWith("ves")) return word.slice(0, -3) + "f";
  if (word.endsWith("S") && !word.endsWith("ss")) return word.slice(0, -1);

  return word; // Si no se puede convertir, devuelve la original
}

// Función útil para obtener un arreglo sin repetir de items de una lista JSON
function uniqueColumn(arr, columna) {
  if (!Array.isArray(arr)) return [];
  const valoresUnicos = new Set();
  arr.forEach(item => {
    const valor = item[columna];
    // Verificamos que el valor no sea nulo ni indefinido
    if (valor) {
      // Si es un texto y contiene punto y coma, lo separamos para obtener valores individuales
      if (typeof valor === 'string' && valor.includes(';')) {
        valor.split(';').forEach(v => {
          if (v.trim() !== "") valoresUnicos.add(v.trim());
        });
      } else {
        // Si es un valor único, lo limpiamos de espacios extra y lo agregamos
        const valorLimpio = typeof valor === 'string' ? valor.trim() : valor;
        if (valorLimpio !== "") valoresUnicos.add(valorLimpio);
      }
    }
  });
  return [...valoresUnicos].sort((a, b) => String(a).localeCompare(String(b)));
}

//Funcion para agregar propiedades al objeto de un dominio actual que se esté presentando
// Funcion para agregar propiedades al objeto de un dominio actual que se esté presentando
function buildFichaObject(objeto, dominio_actual) {
  // Validamos que el dominio actual exista para no romper la ejecución
  if (!dominio_actual) return objeto;

  // Object.assign muta el 'objeto' original agregándole las nuevas propiedades
  Object.assign(objeto, {
    porcentaje_avance_dominio: dominio_actual.porcentaje_avance_dominio || 0,
    cant_atributos: dominio_actual.cant_atributos || 0,
    cant_terminos: dominio_actual.cant_terminos || 0,
    cant_modelos: dominio_actual.cant_modelos || 0,
    cant_estructura: dominio_actual.cant_estructura || 0,
    cant_casos: parseInt(dominio_actual.cant_casos || 0, 10),
    familia: dominio_actual.Familia_de_Dominios || "",
    tipo: dominio_actual.Tipo || dominio_actual.tipo_dominio || "", // Ajuste a la nueva columna 'Tipo'
    codigo_Dominio: dominio_actual.codigo_Dominio || "",
    Conceptos_Clave: dominio_actual.Conceptos_Clave || "",
    subdominios: dominio_actual.subdominios || 0
  });

  return objeto;
}

