async function fichaDominio() {
  var id_dominio_actual = getParams("id_dominio");
  if (!id_dominio_actual) return;

  var dominio_actual = await searchDominios("id_dominio", id_dominio_actual, "Number");
  if (!dominio_actual) {
    console.error("No se encontró el dominio con ID:", id_dominio_actual);
    return;
  }

  const estadisticas = await window.DominiosService.getEstadisticas(id_dominio_actual, dominio_actual.descripcion_dominio)
  dominio_actual.cant_casos = estadisticas.cant_casos;
  dominio_actual.cant_terminos = estadisticas.cant_terminos;
  dominio_actual.cant_atributos = estadisticas.cant_atributos;
  dominio_actual.cant_modelos = estadisticas.cant_modelos;

  var avance_actual = typeof getAvancesDominio === 'function' ? await getAvancesDominio(id_dominio_actual) : null;
  var avance;

  if (avance_actual) {
    avance = buildFichaObject(avance_actual.avance, dominio_actual);
    fillFichaDominio(avance, id_dominio_actual, true, dominio_actual);
  } else {
    avance = {
      porcentaje_avance_dominio: dominio_actual.porcentaje_avance_dominio || 0,
      descripcion_dominio: dominio_actual.descripcion_dominio || "",
      oleada: undefined,

      cant_atributos: dominio_actual.cant_atributos,
      cant_terminos: dominio_actual.cant_terminos,
      cant_casos: dominio_actual.cant_casos,

      cant_modelos: dominio_actual.cant_modelos || 0,
      cant_estructura: dominio_actual.cant_estructura || 0,

      familia: dominio_actual.Familia_de_Dominios || "",
      tipo: dominio_actual.Tipo || dominio_actual.tipo_dominio || "",
      codigo_Dominio: dominio_actual.codigo_Dominio || "",
      Conceptos_Clave: dominio_actual.Conceptos_Clave || "",
      subdominios: dominio_actual.subdominios || 0,
    };

    fillFichaDominio(avance, id_dominio_actual, false, dominio_actual);
  }

  if (typeof registrar_visita === 'function') {
    registrar_visita("FICHA DE DOMINIO", dominio_actual.descripcion_dominio || "");
  }

  if (typeof advanceStorage !== 'undefined') {
    window._fichaDominioActive = advanceStorage;
  } else if (typeof ficha !== 'undefined') {
    window._fichaDominioActive = window._fichaDominioActive || ficha;
  }
}

