//funcion para limpiar modal de añadir atributo



// Función principal (Ahora es ASYNC para esperar a la base de datos)
async function addAtributo() {
  if (typeof cleanModalAtributo === 'function') cleanModalAtributo();

  // Guardar selección previa de características para no perderla al recargar
  const seleccionCaracteristicas = $("#nombrecaract").val();

  // Obtener e inyectar dominios
  let dominios = await getAllDescripcionDominio() || [];
  addDominiosFichaAtributo(dominios);

  // Inicializar todos los dropdowns múltiples
  $(".select2-multiple").select2({
    theme: "bootstrap",
    width: "100%",
    placeholder: "Seleccione una o más opciones",
    allowClear: true
  });

  $("#nombred").off('change.cascada').on('change.cascada', function () {
    // Obtenemos el TEXTO de los dominios seleccionados (Ej: ["Finanzas", "Riesgos"])
    const dominiosSeleccionados = $(this).find('option:selected').map(function () {
      return $(this).text().trim();
    }).get();

    const $sub = $('#nombresub');
    const seleccionesPrevias = $sub.val() || []; // Respaldamos lo que ya estaba marcado

    $sub.empty(); // Vaciamos el select2 de subdominios

    // Si hay dominios seleccionados y existen los diccionarios globales
    if (dominiosSeleccionados.length > 0 && window.diccionarioCasosUso && window.mapaCasoUsoDominio) {

      // Filtramos y agregamos solo los subdominios que pertenezcan a los dominios seleccionados
      Object.keys(window.diccionarioCasosUso).forEach(idCaso => {
        const nombreDominioPadre = window.mapaCasoUsoDominio[idCaso];

        if (dominiosSeleccionados.includes(nombreDominioPadre)) {
          const nombreCaso = window.diccionarioCasosUso[idCaso];

          // Verificamos si este subdominio ya estaba marcado por el usuario antes de la recarga
          const isSelected = seleccionesPrevias.includes(idCaso.toString());

          const opt = new Option(nombreCaso, idCaso, false, isSelected);
          $sub.append(opt);
        }
      });
    }

    // Notificamos a Select2 que las opciones cambiaron para que se redibuje
    $sub.trigger('change.select2');
  });

  try {
    const caracteristicas = await cargaAtributos();
    loadOptions(caracteristicas);

    // Restaurar selección previa de características si existía
    if (seleccionCaracteristicas && seleccionCaracteristicas.length > 0) {
      $("#nombrecaract").val(seleccionCaracteristicas).trigger("change.select2");
    }
  } catch (error) {
    console.error("Error al cargar atributos desde SQL:", error);
  }

  if (typeof loadCatalogos === 'function') loadCatalogos();

  $("#modalAtributo").modal("show");
}

// funcion para cargar asignar automaticamente ids a atributos nuevos/ cargar caracterisitcas
async function cargaAtributos() {
  let caracteristicas = [];

  try {
    // Pedimos a SQL SOLO la columna de características, filtrando por ATRIBUTO
    const atributos = await window.SqlHelper.query(
      "caracteristicas",
      window.TerminosService.TABLA || "procesos_bi.dbo.T_terminos",
      "tipo = 'ATRIBUTO'"
    );

    atributos.forEach(item => {
      const c = item.caracteristicas;
      if (c && typeof c === 'string' && c.trim() !== "") {
        // Separamos por ";" y limpiamos los espacios
        const partes = c.split(";").map(p => p.trim()).filter(Boolean);

        partes.forEach(part => {
          if (!caracteristicas.includes(part)) {
            caracteristicas.push(part);
          }
        });
      }
    });

  } catch (error) {
    console.error("Error en cargaAtributos (SQL):", error);
  }
  return caracteristicas;
}

async function cargaTerminos() {
  let elemento = -1;

  try {
    // Aprovechamos el motor de SQL para que nos devuelva DIRECTAMENTE el ID más alto
    const resultado = await window.SqlHelper.query(
      "MAX(id) AS max_id",
      window.TerminosService.TABLA || "procesos_bi.dbo.T_terminos",
      "tipo = 'TERMINO'"
    );

    // Verificamos que trajo un resultado válido
    if (resultado && resultado.length > 0 && resultado[0].max_id !== null) {
      elemento = Number(resultado[0].max_id);
    }

  } catch (error) {
    console.error("Error en cargaTerminos (SQL):", error);
  }

  return elemento;
}

// Llenar el dropdown de características (Refactorizado para arreglo simple)
function loadOptions(caracteristicas) {
  const $caract = $("#nombrecaract");
  if ($caract.length === 0) return;

  $caract.empty();

  // Limpiar nulos, espacios extra y eliminar duplicados usando Set
  const uniqueValues = Array.from(new Set((caracteristicas || []).map(c => (c || "").trim()).filter(Boolean)));

  uniqueValues.forEach(element => {
    $caract.append(new Option(element, element, false, false));
  });

  if ($caract.hasClass("select2-hidden-accessible")) {
    $caract.trigger("change.select2");
  }
}

