function aplicarBusquedaGlosarioDesdeUrl(intento = 0) {
  const decodeParam = (v = "") => (v || "").toString().replace(/\+/g, " ").trim();
  const filtroUrl = decodeParam(getParams("filtro") || getParams("criterio") || "").toLowerCase();
  const buscarUrl = decodeParam(getParams("buscar"));
  const qUrl = decodeParam(getParams("q"));

  if (filtroUrl) {
    window.criterioGlosario = filtroUrl;
    setDropdownFiltroLabel(filtroUrl);
    nuevoCriterio(filtroUrl);
  }

  // Flujo especial para filtro dominio: primero fijar dominio, luego aplicar q (búsqueda interna)
  if (filtroUrl === "dominio" && buscarUrl) {
    window.dominio = buscarUrl;
    window.dominioBaseBusqueda = buscarUrl;
    const filtrado = searchList(buscarUrl, "ows_descripcion_dominio", window.aux);
    GlosarioApp.printSearchResults(filtrado, { skipUrlFilter: true });
    autocompletado(document.getElementById("glosario-search"), "ows_nombre_metad", filtrado);
    const btn = document.getElementById("dropdown-btn");
    if (btn) {
      btn.innerText = buscarUrl;
    }

    if (qUrl) {
      setBusquedaGlosarioDesdeUrl(qUrl);
      const filtradoQ = searchList(qUrl, "ows_nombre_metad", filtrado);
      GlosarioApp.printSearchResults(filtradoQ, { skipUrlFilter: true });
      syncGlosarioBusquedaUrl(qUrl, "dominio");
      return;
    }
  }

  if (buscarUrl === null || buscarUrl === undefined) return;
  setBusquedaGlosarioDesdeUrl(buscarUrl);

  const criterioActual = filtroGlosarioActual();
  if (criterioActual === "caso de uso" && (!window.casosDeUsoListado || !window.casosDeUsoListado.length)) {
    if (intento < 6) {
      return setTimeout(() => aplicarBusquedaGlosarioDesdeUrl(intento + 1), 250);
    }
  }

  ejecutarBusquedaGlosarioDesdeValor(buscarUrl);
}

function ejecutarBusquedaGlosarioDesdeValor(valor) {
  const criterioActual = filtroGlosarioActual();

  if (criterioActual === "caso de uso") {
    seleccionarCasoUsoPorNombre(valor);
    syncGlosarioBusquedaUrl(valor);
    return;
  }

  if (criterioActual === "dominio") {
    window.dominio = valor;
    const filtrado = searchList(valor || "", "ows_descripcion_dominio", window.aux);
    printSearchResults(filtrado, { skipUrlFilter: true });
    autocompletado(document.getElementById("glosario-search"), "ows_nombre_metad", filtrado);
    const btn = document.getElementById("dropdown-btn");
    syncGlosarioBusquedaUrl(valor);
    return;
  }

  GlosarioApp.printSearchResults(searchList(valor || "", "ows_nombre_metad", window.aux), { skipUrlFilter: true });
  syncGlosarioBusquedaUrl(valor);
}

