function getTablasOwnerDesglosado(usuario = null) {
  if (!usuario) return null;

  let desglose = {};
  let listaTablas = [];

  const fusion = getInfoTablasOficiales({ comoArray: true }) || [];
  const norm = v => String(v || "").trim();

  fusion.forEach(item => {
    if (norm(item.data_owner) === norm(usuario)) {
      listaTablas.push({
        txt_desc_tabla: item.tabla || item.txt_desc_tabla || " ",
        txt_fuente_aprovisionamiento: item.plataforma || item.txt_fuente_aprovisionamiento || " ",
        txt_servidor: item.servidor || item.txt_servidor || " ",
        txt_fuente_esquema: item.esquema || item.txt_fuente_esquema || "DBO",
        txt_host: item.base || item.txt_host || " ",
        txt_documentacion: (item.avance ?? "").toString(),
        etiquetas: item.etiquetas || " ",
        clasificacion: item.clasificacion || " ",
        descripcion: item.descripcion_tabla || " "
      });
    }
  });

  let catalogoEtiquetas = getCatalogoOGASUITE("1");
  desglose["total"] = listaTablas.length;

  listaTablas.forEach(e => {
    if (e.clasificacion === "OFICIAL") {
      desglose["totalOficiales"] = (desglose["totalOficiales"] || 0) + 1;
      if (e.descripcion && e.descripcion.trim()) desglose["documentadas"] = (desglose["documentadas"] || 0) + 1;
      else desglose["sinDocumentar"] = (desglose["sinDocumentar"] || 0) + 1;
    }

    (e.etiquetas || "").split("|").forEach(numeroEtiqueta => {
      const nombreEtiqueta = catalogoEtiquetas[String(numeroEtiqueta || "").trim()];
      if (nombreEtiqueta) {
        const key = nombreEtiqueta.toUpperCase();
        desglose[key] = (desglose[key] || 0) + 1;
      } else {
        desglose["SC"] = (desglose["SC"] || 0) + 1;
      }
    });
  });

  window.__lastOwnerDesglose = { usuario, listaTablas, desglose }; // debug
  return desglose;
}



//function tablasOficiales ficha
// function tablasOficiales ficha
async function fichaTablas() {
  // 1. Obtención de variables globales de entorno de forma segura
  window.diccionarioDT = typeof getDataOwners === 'function' ? getDataOwners()[0] : {};

  const dominioParam = typeof getParams === 'function' ? getParams("dominio") : "";
  const identificador = dominioParam ? dominioParam.replaceAll("\"", "") : "";

  let dominioInfo = null;
  let idDominioRelacionado = null;

  if (identificador) {
    try {
      dominioInfo = await searchDominios("descripcion_dominio", identificador, "Text");
      if (dominioInfo) {
        idDominioRelacionado = dominioInfo.id_dominio;
      }
    } catch (error) {
      console.error("[Ficha_Tablas] Error al consultar el dominio en SQL:", error);
    }
  }

  console.log("[Ficha_Tablas] dominio (query):", dominioParam, "id_dominio relacionado:", idDominioRelacionado);

  const Cod_Etiqueta = typeof getCatalogoOGASUITE === 'function' ? getCatalogoOGASUITE("1") : {};

  // 2. Manipulación del DOM
  const nombreDominioElement = document.getElementById("nombre-dominio");
  if (nombreDominioElement) {
    nombreDominioElement.innerHTML = `<strong>Dominio: </strong>${identificador}`;
  } else {
    console.warn("No se encontró el elemento con id 'nombre-dominio'");
  }

  // 3. Obtención de catálogos
  const tablas_oficiales = typeof getInfoTablasOficiales === 'function' ? getInfoTablasOficiales() : {};
  window.tablas_oficiales = tablas_oficiales;

  let clavesFuentesSet = null;
  if (idDominioRelacionado) {
    try {
      if (typeof obtenerClavesFuentesPorDominio === 'function') {
        const clavesFuentes = await obtenerClavesFuentesPorDominio(idDominioRelacionado);
        if (clavesFuentes && clavesFuentes.length) {
          clavesFuentesSet = new Set(
            clavesFuentes
              .map(typeof normalizarClaveFuente === 'function' ? normalizarClaveFuente : (c => c))
              .filter(Boolean)
          );
        }
      }
    } catch (error) {
      console.error("[OGA][fichaTablas] No se pudieron obtener claves de fuentes para el dominio:", error);
    }
  }

  // 4. Filtrado y Procesamiento
  const coincidenciasDescripcion = [];
  const identificadorNorm = (identificador || "").trim().toUpperCase();
  const tablasPorLlave = new Map();

  for (const [key, value] of Object.entries(tablas_oficiales)) {
    const etiquetasOriginales = value["etiquetas"];
    if (etiquetasOriginales && etiquetasOriginales !== " ") {
      const etiqueta = etiquetasOriginales.split("|").filter(Boolean);
      value["etiquetas_numero"] = etiquetasOriginales;
      value["etiquetas"] = etiqueta.map(e => Cod_Etiqueta[e] || e).join("|");
    }

    let llaveTabla = null;
    if (typeof normalizarLlaveTablaDesdeCatalogo === 'function') {
      llaveTabla = normalizarLlaveTablaDesdeCatalogo(value);
    }

    if (llaveTabla) {
      tablasPorLlave.set(llaveTabla, value);
    }

    // Coincidencia de dominio (case-insensitive) para asegurar que registros de SP no se pierdan
    const descripcion = (value["descripcion_dominio"] || "").trim();
    if (descripcion) {
      const lista = descripcion.split(";").map(e => e.trim().toUpperCase());
      if (lista.includes(identificadorNorm)) coincidenciasDescripcion.push(value);
    }
  }

  let dataFiltrada = coincidenciasDescripcion;

  if (clavesFuentesSet && clavesFuentesSet.size) {
    const coincidenciasFuentes = [];
    clavesFuentesSet.forEach(clave => {
      if (tablasPorLlave.has(clave)) {
        coincidenciasFuentes.push(tablasPorLlave.get(clave));
      }
    });
    if (coincidenciasFuentes.length) {
      dataFiltrada = coincidenciasFuentes;
    }
  }

  // 5. Preparación de DataTables y Estado
  // Fallback por si la utilidad no está definida (caso BuscadorCampos standalone)
  if (typeof construirCatalogoConEstado !== "function") {
    window.construirCatalogoConEstado = async (lista) => lista || [];
  }

  const catalogoConEstado = await window.construirCatalogoConEstado(dataFiltrada);
  window.catalogoCompleto = [...catalogoConEstado];
  window.catalogoOriginales = { '#tablaOficial': catalogoConEstado.map(e => ({ ...e })) };

  if (typeof cargarTodosAtributosCalidadDesdeCatalogoCompleto === 'function') {
    await cargarTodosAtributosCalidadDesdeCatalogoCompleto();
  }

  if (typeof precargarPorcentajesCalidad === 'function') {
    window.mapaPorcentajesCalidad = await precargarPorcentajesCalidad();
  }

  if (typeof inicializarFiltroCasoUsoFichaTablas === 'function') {
    await inicializarFiltroCasoUsoFichaTablas({
      idDominioRelacionado,
      catalogoConEstado,
      tablasPorLlave,
      identificador
    });
  }

  if (typeof setDataTableFichaTablas === 'function') {
    await setDataTableFichaTablas(identificador);
  }

  // 6. Finalización y Eventos
  if (typeof cleanModalTablas === 'function') cleanModalTablas();
  if (typeof ordenarDataOwners === 'function') ordenarDataOwners();
  if (typeof ordenarDataOwners3 === 'function') ordenarDataOwners3();
  if (typeof listenerFichaTablas === 'function') listenerFichaTablas(dataFiltrada, identificador);
  if (typeof Lista_Etiquetas === 'function') Lista_Etiquetas();
  if (typeof ModalEtiquetas === 'function') ModalEtiquetas();
}

async function inicializarFiltroCasoUsoFichaTablas({ idDominioRelacionado, catalogoConEstado, tablasPorLlave, identificador }) {
  const select = document.getElementById("filtro-caso-uso");
  if (!select) return;
  select.innerHTML = `<option value=""></option>`;

  if (!idDominioRelacionado) {
    select.disabled = true;
    if ($(select).data('select2')) $(select).select2('destroy');
    return;
  }

  try {
    const casos = await obtenerCasosUsoPorDominioSimple(idDominioRelacionado);
    casos.forEach(caso => {
      const opt = document.createElement("option");
      opt.value = caso.id;
      opt.textContent = caso.nombre || `Caso ${caso.id}`;
      select.appendChild(opt);
    });
    select.disabled = false;
    $(select).select2({
      theme: "bootstrap",
      placeholder: "Todos los casos de uso",
      width: "100%",
      allowClear: true
    });
  } catch (error) {
    console.error("[Ficha_Tablas] No se pudieron cargar casos de uso para el filtro:", error);
    select.disabled = true;
    if ($(select).data('select2')) $(select).select2('destroy');
  }

  // Log when el filtro se inicializa
  console.log("[Ficha_Tablas] Filtro 'caso de uso' listo: opciones cargadas =", select.options.length - 1);

  select.addEventListener("change", async (e) => {
    const casoId = e.target.value;
    const casoTexto = (e.target.selectedOptions && e.target.selectedOptions[0]) ? e.target.selectedOptions[0].textContent.trim() : "";
    console.log("[Ficha_Tablas] Filtro 'caso de uso' seleccionado:", casoId || "todos", "|", casoTexto || "Todos los casos de uso");
    const baseCatalogo = (window.catalogoOriginales && window.catalogoOriginales['#tablaOficial']) ? window.catalogoOriginales['#tablaOficial'] : catalogoConEstado;
    let dataFiltrada = baseCatalogo;

    if (casoId) {
      try {
        const claves = await obtenerClavesFuentesPorCaso(casoId);
        const clavesSet = new Set(claves.map(normalizarClaveFuente).filter(Boolean));
        console.log("[Ficha_Tablas] Fuentes del caso seleccionado:", claves);
        dataFiltrada = baseCatalogo.filter(row => {
          const llave = buildClaveTablaComparacion(row);
          return llave && clavesSet.has(llave);
        });
      } catch (error) {
        console.error("[Ficha_Tablas] Error al filtrar por caso de uso:", error);
      }
    }

    window.catalogoCompleto = dataFiltrada;
    await setDataTableFichaTablas(identificador);
  });

  // Log adicional para eventos de select2 (asegura que se vea al elegir/limpiar)
  $(select).on("select2:select", function (e) {
    const opt = e.params && e.params.data ? e.params.data : null;
    console.log("[Ficha_Tablas][select2] Caso seleccionado:", opt ? opt.id : "(sin id)", "|", opt ? opt.text : "(sin texto)");
  });
  $(select).on("select2:clear", function () {
    console.log("[Ficha_Tablas][select2] Filtro de caso de uso limpiado (todos)");
  });
}

async function obtenerCasosUsoPorDominioSimple(idDominio) {
  const endpoint = "http://gobinfoana01-2:8510/query";
  const body = {
    campos: "ID_CASO_USO, DESCRIPCION_CASO_USO",
    origen: "PROCESOS_BI.DBO.T_CASOS_USO_ANALITICA",
    condicion: `ID_DOMINIO = ${Number(idDominio)}`
  };
  const casos = await ejecutarConsultaGobInfo(endpoint, body);
  return (casos || []).map(row => ({
    id: Number(row.ID_CASO_USO ?? row.id_caso_uso ?? row.id_caso),
    nombre: (row.DESCRIPCION_CASO_USO ?? row.descripcion_caso_uso ?? "").toString().trim()
  })).filter(c => c.id);
}

async function obtenerClavesFuentesPorCaso(idCaso) {
  const endpoint = "http://gobinfoana01-2:8510/query";
  const registros = await ejecutarConsultaGobInfo(endpoint, {
    campos: "clave_fuente",
    origen: "PROCESOS_BI.DBO.T_CASOS_USO_FUENTES",
    condicion: `id_caso_uso = ${Number(idCaso)} AND (SN_ACTIVO = 1 OR SN_ACTIVO IS NULL)`
  });
  return (registros || [])
    .map(r => r?.CLAVE_FUENTE || r?.clave_fuente || "")
    .filter(Boolean);
}

