async function buscarCampoPorContexto(codigo, base, esquema, tabla, servidor, plataforma) {
  const resultados = await searchIT(codigo.toString());

  const coincidencia = resultados.find(el =>
    el.codigo === codigo.toString() &&
    el.base === base &&
    el.esquema === esquema &&
    el.tabla === tabla &&
    el.servidor === servidor &&
    el.plataforma === plataforma
  );

  return coincidencia ? coincidencia.campo : "";
}

