async function setDataTableFichaTablas(identificador) {
  const catalogoConEstado = window.catalogoCompleto || [];
  if ($.fn.DataTable.isDataTable('#tablaOficial')) {
    $('#tablaOficial').DataTable().clear().destroy();
  }
  console.log('tablaOficial len:', catalogoConEstado?.length);
  console.log('tablaOficial row0:', catalogoConEstado?.[0]);
  console.log('row0 keys:', catalogoConEstado?.[0] ? Object.keys(catalogoConEstado[0]) : []);

  window.tablaOficialInstance = $('#tablaOficial').DataTable({
    data: catalogoConEstado,
    destroy: true,
    deferRender: true,
    createdRow: function (row, data) {
      const valorBusqueda = `${data.servidor}_${data.esquema}_${data.base}_${data.tabla}`;
      const nombreTablaHTML = `[ ${data.base} ] . [ ${data.esquema} ] . [ ${data.tabla} ]`;
      const iconoTooltipLoader = `<span class="estado-icon-loader" style="width: 16px; height: 16px; display: inline-block; background: url('spinner.gif') no-repeat center center; background-size: contain; margin-right: 6px;"></span>`;
      let iconoTooltipFinal = iconoTooltipLoader;

      if ([0, 1, 2].includes(data._estado)) {
        const iconClass = data._estado === 2 ? 'simple-icon-doc' : 'iconsminds-loading-2';
        const iconColor = data._estado === 2 ? '#D2006E' : '#bbb';
        const tooltipText = obtenerEtiquetaEstado(data._estado);
        iconoTooltipFinal = `<icon class="${iconClass} estado-tooltip" data-toggle="tooltip" data-placement="right" title="${tooltipText}" style="font-size: 14px; color: ${iconColor}; cursor: pointer; margin-right: 4px;" onclick="visualizarArchivoReciente('${data.base}', '${data.esquema}', '${data.tabla}')"></icon>`;
      }

      const htmlInicial = `
        <icon class="simple-icon-pencil" type="button" data-toggle="dropdown" aria-haspopup="true" aria-expanded="false"></icon>
        <span style="position: relative; display: inline-flex; align-items: center;">
          <span class="estado-icon-placeholder" style="margin-right: 6px;">${iconoTooltipFinal}</span>
          <span onclick="buscarExploradorMetadatos('Tabla','${valorBusqueda}')" class="link_subrrayado" style="display: inline-flex; align-items: center;">
            ${nombreTablaHTML}
          </span>
        </span>
        <div class="dropdown-menu dropdown-menu-right mt-3">
          <a onclick="mostrarOpcionesCampo(2,'${data.data_owner}','')" class="dropdown-item do" href="#"></a>
          <a id="ds" onclick="mostrarOpcionesCampo(4,'${data.data_steward}','')" class="ds dropdown-item" href="#"></a>
          <a id="calidad" class="calidad dropdown-item" href="#" onclick="abrirModalIndicadores('${data.plataforma}', '${data.servidor}', '${data.base}', '${data.esquema}', '${data.tabla}')">Dimensiones de Calidad</a>
          <a id="eliminarDom" onclick="mostrarOpcionesCampo(7,'${identificador}','${data.descripcion_dominio}','${data.tabla}')" class="eliminarDom dropdown-item" href="#"></a>
          <a id="etiqueta" onclick="mostrarOpcionesCampo(9, '','','','','','','','','','${data.etiquetas_numero}')" class="etiqueta dropdown-item" href="#">Etiqueta</a>
          <div class="dropdown-item profiling-option" style="position: relative; cursor: pointer;" onmouseover="this.querySelector('.sub-options').style.display='block'" onmouseout="this.querySelector('.sub-options').style.display='none'">
            Profiling
            <div class="sub-options" style="display: none; position: absolute; top: 0; left: 100%; z-index: 10; background-color: #fff; box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1); width: 200px; padding: 10px; border-radius: 0.75rem;">
              <a id="generarProfiling" onclick="generarProfiling('${window.current_user}', '${data.servidor}', '${data.base}', '${data.esquema}', '${data.tabla}')" class="dropdown-item" href="#">Generar Profiling</a>
              <a id="visualizarProfiling" onclick="mostrarPopupProfiling('${data.base}', '${data.esquema}', '${data.tabla}')" class="dropdown-item" href="#">Ver Profiling</a>
            </div>
          </div>
        </div>`;

      $('td:eq(1)', row).html(htmlInicial);

      $(row).find('[data-toggle="tooltip"]').tooltip();

      const condicionOwner = data.data_owner !== " ";
      const condicionSteward = data.data_steward !== " ";
      let mensaje = '';

      if (condicionOwner || condicionSteward) {
        let nombre = condicionOwner ? capitalizarPrimeraLetra(data.nombre_data_owner.split(" ")[0]) + " " + capitalizarPrimeraLetra(data.nombre_data_owner.split(" ")[2]) : "";
        let nombre2 = condicionSteward ? capitalizarPrimeraLetra(data.nombre_data_steward.split(" ")[0]) + " " + capitalizarPrimeraLetra(data.nombre_data_steward.split(" ")[2]) : "";
        mensaje = condicionOwner && condicionSteward ? `Data Owner: ${nombre}<br>Data Steward: ${nombre2}` : (condicionOwner ? `Data Owner: ${nombre}` : `Data Steward: ${nombre2}`);
        const tablarow = row.children[4];
        $(tablarow).attr({ "data-toggle": "tooltip", "data-placement": "bottom" });
        $(tablarow).tooltip({
          html: true,
          boundary: 'window',
          title: mensaje,
          template: `<div class="custom-tooltip tooltip tooltip2"><div class="arrow"></div><div class="tooltip-inner inner"></div></div>`
        });
      }
    },
    initComplete: function () {
      const tabla = $('#tablaOficial').DataTable();
      $('#btn_tablas_oficiales-search').on('keyup', function () {
        tabla.search(this.value).draw();
      });
    },
    drawCallback: function () {
      changeoptionsnames();
      insertarIconosCalidadEnTabla();
    },
    paging: true,
    colResize: { isEnabled: true, hasBoundCheck: true },
    autoWidth: true,
    info: true,
    ordering: true,
    scrollX: true,
    scrollCollapse: true,
    scrollY: 'calc(50vh)',
    searching: true,
    dom: 'Btlip',
    buttons: [
      {
        extend: 'excel',
        text: 'Exportar a Excel',
        customize: function (xlsx) {
          customizeExcel(xlsx, 'Tablas Oficiales del Dominio ' + identificador, "");
        }
      }
    ],
    columns: [
      { data: 'txt_fuente_aprovisionamiento' },
      {
        data: null,
        render: function (data) {
          return ` [ ${data.base} ] . [ ${data.esquema} ] . [ ${data.tabla} ] `;
        }
      },
      {
        data: 'avance',
        render: function (data) {
          const numericData = parseFloat(data);
          return isNaN(numericData) || !data ? '0%' : numericData + '%';
        }
      },
      {
        data: 'etiquetas',
        render: function (data) {
          if (typeof data === 'string' && data.trim() !== '') {
            return `<div class="badge-container">${data.split('|').map(e => `<span style="font-size: 12px;" class="badge badge-pill badge-secondary atributo">${e.trim()}</span>`).join('&nbsp;')}</div>`;
          }
          return '';
        }
      },
    ],
    columnDefs: [
      { targets: 3, width: '120px' },
      { targets: 2, width: '10px' },
      { targets: 1, width: '200px' },
      { targets: 0, width: '10px' },
    ],
    language: {
      decimal: '',
      emptyTable: 'No hay datos disponibles en la tabla',
      info: '_TOTAL_ resultados',
      infoEmpty: 'Mostrando 0 a 0 de 0 registros',
      infoFiltered: '',
      thousands: ',',
      lengthMenu: 'Mostrar _MENU_ registros',
      loadingRecords: 'Cargando...',
      processing: '',
      search: '',
      zeroRecords: 'No se encontraron registros',
      paginate: {
        first: 'Primero', last: 'Último', next: '>', previous: '<'
      },
      aria: {
        sortAscending: ': activate to sort column ascending',
        sortDescending: ': activate to sort column descending'
      }
    },
    pageLength: 25
  });

  $('.dataTables_empty').css('text-align', 'center');
}

//Funcion de carga para FichaAtributo.aspx
async function fichaAtributo() {
  let identificador = getParams("atributo"); // se obtiene mediante parametros de URL el identificador del atributo a presentar
  if (!identificador) return; // Prevención si no hay parámetro en la URL

  identificador = identificador.replaceAll(" ", "").split("+");

  const atributo = await window.TerminosService.getAtributo(identificador[0]);

  if (!atributo) {
    console.error("No se encontró el atributo en la base de datos.");
    return;
  }

  $("#nombre-atributo").text(atributo.nombre || "");
  $("#dominio").text(atributo.dominios || "");
  $("#subdominio").text(typeof mayusc_each_word === 'function' ? mayusc_each_word(atributo.casos_uso || atributo.txt_desc_subdominio || "") : (atributo.casos_uso || ""));
  $("#subcategoria").text(typeof mayusc_each_word === 'function' ? mayusc_each_word(atributo.txt_desc_subcategoria || "") : (atributo.txt_desc_subcategoria || ""));
  $("#observacion").text(atributo.descripcion || "");

  // Asumo que cargarCaracteristicasAtributo también fue refactorizada para recibir el JSON
  if (typeof cargarCaracteristicasAtributo === 'function') {
    cargarCaracteristicasAtributo(atributo);
  }

  // Lógica de catálogos refactorizada para JSON y a prueba de errores
  let catalogo = atributo.catalogos_asociados;
  let catalogos = [];

  if (catalogo && catalogo.trim() !== "") {
    if (catalogo.includes(";")) {
      let cat = catalogo.split(";");
      cat.forEach(element => {
        let partes = element.trim().split("||");
        if (partes.length === 2) {
          catalogos.push({ vista: partes[0].trim(), codigo: partes[1].trim() });
        }
      });
    } else {
      let partes = catalogo.split("||");
      if (partes.length === 2) {
        catalogos.push({ vista: partes[0].trim(), codigo: partes[1].trim() });
      }
    }

    // buscar cada catalogo del array catalogos
    let busqueda = [];
    catalogos.forEach(element => {
      if (typeof searchCatalogo === 'function') {
        busqueda.push(searchCatalogo(element.vista, element.codigo));
      }
    });

    if (typeof setDataTableCatalogoFicha === 'function') {
      setDataTableCatalogoFicha(busqueda);
    }
  }

  if (localStorage.getItem("citizen") == null) {
    let pertenece = typeof revisar_usuario === 'function' ? revisar_usuario() : "false";
    localStorage.setItem('citizen', pertenece);
  }

  let pertenece = localStorage.getItem("citizen");
  if (pertenece === "false") {
    let tablaEl = document.getElementById("tabla");
    if (tablaEl) tablaEl.style.display = "none";
  } else {
    let errEl = document.getElementById("mostrarerror");
    if (errEl) errEl.style.display = "none";

    const info_tecnica_corta = typeof searchIT === 'function' ? await searchIT([identificador[0]]) : [];

    // Uniré el array de lista con la lista corta update
    const resultado_info_tecnica = [];
    // Creo un objeto para rastrear los campos ya procesados
    const camposProcesados = {};

    // Iterar sobre la lista larga y agrego elementos únicos al resultado
    info_tecnica_corta.forEach(elemento => {
      if (camposProcesados[elemento.llave_unica] === undefined && elemento.codigo === identificador[0]) {
        resultado_info_tecnica.push(elemento);
        camposProcesados[elemento.llave_unica] = true;
      }
    });

    if (typeof setDataTableAtributo === 'function') {
      if (pertenece === "No pertenece a las áreas") {
        setDataTableAtributo(resultado_info_tecnica, true);
      } else {
        setDataTableAtributo(resultado_info_tecnica, false);
      }
    }

    $(".resumen-metadatos-linaje-button").off("click").on("click", function (t) {
      t.preventDefault();
      $(".resumen-metadatos-linaje").toggleClass("shown");
      $(".resumen-metadatos-linaje-button").toggleClass("text-primary");
      $(this).tooltip('hide');
    });

    window.entidadesMetadatosLinaje = resultado_info_tecnica;

    //Lógica para llenar modal_indicadores de 2 secciones
    if (typeof fillModalCalidad === 'function') await fillModalCalidad();
    if (typeof deleteFiltroCalidad === 'function') deleteFiltroCalidad();

    if (!window.porcentajeResumen) {
      let canvasEl = document.getElementById("resumen-chart");
      if (canvasEl) {
        let ctx = canvasEl.getContext('2d');

        if (!window.promedioAtributo) {
          if (typeof setPromedioAtributo === 'function') setPromedioAtributo(atributo);
        }

        new Chart(ctx, {
          type: "doughnut",
          data: {
            labels: ["Avance", "Faltante"],
            datasets: [{
              label: "",
              borderColor: ["#D2006E", "#160F41"],
              backgroundColor: ["#D2006E", "#160F41"],
              borderWidth: 2,
              data: [window.promedioAtributo || 0, 100 - (window.promedioAtributo || 0)]
            }]
          },
          options: {
            elements: {
              center: {
                text: window.promedioAtributo === 0 ? "N/D" : `${window.promedioAtributo}%`,
                color: "#373737",
                fontStyle: "Nunito, sans-serif",
                sidePadding: 15,
                maxFontSize: 15,
                minFontSize: 15,
              }
            },
            plugins: {
              datalabels: { display: false }
            },
            responsive: true,
            maintainAspectRatio: false,
            cutoutPercentage: 80,
            title: {
              display: true,
              text: "Porcentaje de Calidad",
              fontStyle: "Nunito, sans-serif",
              minFontSize: 28,
              maxFontSize: 28
            },
            layout: {
              padding: { bottom: 20 }
            },
            legend: { display: false }
          }
        });
      }

      let numEntidadesEl = document.getElementById("numeroEntidadesPromedio");
      if (numEntidadesEl) {
        numEntidadesEl.innerHTML = `${window.entiadesEvaluadas || 0} ${(window.entiadesEvaluadas === 1) ? "entidad evaluada" : "entidades evaluadas"} `;
      }

      if (typeof loadCardResumen === 'function') loadCardResumen();
    }
  }

  if (typeof registrar_visita === 'function') {
    registrar_visita("FICHA DE ATRIBUTO", atributo.nombre || "");
  }
}

function calcularEstadisticas(lista) {
  const basesUnicas = new Set();           // Almacenar los orígenes únicos
  const tablasPorBase = {};                 // Almacenar las tablas únicas por origen
  let totalCampos = 0;                     // Contador total de atributos

  lista.forEach((item) => {
    // 1. Contar orígenes únicos
    basesUnicas.add(item.base);

    // 2. Contar tablas únicas por origen
    if (!tablasPorBase[item.base]) {
      tablasPorBase[item.base] = new Set();
    }
    tablasPorBase[item.base].add(item.tabla);

    // 3. Contar total de atributos
    totalCampos++;
  });

  // Número total de tablas sumando todas las tablas únicas por origen
  const totalTablas = Object.values(tablasPorBase).reduce((sum, set) => sum + set.size, 0);

  return {
    bases: basesUnicas.size, // Número de orígenes únicos
    tablas: totalTablas,           // Número total de tablas únicas
    campos: totalCampos      // Número total de atributos
  };
}



function loadCardResumen() {


  let contadores = calcularEstadisticas(window.entidadesMetadatosLinaje)

  window.porcentajeResumen = {
    tablas: contadores.tablas,
    bases: contadores.bases,
    campos: contadores.campos,
    artefactos: artefactos.size,
  }
  $("#resumen-contador-bases").text(window.porcentajeResumen.bases)
  $("#resumen-contador-tablas").text(window.porcentajeResumen.tablas)
  $("#resumen-contador-campos").text(window.porcentajeResumen.campos)
  $("#resumen-contador-artefactos").text("--")
}

function tablaCalidadVacia() {
  let canExit = true;  // Para verificar si puede salir globalmente

  // Iterar sobre cada fila del DataTable
  $("#indicadores_calidad tbody tr").each(function () {
    let hasText = false;
    let row = $(this);  // Fila actual

    // Verificar si los inputs en la fila tienen texto
    row.find(".valor_calidad_atributo").each(function () {
      if ($(this).val().length > 1) {
        hasText = true;
      }
    });

    row.find(".valor_calidad_reglas").each(function () {
      if ($(this).val()) {
        hasText = true;
      }
    });

    // Verificar si el botón de la fila está deshabilitado
    let isButtonDisabled = row.find(".btnGuardarIndicadores").prop("disabled");
    // Si tiene texto y el botón no está deshabilitado, no se puede salir
    if (hasText && !isButtonDisabled) {
      canExit = false;  // No permitir salida
      return false;  // Salir del loop de filas, no tiene sentido seguir buscando
    }
  });
  return canExit;
}

async function fillModalCalidad() {
  $("#nueva-entidad").click(function () {
    if (!tablaCalidadVacia()) {
      $("#confirmModal").modal('show'); // Muestra el modal
    } else {
      deleteFiltroCalidad()
    }
  });

  // Si se presiona "Sí" en el modal
  $("#confirmYes").click(function () {
    // Ejecuta la función de eliminación cuando se confirma
    deleteFiltroCalidad();
    $("#confirmModal").modal('hide'); // Oculta el modal después de confirmar
  });
  window.calidadTablasOficiales = getAutocompletadoTablas();

  window.entidadesMetadatosLinaje.sort((a, b) => a.tabla.localeCompare(b.tabla))
  window.entidadesMetadatosLinaje.sort((a, b) => a.esquema.localeCompare(b.esquema))
  window.entidadesMetadatosLinaje.sort((a, b) => a.base.localeCompare(b.base))
  const encontrados = new Set();
  const resultado = window.entidadesMetadatosLinaje.filter(obj => {
    if (!encontrados.has(obj.llave_tabla)) {
      encontrados.add(obj.llave_tabla);
      return true;
    }
    return false;
  });

  let sortedSource = resultado.map(item => ({ label: item.tabla.toLocaleUpperCase(), value: item }))
  // let sortedSource = window.entidadesMetadatosLinaje.map(item =>( {label:item.tabla.toLocaleUpperCase() , value: item}))
  $("#entidad-search").autocomplete({
    source: sortedSource,
    select: function (event, ui) {
      // Evitar que se establezca el valor por defecto del input (que sería el `value`)
      event.preventDefault();
      let entidad = ui.item.value

      let itemLlave = `[${entidad.servidor || entidad.txt_servidor}].[${entidad.base || entidad.txt_host}].[${entidad.esquema || entidad.txt_fuente_esquema}].[${entidad.tabla || entidad.txt_desc_tabla}]`
      let selectedItem = $(".lista-entidades-calidad__item")[window.listaEntidadesCalidad.indexOf(itemLlave)]

      if (!selectedItem) {
        fillInfoEntidadIndicadores(ui.item.value)
        filtrarTablaCalidad();
      } else {
        selectedItem.click()
      }
    }
  }).autocomplete("widget").addClass("select-entidades")
  //Llena la lista de entidades que cuentan con documentacion de indicadores de calidad seccion izquierda modal
  await fillListaEntidades()
}

//Funcion para mostrar los indicadores de calida de la entidad seleccionada
function filtrarTablaCalidad() {
  $("#entidad-buscar").css("display", "inherit");
  $("#entidad-actual").text(window.entidad_actual || "Seleccione una Entidad");
  let tablas = getCalidad_atributo(window.identificador_atributo)
  let filtrado = []
  let servidor = window.objeto_entidad_actual.servidor || window.objeto_entidad_actual.txt_servidor
  let base = window.objeto_entidad_actual.base || window.objeto_entidad_actual.txt_host
  let esquema = window.objeto_entidad_actual.esquema || window.objeto_entidad_actual.txt_fuente_esquema
  let tabla = window.objeto_entidad_actual.tabla || window.objeto_entidad_actual.txt_desc_tabla
  Object.entries(tablas).forEach(([key, value]) => {
    if (
      key.includes(window.entidad_actual) && (
        value.servidor === servidor &&
        value.base === base &&
        value.esquema === esquema &&
        value.tabla === tabla
      )) filtrado.push(value)
  })
  let data_tabla = [];
  $.each(window.tabla_indicador_calidad, function (value, text) {
    data_tabla.push({ value: value, text: text });
  });

  // Integrar los porcentajes en los datos de la tabla
  for (let i = 0; i < data_tabla.length; i++) {
    let value = data_tabla[i].value;
    for (let key in filtrado) {
      if (filtrado[key].id_dimension == value &&
        filtrado[key].id_atributos == window.identificador_atributo) {
        data_tabla[i].porcentaje = filtrado[key].valor;
        data_tabla[i].descripcion_reglas = filtrado[key].descripcion_reglas;
        data_tabla[i].usuario_ult_actualizacion = filtrado[key].usuario_ult_actualizacion;
        data_tabla[i].fecha_ult_actualizacion = filtrado[key].fecha_ult_actualizacion;
        break;
      }
    }
  }
  redrawDataTable("indicadores_calidad", data_tabla);
  $('.btnGuardarIndicadores').prop('disabled', true);

}

//Funcion para llenar la informacion de la entidad seleccionada
// Función para llenar la información de la entidad seleccionada
async function fillInfoEntidadIndicadores(entidad) {
  let entidadSearch = $("#entidad-search");
  entidadSearch.css("background-color", '#e9ecef');
  entidadSearch.prop('disabled', true);

  let itemLlave = `[${entidad.plataforma}].[${entidad.servidor}].[${entidad.base}].[${entidad.esquema}].[${entidad.tabla}]`;

  let selectedItem = window.calidadTablasOficiales.find(item =>
    `[${item.txt_fuente_aprovisionamiento}].[${item.txt_servidor}].[${item.txt_host}].[${item.txt_fuente_esquema}].[${item.txt_desc_tabla}]` === itemLlave
  )
  // ) || window.entidadesMetadatosLinaje.find(item =>
  //   `[${item.servidor}].[${item.base}].[${item.esquema}].[${item.tabla}]` === itemLlave
  // );

  if (selectedItem) {
    window.entidad_actual = selectedItem.txt_desc_tabla || selectedItem.tabla || "";
    window.objeto_entidad_actual = selectedItem;

    $("#entidad-search").val(selectedItem.txt_desc_tabla || selectedItem.tabla || "");
    $("#entidad-actual").text(selectedItem.txt_desc_tabla || selectedItem.tabla || "Entidad no encontrada");
    $("#servidor").val(selectedItem.txt_servidor || selectedItem.servidor || "");
    $("#Aprovisionamiento").val(selectedItem.txt_fuente_aprovisionamiento || selectedItem.plataforma || "");
    $("#base").val(selectedItem.txt_host || selectedItem.base || "");
    $("#Esquema").val(selectedItem.txt_fuente_esquema || selectedItem.esquema || "");
    $("#documentacion").val(`${selectedItem.txt_documentacion || selectedItem.porcentaje_avance || ""}%`);

    let identificador = getParams("atributo");
    console.log("atributo detectado =", identificador);
    identificador = identificador.split(" ");
    const atributo = window.TerminosService.getAtributo(identificador[0]);

    if (atributo) {
      $("#atributo-nombre").val(atributo.attr("ows_nombre_metad"));

      //  Buscar campo técnico usando searchIT
      const info_tecnica_corta = await searchIT(identificador[0]);

      const campo = info_tecnica_corta.find(el =>
        el.codigo === identificador[0] &&
        el.base === entidad.base &&
        el.esquema === entidad.esquema &&
        el.tabla === entidad.tabla &&
        el.plataforma === entidad.plataforma
      )?.campo || "";

      $("#campo").val(campo);
    }
  }
}

//Funcion para llenar la lista de entidades con indicadores de calidad evaluadas
async function fillListaEntidades() {
  let entidadesCalidad = getEntidad_Atributo(window.identificador_atributo || "");
  window.listaEntidadesCalidad = [];
  let listaEntidadesDocumentadas = document.getElementById("lista-entidades-calidad");
  listaEntidadesDocumentadas.innerHTML = '';

  // Inyectar estilos visuales para el modal de profiling
  if (!document.getElementById("profiling-modal-style")) {
    const estilo = document.createElement("style");
    estilo.id = "profiling-modal-style";
    estilo.innerHTML = `
      #profilingModal .modal-dialog {
        max-width: 95% !important;
        width: 1000px !important;
        border: 1px solid rgba(128, 128, 128, 0.3);
        border-radius: 15px;
      }
      #profilingModal .modal-content {
        min-width: 1000px !important;
        border-radius: 15px;
        border: 1px solid rgba(128, 128, 128, 0.2);
        box-shadow: 0 6px 20px rgba(0, 0, 0, 0.1);
      }
    `;
    document.head.appendChild(estilo);
  }

  for (const item of entidadesCalidad) {
    let entidad = document.createElement("a");

    // Espera el estado del profiling
    const estado = await estadoProfiling(item.base, item.esquema, item.tabla);
    const iconClass = estado === 2 ? 'simple-icon-doc' : 'iconsminds-loading-2';
    const iconColor = estado === 2 ? '#D2006E' : '#bbb';

    // Crear icono según el estado
    let iconHTML = '';
    if (estado === 2 || estado === 1 || estado === 0) {
      const onclickAction = estado === 2
        ? `onclick="mostrarPopupProfiling('${item.base}', '${item.esquema}', '${item.tabla}')"`
        : '';

      iconHTML = `
        <icon class="${iconClass}"
              style="font-size: 13px; color: ${iconColor}; margin-left: 8px; cursor: ${estado === 2 ? 'pointer' : 'default'};"
              title="${estado === 2 ? 'Ver Profiling generado' : 'Profiling en proceso'}"
              ${onclickAction}>
        </icon>`;
    }

    // Crear elemento visual
    entidad.innerHTML = `${iconHTML}${item.tabla.replaceAll('<br>', '')}`;
    entidad.className = "mb-2 lista-entidades-calidad__item";
    entidad.style.fontSize = "clamp(0.65rem, .6vw + 0.2rem, 1.125rem)";
    entidad.style.minWidth = "280px";
    entidad.style.padding = "6px 10px";
    entidad.style.borderRadius = "6px";
    entidad.style.display = "inline-block";
    entidad.setAttribute("href", "#catalogo");

    entidad.addEventListener("click", function () {
      $('a.font-weight-bold.color-theme-1').removeClass('font-weight-bold color-theme-1');
      this.classList.add("font-weight-bold", "color-theme-1");
      fillInfoEntidadIndicadores(item);
      filtrarTablaCalidad();
    });

    window.listaEntidadesCalidad.push(`[${item.servidor}].[${item.base}].[${item.esquema}].[${item.tabla}]`);
    listaEntidadesDocumentadas.appendChild(entidad);
  }
}

function chartfaltante() {
  let parametros = ["Completitud", "Unicidad", "Validez", "Lógica", "Precisión", "Integridad", "Oportunidad", "Cobertura", "Integralidad"]
  let data = [100, 80, 95, 90.5, 85, 85, 96, 90.87, 88.55]
  Chart.pluginService.register({
    beforeDraw: function (chart) {
      if (chart.config.options.elements.center) {
        // Get ctx from string
        var ctx = chart.chart.ctx;

        // Get options from the center object in options
        var centerConfig = chart.config.options.elements.center;
        var fontStyle = centerConfig.fontStyle || 'Arial';
        var txt = centerConfig.text;
        var color = centerConfig.color || '#000';
        var maxFontSize = centerConfig.maxFontSize || 75;
        var sidePadding = centerConfig.sidePadding || 20;
        var sidePaddingCalculated = (sidePadding / 100) * (chart.innerRadius * 2)
        // Start with a base font of 30px
        ctx.font = "30px " + fontStyle;

        // Get the width of the string and also the width of the element minus 10 to give it 5px side padding
        var stringWidth = ctx.measureText(txt).width;
        var elementWidth = (chart.innerRadius * 2) - sidePaddingCalculated;

        // Find out how much the font can grow in width.
        var widthRatio = elementWidth / stringWidth;
        var newFontSize = Math.floor(30 * widthRatio);
        var elementHeight = (chart.innerRadius * 2);

        // Pick a new font size so it will not be larger than the height of label.
        var fontSizeToUse = Math.min(newFontSize, elementHeight, maxFontSize);
        var minFontSize = centerConfig.minFontSize;
        var lineHeight = centerConfig.lineHeight || 25;
        var wrapText = false;

        if (minFontSize === undefined) {
          minFontSize = 20;
        }

        if (minFontSize && fontSizeToUse < minFontSize) {
          fontSizeToUse = minFontSize;
          wrapText = true;
        }

        // Set font settings to draw it correctly.
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        var centerX = ((chart.chartArea.left + chart.chartArea.right) / 2);
        var centerY = ((chart.chartArea.top + chart.chartArea.bottom) / 2);
        ctx.font = fontSizeToUse + "px " + fontStyle;
        ctx.fillStyle = color;

        if (!wrapText) {
          ctx.fillText(txt, centerX, centerY);
          return;
        }

        var words = txt.split(' ');
        var line = '';
        var lines = [];

        // Break words up into multiple lines if necessary
        for (var n = 0; n < words.length; n++) {
          var testLine = line + words[n] + ' ';
          var metrics = ctx.measureText(testLine);
          var testWidth = metrics.width;
          if (testWidth > elementWidth && n > 0) {
            lines.push(line);
            line = words[n] + ' ';
          } else {
            line = testLine;
          }
        }

        // Move the center up depending on line height and number of lines
        centerY -= (lines.length / 2) * lineHeight;

        for (var n = 0; n < lines.length; n++) {
          ctx.fillText(lines[n], centerX, centerY);
          centerY += lineHeight;
        }
        //Draw text in center
        ctx.fillText(line, centerX, centerY);
      }
    }
  });
  let y = 0
  for (let x = 2; x < (parametros.length + 2); x++) {
    let nombre = "categoryChart" + x
    var categoryChart = document.getElementById(nombre);
    var myDoughnutChart = new Chart(categoryChart, {
      //    plugins: [centerTextPlugin],
      type: "doughnut",
      data: {
        labels: ["Avance", "Faltante"],
        datasets: [
          {
            label: "",
            borderColor: ["#D2006E", "#160F41"],
            backgroundColor: [
              "#D2006E",
              "#160F41"
            ],
            borderWidth: 2,
            data: [data[y], 100 - data[y]]
          }
        ]
      },
      draw: function () { },
      options: {
        elements: {
          center: {
            text: data[y] + "%",
            color: "#373737",
            fontStyle: " Nunito, sans-serif", // Default is Arial
            sidePadding: 15, // Default is 20 (as a percentage)
            maxFontSize: 15, // Default is 20 (in px), set to false and text will not wrap.
            minFontSize: 15,


          }
        },
        plugins: {
          datalabels: {
            display: false
          }
        },
        responsive: true,
        maintainAspectRatio: false,
        cutoutPercentage: 80,
        title: {
          display: true,


          text: parametros[y],
          fontStyle: " Nunito, sans-serif", // Default is Arial
          minFontSize: 28,
          maxFontSize: 28
        },
        layout: {
          padding: {
            bottom: 20
          }
        },
        legend: {
          display: false,

        },
        onClick: (e) => {
          clickDonut(e, myDoughnutChart);
        }
        // tooltips: chartTooltip
      }
    });
    y += 1

    /*var chartTooltip = {
      backgroundColor: foregroundColor,
      titleFontColor: primaryColor,
      borderColor: separatorColor,
      borderWidth: 0.5,
      bodyFontColor: primaryColor,
      bodySpacing: 10,
      //xPadding: 15,
     // yPadding: 15,
      cornerRadius: 0.15,
      displayColors: false
    };*/
  }
  return Math.round((data.reduce(add, 0)) / data.length)
}

function add(accumulator, a) {
  return accumulator + a;
}

