//funcion para segmentar datatable de catalogo de referencias
function segmentarTabla(tabla, valor) {
  const dt = $(tabla).DataTable();

  if (!dt) {
    console.error(`? No se encontró la tabla: ${tabla}`);
    return;
  }

  const usarSearchDirecto = (tabla === "#catalogo" || tabla === "#autorizacion" && tabla != "#tablaOficial");
  const btn = document.getElementById("segmentar-tabla-btn");

  if (usarSearchDirecto) {
    // Usa el método search directo sobre la columna 3
    dt.columns(3).search(valor === "Todas" ? "" : valor).draw();
  } else {
    // Segmentación usando copia local en memoria
    window.catalogoOriginales = window.catalogoOriginales || {};
    const datosOriginales = window.catalogoOriginales[tabla] || dt.rows().data().toArray();

    if (!Array.isArray(datosOriginales) || datosOriginales.length === 0) {
      console.warn("?? No hay datos para aplicar el filtro.");
      return;
    }

    dt.clear();

    if (valor === "Todas") {
      dt.rows.add(datosOriginales);
      dt.page.len(25);
    } else if (valor === "Con Profiling" && tabla === "#tablaOficial") {
      const filtradas = datosOriginales.filter(r => r.tiene_profiling);
      dt.rows.add(filtradas);
      dt.page.len(filtradas.length);
    } else {
      const filtradas = datosOriginales.filter(r => {
        if (typeof r.etiquetas === 'string') {
          return r.etiquetas.split('|').map(e => e.trim()).includes(valor);
        }
        return Object.values(r).some(v => String(v).toLowerCase().includes(valor.toLowerCase()));
      });
      dt.rows.add(filtradas);
      dt.page.len(25);
    }

    dt.draw();
  }

  // Actualizar botón segmentador y tooltips
  btn.textContent = valor;
  btn.classList.toggle("activo", valor !== "Todas");
  $('[data-toggle="tooltip"]').tooltip();
}

