//Funcion de carga para Dominio_metadatos_linaje.aspx
async function metadatosLinaje() {
  // 1. Obtener parámetros de forma segura
  const idDominioParam = typeof getParams === 'function' ? getParams("id_dominio") : null;
  if (!idDominioParam) return;

  const dominio = await searchDominios("id_dominio", idDominioParam, "Number");

  if (!dominio) {
    console.error("[metadatosLinaje] No se encontró el dominio con ID:", idDominioParam);
    return;
  }

  const dominioId = dominio.id_dominio;
  const descripcionDominio = dominio.descripcion_dominio || "Sin Dominio";

  // 3. Actualizar UI con la información del dominio
  if (typeof fillBreadcrumbs === 'function') {
    fillBreadcrumbs(dominioId, descripcionDominio);
  }
  $("#nombre-dominio").text(descripcionDominio);

  // 4. Obtener atributos del dominio 
  // (Asumiendo que getAtributosFrom también migró a SQL, agregamos 'await' por seguridad)
  let atributos = [];
  if (typeof getAtributosFrom === 'function') {
    // Si la función aún es síncrona, el await no afectará. Si es asíncrona, prevendrá un error.
    atributos = await getAtributosFrom(descripcionDominio) || [];
  }
  window.atributos = atributos;

  if (typeof autocompleteMetadatosLinaje === 'function') {
    autocompleteMetadatosLinaje(document.getElementById("atributo-search"), atributos);
  }

  // 5. Llenado inicial de la lista de atributos
  const contenedorLista = document.getElementById("lista-atributos");
  if (contenedorLista) contenedorLista.innerHTML = '';

  let atributos_ids = [];

  atributos.forEach(function (item) {
    const itemId = item.id || item.id_metad;
    const itemNombre = (item.nombre || item.nombre_metad || "Sin Nombre").replaceAll('<br>', '');

    if (itemId) atributos_ids.push(itemId);

    const enlace = document.createElement("a");
    enlace.innerHTML = itemNombre;
    enlace.className = "mb-2";
    enlace.setAttribute("href", "#catalogo");

    // Evento click del enlace
    enlace.addEventListener("click", function (e) {
      e.preventDefault(); // Evitamos el salto brusco en la página por el href="#"
      $('a.font-weight-bold.color-theme-1').removeClass('font-weight-bold color-theme-1');

      const searchInput = document.getElementById("atributo-search");
      if (searchInput) searchInput.value = this.innerHTML;

      window.atributo_actual = this.innerHTML;
      this.classList.add("font-weight-bold", "color-theme-1");

      if (typeof filtrarTabla === 'function') filtrarTabla();
    });

    if (contenedorLista) contenedorLista.appendChild(enlace);
  });

  // 6. Obtener Información Técnica (Linaje)
  let informacion_tecnica = [];
  if (typeof searchIT === 'function' && atributos_ids.length > 0) {
    informacion_tecnica = await searchIT(atributos_ids);
  }
  window.it = informacion_tecnica;

  if (typeof setDataTableMetadatosLinaje === 'function') {
    setDataTableMetadatosLinaje(informacion_tecnica);
  }

  // 7. Ajustes visuales de la tabla
  $("#catalogo_wrapper").css("height", "356px").addClass("overflow-auto");

  // 8. Registro de métricas
  if (typeof registrar_visita === 'function') {
    registrar_visita("METADATOS Y LINAJE DE DOMINIO", descripcionDominio);
  }
}

//Buscar atributos mediante regex
function buscarAtributo(search_value, list) {
  if (search_value.includes("(")) search_value = search_value.replaceAll("(", "\\(");
  if (search_value.includes(")")) search_value = search_value.replaceAll(")", "\\)");
  let regex = new RegExp(search_value, "i");
  var results = list.filter(item => regex.test(item.attr("ows_nombre_metad")));
  return results;
}

