//Función que simula una búsqueda por tabla.
//Al hacer clic en una tabla en el "Explorador de Metadatos", te lleva a la vista tablas con los datos de esa tabla
function mostrarbusquedaTabla(servidor, base, esquema, tabla) {
  $("[data-toggle='tooltip']").tooltip('hide');
  let actual = document.getElementById("dropdown-buscador").innerText;
  document.getElementById("dropdown-buscador").innerText = "Tabla";

  let opcion = document.getElementById("opcionfiltro").innerText;
  let opcion2 = document.getElementById("opcionfiltro2").innerText;

  if (opcion == "Tabla") {
    document.getElementById("opcionfiltro").innerText = actual;
  } else if (opcion2 == "Tabla") {
    document.getElementById("opcionfiltro2").innerText = actual;
  }

  document.getElementById("campos-search").value = tabla;
  window.tablab = tabla;

  if (!$("#switchS3").is(':checked')) {
    document.getElementById("switchS3").click();
  }

  let visible = $("#columna-arbol").is(":visible");

  let resultados = buscarCampo(tabla, window.info_tecnica, servidor, base, esquema, tabla, false, true, true);
  let distinto = arrayCamposDistinct(resultados)
  window.campos = resultados;
  setDataTableBuscadorCampos(distinto);
}

function autoBuscarTablaDesdeUrl(tablaNombre, dataset, servidor = window.servidor, base = window.base, esquema = window.esquema) {
  const valor = (tablaNombre || '').trim();
  const tablaActual = (window.tabla || '').replaceAll(' ', '');
  if (!valor || (valor.replaceAll(' ', '') === '' && !tablaActual)) return;

  const dataFuente = Array.isArray(dataset) && dataset.length
    ? dataset
    : (Array.isArray(window.info_tecnica) ? window.info_tecnica : []);
  if (!dataFuente.length) return;

  window.tablab = valor;
  const resultados = buscarCampo(valor, dataFuente, window.servidor, window.base, window.esquema, window.tabla, false);
  const camposDistinct = arrayCamposDistinct(resultados);
  const mostrarAgrupado = $("#switchS3").is(':checked');

  const arbol = document.getElementById("arbol_campos");
  if (arbol) {
    arbol.innerHTML = cargar_arbol(resultados);
  }

  setDataTableBuscadorCampos(mostrarAgrupado ? camposDistinct : resultados);

  if (!$("#campos-buscar").is(":visible")) { $("#campos-buscar").toggle(); }
}


