// Reactivado: actualizarDominio con persistencia en Z_METADATA_TABLAS.
// Opcional: plataforma/txt_fuente_aprovisionamiento como 7mo parámetro.
function actualizarDominio(cambio, tabla, servidor, base, esquema, descripcion, plataforma) {
  // Validar llaves para evitar registros "undefined"
  const t = (tabla || '').toString().trim();
  const s = (servidor || '').toString().trim();
  const b = (base || '').toString().trim();
  const e = (esquema || '').toString().trim();
  if (!t || !s || !b || !e) return;
  const valor = (descripcion ?? '').toString();

  if (__updDominioLock) return;
  __updDominioLock = true;
  setTimeout(() => { __updDominioLock = false; }, 300);

  const llaveTabla = `${s.toUpperCase()}_${e.toUpperCase()}_${b.toUpperCase()}_${t.toUpperCase()}`;
  const plataformaFallback = (() => {
    if (plataforma && String(plataforma).trim()) return String(plataforma).trim();
    const cache = (window.tablas_oficiales && window.tablas_oficiales[llaveTabla]) || null;
    if (cache) {
      if (cache.plataforma && String(cache.plataforma).trim()) return String(cache.plataforma).trim();
      if (cache.txt_fuente_aprovisionamiento && String(cache.txt_fuente_aprovisionamiento).trim()) return String(cache.txt_fuente_aprovisionamiento).trim();
    }
    if (typeof getInfoTablasOficialesTemp === "function") {
      const temp = getInfoTablasOficialesTemp() || {};
      if (temp[llaveTabla]) {
        const rec = temp[llaveTabla];
        if (rec.plataforma && String(rec.plataforma).trim()) return String(rec.plataforma).trim();
        if (rec.txt_fuente_aprovisionamiento && String(rec.txt_fuente_aprovisionamiento).trim()) return String(rec.txt_fuente_aprovisionamiento).trim();
      }
    }
    return "";
  })();

  const listName = "Z_METADATA_TABLAS";
  const caml = '<Query><Where>\
      <And>\
        <Eq><FieldRef Name="txt_desc_tabla"/><Value Type="Text">' + t + '</Value></Eq>\
        <And>\
          <Eq><FieldRef Name="txt_servidor"/><Value Type="Text">' + s + '</Value></Eq>\
          <And>\
            <Eq><FieldRef Name="txt_host"/><Value Type="Text">' + b + '</Value></Eq>\
            <Eq><FieldRef Name="txt_fuente_esquema"/><Value Type="Text">' + e + '</Value></Eq>\
          </And>\
        </And>\
      </And>\
    </Where></Query>';

  $().SPServices({
    operation: "GetListItems",
    async: true,
    listName,
    CAMLQuery: caml,
    CAMLViewFields: "<ViewFields><FieldRef Name='ID' /></ViewFields>",
    completefunc: function (xData) {
      const rows = $(xData.responseXML).SPFilterNode("z:row");
      const valuepairs = [[cambio, valor]];
      if (plataformaFallback) valuepairs.push(["txt_fuente_aprovisionamiento", plataformaFallback]);

      if (rows.length > 0) {
        // Update existente (sin tocar llaves)
        $().SPServices.SPUpdateMultipleListItems({
          async: true,
          listName,
          batchCmd: "Update",
          CAMLQuery: caml,
          valuepairs
        });
      } else {
        // New: crea con llaves + cambio + plataforma opcional
        const valuepairsNew = [
          ["txt_desc_tabla", t],
          ["txt_servidor", s],
          ["txt_host", b],
          ["txt_fuente_esquema", e],
          [cambio, valor]
        ];
        if (plataformaFallback) valuepairsNew.push(["txt_fuente_aprovisionamiento", plataformaFallback]);

        $().SPServices({
          operation: "UpdateListItems",
          async: true,
          listName,
          batchCmd: "New",
          valuepairs: valuepairsNew
        });
      }
    }
  });
}

function getUserAndDate() {
  //Obtengo el usuario que está haciendo los cambios
  let usuario;
  if (window.current_user == undefined) {
    usuario = obtenerUsuario();
    var current_user = usuario.current_user;
    window.current_user = current_user;

  } else {
    current_user = window.current_user;
  }

  //Obtengo los datos de empleado asociados a ese usuario
  let datos_usuario = datos_visitante(current_user);
  //En caso no pueda obtener sus datos, pongo el nombre de usuario como codigo empleado
  if (!datos_usuario) {
    var array_datos_usuario = [current_user, " ", " "]
  } else {
    var array_datos_usuario = [datos_usuario.attr("ows_valor4"), datos_usuario.attr("ows_valor1"), datos_usuario.attr("ows_valor10")];
  }

  var tzoffset = (new Date()).getTimezoneOffset() * 60000; //offset in milliseconds
  var localISOTime = (new Date(Date.now() - tzoffset)).toISOString().slice(0, -1);
  if (current_user === "jcastillo3") return [['22398', 'GOBIERNO DE INFORMACION Y ANALITICA', 'TRANSFORMACION'], localISOTime]
  return [array_datos_usuario, localISOTime]
}

function actualizarTablasOficiales(cambio, tabla, servidor, base, esquema, nuevo_valor) {
  console.log("?? [actualizarTablasOficiales] INICIO", { cambio, tabla, servidor, base, esquema, nuevo_valor });
  try {
    // 0) Validaciones mínimas
    if (!cambio) {
      console.warn("?? [actualizarTablasOficiales] 'cambio' vacío/indefinido.");
      return;
    }
    if (!tabla || !servidor || !base || !esquema) {
      console.warn("?? [actualizarTablasOficiales] Faltan llaves (tabla/servidor/base/esquema).", { tabla, servidor, base, esquema });
      return;
    }

    // 1) Usuario/fecha
    const datos_usuario = getUserAndDate();
    const array_datos_usuario = datos_usuario?.[0];
    const localISOTime = datos_usuario?.[1];
    console.log("?? [actualizarTablasOficiales] Usuario/Fecha", { array_datos_usuario, localISOTime });

    // 2) Mapeo de campos según el tipo de cambio
    const dict_log_cambios = {
      "data_owner": ["data_owner", "nombre_data_owner", "usuario_modificacion_do", "fecha_modificacion_do"],
      "data_steward": ["data_steward", "nombre_data_steward", "usuario_modificacion_ds", "fecha_modificacion_ds"],
      "descripcion_tabla": ["descripcion_tabla", "usuario_modificacion_descripcion", "fecha_modificacion_descripcion"],
      "clasificacion": ["clasificacion", "usuario_modificacion_clasif", "fecha_modificacion_clasif"],
      "descripcion_dominio": ["descripcion_dominio", "usuario_modificacion_clasif", "fecha_modificacion_clasif"],
      "etiquetas": ["etiquetas", "usuario_modificacion_etiqueta", "fecha_modificacion_etiqueta"],
    };

    if (!dict_log_cambios[cambio]) {
      console.warn("?? [actualizarTablasOficiales] 'cambio' no reconocido en dict_log_cambios:", cambio);
      return;
    }

    // 3) Construir pares a actualizar
    const camposObjetivo = dict_log_cambios[cambio];
    const array_dato_tabla_oficial = [];
    const esPersona = (cambio === "data_owner" || cambio === "data_steward");
    const esDescripcionTabla = (cambio === "descripcion_tabla");
    const valorNormalizado = esDescripcionTabla ? sanitizeDescripcionTexto(nuevo_valor) : nuevo_valor;
    const nombrePersona = esPersona ? (window.diccionarioDT?.[nuevo_valor] || "") : undefined;

    // Pares base
    const desc_cambios = [
      [cambio, valorNormalizado],
      // agregar nombre_xxx solo si corresponde (DO/DS)
      ...(esPersona ? [["nombre_" + cambio, nombrePersona]] : []),
      // usuario modificacion (penúltimo del arreglo objetivo)
      [camposObjetivo[camposObjetivo.length - 2], array_datos_usuario?.[0]],
      // fecha modificacion (último del arreglo objetivo)
      [camposObjetivo[camposObjetivo.length - 1], localISOTime],
    ];

    console.log("?? [actualizarTablasOficiales] desc_cambios (antes de filtrar a camposObjetivo)", desc_cambios);
    console.log("?? [actualizarTablasOficiales] camposObjetivo", camposObjetivo);

    // Cruzar desc_cambios con los campos admitidos para este 'cambio'
    for (let i = 0; i < camposObjetivo.length; i++) {
      const objetivo = camposObjetivo[i];
      for (let j = 0; j < desc_cambios.length; j++) {
        if (objetivo === desc_cambios[j][0]) {
          array_dato_tabla_oficial.push([objetivo, desc_cambios[j][1]]);
        }
      }
    }

    // 4) Preparar CAML
    const CAMLQuery = '<Query><Where>\
      <And>\
        <Eq><FieldRef Name="txt_desc_tabla"/><Value Type="Text">' + tabla + '</Value></Eq>\
        <And>\
          <Eq><FieldRef Name="txt_servidor"/><Value Type="Text">' + servidor + '</Value></Eq>\
          <And>\
            <Eq><FieldRef Name="txt_host"/><Value Type="Text">' + base + '</Value></Eq>\
            <Eq><FieldRef Name="txt_fuente_esquema"/><Value Type="Text">' + esquema + '</Value></Eq>\
          </And>\
        </And>\
      </And>\
    </Where></Query>';

    console.log("?? [actualizarTablasOficiales] CAMLQuery", CAMLQuery);
    console.log("?? [actualizarTablasOficiales] valuepairs", array_dato_tabla_oficial);

    // 5) Disparo a SharePoint
    $().SPServices.SPUpdateMultipleListItems({
      async: true,
      listName: "Z_METADATA_TABLAS",
      batchCmd: "Update",
      CAMLQuery: CAMLQuery,
      valuepairs: array_dato_tabla_oficial,
      completefunc: function (xData, Status) {
        console.log("? [actualizarTablasOficiales] completefunc Status:", Status);
        if (Status !== "success") {
          console.warn("?? [actualizarTablasOficiales] Respuesta no exitosa.", { xData, Status });
        } else {
          console.log("?? [actualizarTablasOficiales] Update OK para:", { tabla, servidor, base, esquema, cambio, nuevo_valor });
        }
      }
    });

  } catch (err) {
    console.error("? [actualizarTablasOficiales] ERROR", err);
  }
}


function escribirTablasOficiales(cambio, tabla, plataforma, servidor, base, esquema, descripcion) {
  //Obtengo el usuario que está haciendo los cambios
  datos_usuario = getUserAndDate();
  let array_datos_usuario = datos_usuario[0];
  let localISOTime = datos_usuario[1];

  //Crearé el nuevo registro con casi todos los campos en blanco
  array_dato_tabla_oficial = [
    ["txt_desc_tabla", tabla],
    ["descripcion_tabla", " "],
    ["usuario_modificacion_descripcion", " "],
    ["fecha_modificacion_descripcion", " "],
    ["descripcion_dominio", " "],
    ["txt_fuente_aprovisionamiento", plataforma],
    ["txt_servidor", servidor],
    ["txt_host", base],
    ["txt_fuente_esquema", esquema],
    ["data_owner", " "],
    ["nombre_data_owner", " "],
    ["usuario_modificacion_do", " "],
    ["fecha_modificacion_do", " "],
    ["data_steward", " "],
    ["nombre_data_steward", " "],
    ["usuario_modificacion_ds", " "],
    ["fecha_modificacion_ds", " "],
    ["clasificacion", " "],
    ["usuario_modificacion_clasif", " "],
    ["fecha_modificacion_clasif", " "],
    ["etiquetas", " "],
    ["usuario_modificacion_etiqueta", " "],
    ["fecha_modificacion_etiqueta", " "],
    ["avance", " "]
  ]
  //Reviso que log de cambios debo editar
  let dict_log_cambios = {
    "data_owner": ["data_owner", "nombre_data_owner", "usuario_modificacion_do", "fecha_modificacion_do"],
    "data_steward": ["data_steward", "nombre_data_steward", "usuario_modificacion_ds", "fecha_modificacion_ds"],
    "descripcion_tabla": ["descripcion_tabla", "usuario_modificacion_descripcion", "fecha_modificacion_descripcion"],
    "clasificacion": ["clasificacion", "usuario_modificacion_clasif", "fecha_modificacion_clasif"],
    "etiquetas": ["etiquetas", "usuario_modificacion_etiqueta", "fecha_modificacion_etiqueta"]
  }
  const esPersona = (cambio === "data_owner" || cambio === "data_steward");
  const esDescripcionTabla = (cambio === "descripcion_tabla");
  const valorNormalizado = esDescripcionTabla ? sanitizeDescripcionTexto(descripcion) : descripcion;
  const nombrePersona = esPersona ? (window.diccionarioDT?.[descripcion] || "") : undefined;
  //Luego actualizaré los datos que ingresó el usuario
  desc_cambios = [
    [cambio, valorNormalizado],
    ...(esPersona ? [["nombre_" + cambio, nombrePersona]] : []),
    [dict_log_cambios[cambio][dict_log_cambios[cambio].length - 2], array_datos_usuario[0]], //Aqui estoy ingresando el usuario modificacion y su codigo de empleado, por ejemplo ["usuario_modificacion_do", 20234]
    [dict_log_cambios[cambio][dict_log_cambios[cambio].length - 1], localISOTime], //Aqui estoy ingresando la fecha de modificación, por ejemplo ["fecha_modificacion_do", "2024-02-21T10:27:10.686"]
  ]
  //Recorro las variables a actualizar y las actualizo
  for (var i = 0; i < array_dato_tabla_oficial.length; i++) {
    for (var i_cambios = 0; i_cambios < desc_cambios.length; i_cambios++) {
      if (array_dato_tabla_oficial[i][0] === desc_cambios[i_cambios][0]) {
        array_dato_tabla_oficial[i][1] = desc_cambios[i_cambios][1]
      }
    }
  }
  //Finalmente escribo el nuevo registro
  $().SPServices({
    operation: "UpdateListItems",
    async: false,
    batchCmd: "New",
    listName: "Z_METADATA_TABLAS",
    valuepairs: array_dato_tabla_oficial,
    completefunc: function (xData, Status) { }
  })
}

async function getAtributosSelect() {
  const diccionario = {};
  const diccionarionombre = {};

  try {
    const resultados = await window.SqlHelper.query(
      "id, nombre, descripcion, etiqueta_tecnica",
      window.TerminosService.TABLA || "procesos_bi.dbo.T_terminos",
      "tipo = 'ATRIBUTO' AND sn_activo = 1"
    );

    if (resultados && resultados.length > 0) {
      resultados.forEach(row => {
        const codigo = row.id ? String(row.id) : "";
        const nombre = row.nombre ? String(row.nombre).trim() : "";
        const descripcion = row.descripcion ? String(row.descripcion).trim() : "";
        const etiquetaTecnica = row.etiqueta_tecnica ? String(row.etiqueta_tecnica).trim() : "";

        if (codigo && nombre) {
          diccionarionombre[nombre] = codigo;
          diccionario[codigo] = [nombre, descripcion, etiquetaTecnica];
        }
      });
    }

  } catch (error) {
    console.error("Error al obtener los atributos para el Select desde SQL:", error);
  }

  return [diccionario, diccionarionombre];
}

async function setSelectAtributos() {
  const selectAtributoWrapper = document.getElementById("select-atributo-wrapper");

  const [diccionario, diccionarionombre] = await getAtributosSelect();
  let opcionesAtributos = '<option label="&nbsp;">&nbsp;</option>';
  let opcionesEtiquetaTecnica = '<option label="&nbsp;">&nbsp;</option>';

  // Nombres ordenados alfabéticamente
  const nombres = Object.keys(diccionarionombre).sort((a, b) => a.localeCompare(b, undefined, { sensitivity: 'base' }));

  // Construcción de opciones (incluye código visible)
  nombres.forEach(nombre => {
    const codigo = diccionarionombre[nombre];
    const [_, descripcion, etiquetaTecnica] = diccionario[codigo] || ["", "", ""];

    if (nombre) {
      // Visible: Nombre — [CÓDIGO]
      opcionesAtributos += `
        <option
          value="${codigo}"
          title="${descripcion || ''}"
          data-code="${codigo}"
          data-nombre="${nombre}"
          data-etiqueta="${etiquetaTecnica || ''}"
        >
          ${nombre} — [${codigo}]
        </option>`;
    }

    if (etiquetaTecnica) {
      // Visible: EtiquetaTecnica — [CÓDIGO]
      opcionesEtiquetaTecnica += `
        <option
          value="${codigo}"
          title="${descripcion || ''}"
          data-code="${codigo}"
          data-nombre="${nombre}"
          data-etiqueta="${etiquetaTecnica}"
        >
          ${etiquetaTecnica} — [${codigo}]
        </option>`;
    }
  });

  // (Opcional) Switch para buscar por etiqueta técnica
  const checkboxEtiquetaTecnica = document.createElement('input');
  checkboxEtiquetaTecnica.type = "checkbox";
  checkboxEtiquetaTecnica.id = "checkboxEtiquetaTecnica";
  checkboxEtiquetaTecnica.onchange = function () {
    ordenarSelectAtributos(opcionesAtributos, opcionesEtiquetaTecnica);
  };

  const labelEtiquetaTecnica = document.createElement("label");
  labelEtiquetaTecnica.classList.add("m-0");
  labelEtiquetaTecnica.textContent = "Buscar por etiqueta técnica";

  const etiquetaTecnicaWrapper = document.createElement('div');
  etiquetaTecnicaWrapper.classList.add("d-flex", "align-items-center", "py-3", "w-80");
  etiquetaTecnicaWrapper.style.gap = ".25rem";
  etiquetaTecnicaWrapper.appendChild(checkboxEtiquetaTecnica);
  etiquetaTecnicaWrapper.appendChild(labelEtiquetaTecnica);

  // Si luego quieres mostrar el switch, descomenta:
  // selectAtributoWrapper.appendChild(etiquetaTecnicaWrapper);

  // Render inicial del select (tu función existente)
  ordenarSelectAtributos(opcionesAtributos, opcionesEtiquetaTecnica);
}

function ordenarSelectAtributos(opcionesNombre, opcionesEtiquetaTecnica) {
  let etiquetaTecnicaIsChecked = $("#checkboxEtiquetaTecnica").is(':checked')
  let select = document.getElementById("atributoselect");
  if (etiquetaTecnicaIsChecked) {
    select.innerHTML = opcionesEtiquetaTecnica
  } else {
    select.innerHTML = opcionesNombre
  }
}

//Funcion ordenarAtributos() - nota : Falta estilo pero ya muestra la descripcion
async function ordenarAtributos() {
  var x = document.getElementById("atributoselect");
  var option;

  // Obtener los diccionarios de la función getAtributosSelect
  let [diccionario, diccionarionombre] = await getAtributosSelect();

  // Obtener los nombres de los atributos y ordenarlos alfabéticamente
  let nombres = Object.keys(diccionarionombre);
  nombres.sort(function (a, b) {
    return a.localeCompare(b);
  });

  // Iterar sobre cada nombre y crear opciones
  nombres.forEach(nombre => {
    option = document.createElement("option");
    option.text = nombre;
    option.value = diccionarionombre[nombre];

    // Asignar el atributo title para el tooltip usando la descripción del diccionario
    let descripcion = diccionario[diccionarionombre[nombre]][1];
    option.title = descripcion;

    x.add(option);
  });
}


//funcion para cargar codigos y nombres de data owner
function getDataOwners({ codigoEmpleado = null, dataOwners = false } = {}) {
  let diccionario = {}
  let diccionarionombres = {}
  let diccionariocorreos = {}
  let diccionariousuarios = {}
  //Query para obtener el registro por codigo de empleado

  let query2 = '<Query>'
  if (codigoEmpleado) {
    query2 += `<Where><Eq><FieldRef Name="valor4"/><Value Type="text">${codigoEmpleado}</Value></Eq>`
    if (dataOwners) query2 += '<And><And><Neq><FieldRef Name="valor11" /><Value Type="text">Data User</Value></Neq><Neq><FieldRef Name="valor11" /><Value Type="text">DataUser</Value></Neq></And></And></Where>'
    else query2 += '</Where>'
  } else {
    if (dataOwners) query2 += '<Where><And><Neq><FieldRef Name="valor11" /><Value Type="text">Data User</Value></Neq><Neq><FieldRef Name="valor11" /><Value Type="text">DataUser</Value></Neq></And></Where>'
  }
  query2 += '</Query>'
  $().SPServices({
    operation: "GetListItems",
    async: false,
    listName: "LONG_LOC_MODEL_ART",
    CAMLQuery: query2,
    CAMLViewFields: "<ViewFields>\
                        <FieldRef Name='valor1' />\
                        <FieldRef Name='valor4' />\
                        <FieldRef Name='valor5' />\
                        <FieldRef Name='valor6' />\
                        <FieldRef Name='valor7' />\
                        <FieldRef Name='valor8' />\
                    </ViewFields>",
    completefunc: function (xData, Status) {
      //cargar data owners a options 
      //var x = document.getElementById("dataownerselect");
      var option;
      $(xData.responseXML).find("z\\:row").each(function () {
        let codigo = $(this).attr("ows_valor4")
        let grupo = $(this).attr("ows_valor1")
        let correo = $(this).attr("ows_valor8") ? $(this).attr("ows_valor8").toLowerCase() : undefined
        let namecompleto = String($(this).attr("ows_valor5")) + ' ' + String($(this).attr("ows_valor6")) + ' ' + String($(this).attr("ows_valor7"))
        diccionario[codigo] = namecompleto
        diccionarionombres[namecompleto] = codigo
        diccionariocorreos[codigo] = correo
        diccionariousuarios[correo] = codigo
      });
    }
  });

  //Validación si no existen datos del codigo del empleado
  if (codigoEmpleado && Object.keys(diccionario).length <= 0) return null;
  return [diccionario, diccionarionombres, diccionariocorreos, diccionariousuarios]
}

