function onlyUnique(value, index, self) {
  return self.indexOf(value) === index;
}

// Llenar el dropdown de dominios
function addDominiosFichaAtributo(dominios) {
  const $sel = $("#nombred");
  if ($sel.length === 0) return;

  $sel.empty();

  dominios.forEach(item => {
    if (typeof item === "string") {
      $sel.append(new Option(item, item, false, false));
    } else if (item && (item.id != null || item.descripcion)) {
      $sel.append(new Option(item.descripcion, item.id, false, false));
    }
  });

  if ($sel.hasClass("select2-hidden-accessible")) {
    $sel.trigger("change.select2");
  }
}

