async function getAtributosAdministrar() {
  let lista = [];

  // Nota: Si getAtributosAutorizacion() también consulta a la base de datos, 
  // es probable que debas agregarle un 'await' aquí.
  let atributosAutorizacion = typeof getAtributosAutorizacion === 'function' ? getAtributosAutorizacion() : {};

  try {
    // 1. Consultar a SQL Server usando SqlHelper
    // Traemos solo los campos necesarios y filtramos directamente por ATRIBUTO y activos
    const resultados = await window.SqlHelper.query(
      "id, tipo, nombre, descripcion, etiqueta_tecnica, dato_personal, sn_activo",
      window.TerminosService.TABLA || "procesos_bi.dbo.T_terminos",
      "tipo = 'ATRIBUTO' AND sn_activo = 1"
    );

    // 2. Mapear los resultados
    if (resultados && resultados.length > 0) {
      resultados.forEach(row => {
        // Parseamos los valores garantizando que no sean null (o los convertimos a string para mantener compatibilidad)
        let id = row.id ? String(row.id) : "";
        let tipoMetadato = row.tipo || "";
        let nombreAtributo = row.nombre || "";
        let descripcion = row.descripcion || "";
        let etiquetaTecnica = row.etiqueta_tecnica || "";
        let datoPersonal = (row.dato_personal !== null && row.dato_personal !== undefined) ? String(row.dato_personal) : "";
        let activo = (row.sn_activo !== null && row.sn_activo !== undefined) ? String(row.sn_activo) : "1";

        let atributo = {
          id,
          tipoMetadato,
          nombreAtributo,
          descripcion,
          etiquetaTecnica,
          datoPersonal,
          activo
        };

        // Verificación si ya existe una petición para ese atributo y mostrar data actualizada en la tabla
        let atributoPendiente = atributosAutorizacion[id];
        if (atributoPendiente) {
          // Soporta tanto el nombre viejo de la columna (nombre_metad) como el nuevo (nombre)
          if (atributoPendiente.cambioSolicitado === "nombre_metad" || atributoPendiente.cambioSolicitado === "nombre") {
            atributo.nombreAtributo = atributoPendiente.solicitado;
          } else {
            atributo.descripcion = atributoPendiente.solicitado;
          }
        }

        lista.push(atributo);
      });
    }
  } catch (error) {
    console.error("Error al obtener los atributos para administrar desde SQL:", error);
  }

  return lista;
}

