function generarObjetosEmpleados() {
  if (!window.empleados || window.empleados.length === 0) {
    const currentUser = window.current_user || getUserAndDate()[0][0];
    window.empleados = getEmpleados({ usuario: currentUser });
  }

  const objetoAreas = {};
  const objetoEmpleados = {};
  const objetoAreasEmpleados = {};
  const objetoUsuarioEmpleados = {};

  window.empleados.forEach((e, index) => {
    const usuarioLower = e.usuario ? e.usuario.toLowerCase() : "";

    if (!objetoAreasEmpleados[e.centroCosto]) objetoAreasEmpleados[e.centroCosto] = [];
    objetoAreasEmpleados[e.centroCosto].push({ text: e.nombreCompleto, id: e.codigo });

    if (!objetoAreas[e.codCentroCosto]) objetoAreas[e.codCentroCosto] = e.centroCosto;

    objetoEmpleados[e.codigo] = e;

    // Solo guardamos el usuarioLower si existe, para evitar guardar claves vacías
    if (usuarioLower) {
      objetoUsuarioEmpleados[usuarioLower] = e;
    }
  });

  window.objetoEmpleados = objetoEmpleados;
  window.objetoAreasEmpleados = objetoAreasEmpleados;
  window.objetoAreas = objetoAreas;
  window.objetoUsuarioEmpleados = objetoUsuarioEmpleados;
}





function clearAMC() {
  window.amcSeleccionado = false;
  window.celdaEditada = false;
  window.edited = false;
  window.currentCell = null;

  $("#amc-name").val("").trigger("change");
  $("#amc-name").attr("amc-id", "");
  $("#amc-area-solicitante").val("").trigger("change");
  $("#amc-sponsor").val("").trigger("change");
  $("#amc-formato").val("1").trigger("change");
  $("#input-adjuntar-documento").attr("url-file", "");
  $("#name-adjuntar-documento").text("");

  const currentUser = window.current_user || getUserAndDate()[0][0];
  document.getElementById("amc-user").textContent = currentUser;

  const cellElements = document.getElementsByClassName("amc-cell");
  Array.from(cellElements).forEach((e, index) => {
    cellElements[index].innerHTML = AMCCellContent({
      title: window.CELL_TITLES[index],
      data: [],
    });
  });

  $("#seguimiento-input").val(``);
  $("#seguimiento-comentario-respuesta").text(``);
  $("#seguimiento-comentario-respuesta").attr("comentario", "");
  document.getElementById("seguimiento-cancelar-respuesta").style.visibility = "hidden";
  document.getElementById("btn-clear-amc").style.visibility = "hidden";
  document.getElementById("seguimiento-conteo").textContent = "0 Entradas";
  document.getElementById("seguimiento-comentarios").innerHTML = "";

  const newUrl = window.location.origin + window.location.pathname;
  window.history.replaceState({}, document.title, newUrl);
}



