function getSuggestions({ input, users }) {
  const lowerInput = input.toLowerCase();
  return users
    .filter(user => user.keywords.some(k => k.toLowerCase().includes(lowerInput)))
    .map(user => user.label);
}


// Función para convertir un array buffer en un formato base64
function arrayBufferToBase64(buffer) {
  var binary = '';
  var bytes = new Uint8Array(buffer);
  var len = bytes.byteLength;
  for (var i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}


// Función para subir los archivos a SharePoint
function uploadFileToSharePoint(file, folderUrl, codigo) {
  var inputArchivo = document.getElementById('name-adjuntar-documento');

  // Se obtiene el valor del campo de texto
  var nombreDocumento = file.name || ""
  nombreDocumento = nombreDocumento.split(".")[0].split(" ").join("_")
  // Se valida que el campo no esté vacío
  if (nombreDocumento.trim() === "") {
    showNotification("top", "center", "info", "Por favor, ingrese una descripción para el documento.");
    return;
  }

  // Obtiene la extensión del archivo
  var fileExtension = file.name.split('.').pop().toLowerCase();

  // Array con las extensiones permitidas
  var extensiones_permitidas = ['xlsx', 'xls', 'pptx', 'ppt', 'txt', 'csv', 'pdf', 'docx'];

  // Valida si la extensión está en la lista de permitidas
  if (!extensiones_permitidas.includes(fileExtension)) {
    showNotification("top", "center", "danger", "La extensión del archivo no es válida. Por favor, suba un archivo con extensión xlsx , xls , pptx, txt , docx o csv");
    // Limpia el input y el texto del nombre mostrado
    $("#input-adjuntar-documento").val("");
    $("#name-adjuntar-documento").text("");
    return false;
  }
  // Crea el nuevo nombre del archivo con la extensión original
  var newFileName = nombreDocumento + "." + fileExtension;


  // Se crea una instancia FileReader() que permite la lectura del archivo
  var reader = new FileReader();

  // Permite leer el contenido de un archivo y devolver los datos en forma de ArrayBuffer.
  reader.readAsArrayBuffer(file);
  var fileCreationUrl = ``

  // Se ejecuta una vez que los documentos estén completamente leídos.
  reader.onload = function (e) {
    // Obtiene el contenido del archivo
    var fileContent = e.target.result;

    inputArchivo.textContent = file.name;

    // Convierte el contenido en base64
    var fileBase64 = arrayBufferToBase64(new Uint8Array(fileContent));

    // Crea el archivo en la carpeta
    fileCreationUrl = `${folderUrl}/${codigo}_${newFileName}`

    $().SPServices({
      operation: "CopyIntoItems",
      SourceUrl: fileCreationUrl,
      DestinationUrls: [fileCreationUrl],
      Stream: fileBase64,
      async: false,
      completefunc: function (xData, Status) {
        if (Status === "success") {
          // Muestra la notificación
          showNotification("top", "center", "success", `Su documento ${newFileName} subio con éxito.`);
          // Limpia el campo de texto
          $("#name-adjuntar-documento").text("");
        } else {
          showNotification("top", "center", "danger", "Error al cargar el archivo.");
        }
      }
    });
    $("#input-adjuntar-documento").attr("url-file", fileCreationUrl)
  };
  return fileCreationUrl;
}

function formatDate(date, reverse = false) {
  const day = String(date.getDate()).padStart(2, '0');
  const month = String(date.getMonth() + 1).padStart(2, '0'); // Los meses empiezan en 0
  const year = date.getFullYear();
  if (reverse) return `${year}-${month}-${day}`
  return `${day}-${month}-${year}`;
}

function parseCommentDate(raw) {
  if (!raw) return null;
  const safe = String(raw).trim();
  if (!safe) return null;
  if (safe.endsWith('Z') || /[+-]\d{2}:?\d{2}$/.test(safe)) {
    return new Date(safe);
  }
  if (safe.includes('T')) {
    return new Date(`${safe}Z`);
  }
  return new Date(safe);
}

function getFormattedDate({ date = null, hour = false }) {
  if (!date) return null;

  const options = { day: '2-digit', month: 'short', year: 'numeric' };
  let formattedDate = date.toLocaleDateString('es-EC', options).replace(',', '');

  if (hour) {
    const time = date.toLocaleTimeString('es-EC', { hour: '2-digit', minute: '2-digit', hour12: false });
    formattedDate += ` ${time}`;
  }

  return formattedDate;
}

function getNextIdAMC({ list = [], parameter = null }) {
  const user = (window.current_user || "").toString().toLowerCase();
  if (!parameter) return user ? `${user}-1` : "1";
  let maxSeq = 0;
  (list || []).forEach((entity = {}) => {
    const raw = entity[parameter] || "";
    const match = String(raw).match(/^[^-]+-(\d+)$/);
    if (match && match[1]) {
      const n = parseInt(match[1], 10);
      if (!Number.isNaN(n)) maxSeq = Math.max(maxSeq, n);
    } else {
      const n = parseInt(raw, 10);
      if (!Number.isNaN(n)) maxSeq = Math.max(maxSeq, n);
    }
  });
  const next = maxSeq + 1;
  return user ? `${user}-${next}` : String(next);
}

function getMaximoIdComentarioAMC() {
  const comentariosAMC = getComentariosAMC();
  let idMaximo = 0;
  comentariosAMC.forEach(e => {
    if (e.id_comentario > idMaximo) idMaximo = e.id_comentario;
  })
}

function getMaxParameter({ list = null, parameter = null }) {
  if (!list || !parameter) return;
  let maxParameter = 0;
  list.forEach(e => {
    if (parseInt(e[parameter]) > maxParameter) maxParameter = parseInt(e[parameter])
  })
  return parseInt(maxParameter)
}

function setOpcionesSelect({
  idSelect = "",
  dataSelect = []
}) {
  const select = $(`#${idSelect}`)
  select.empty();
  select.append(new Option("", "", false, false))
  dataSelect.forEach(opcion => {
    const opcionSelect = new Option(opcion.text, opcion.id, false, false);
    select.append(opcionSelect)
  })

  select.trigger("change")
}

function guardarAMC(divId) {
  const originalContent = document.body.innerHTML;
  const printContent = document.getElementById(divId).outerHTML;

  document.body.innerHTML = printContent; // Reemplaza todo el contenido del body
  window.print(); // Ejecuta la impresión
  document.body.innerHTML = originalContent; // Restaura el contenido original
}

// Funcion para obtener todos los amc o uno en especifico
function getAnalyticsModelCanvas({ idAMC = null, nombreAMC = null, username = null } = {}) {
  let query = "";

  if (idAMC) {
    query = `<Query><Where><Eq><FieldRef Name="id_amc"/><Value Type="Text">${idAMC}</Value></Eq></Where></Query>`;
  } else if (nombreAMC) {
    query = `<Query><Where><Eq><FieldRef Name="nombre_amc"/><Value Type="Text">${nombreAMC}</Value></Eq></Where></Query>`;
  } else if (username) {
    query = `<Query><Where><BeginsWith><FieldRef Name="id_amc"/><Value Type="Text">${username}-</Value></BeginsWith></Where></Query>`;
  } else if (username) {
    query = `<Query><Where><BeginsWith><FieldRef Name="usuario_creacion"/><Value Type="Text">${username}</Value></BeginsWith></Where></Query>`;
  }


  const analyticsModelCanvas = [];
  $().SPServices({
    operation: "GetListItems",
    async: false,
    listName: "Z_ANALYTICS_MODEL_CANVAS",
    CAMLQuery: query,
    CAMLViewFields: "<ViewFields>\
                        <FieldRef Name='id_amc' />\
                        <FieldRef Name='nombre_amc' />\
                        <FieldRef Name='area_solicitante' />\
                        <FieldRef Name='sponsor' />\
                        <FieldRef Name='formato' />\
                        <FieldRef Name='decisiones' />\
                        <FieldRef Name='predicciones' />\
                        <FieldRef Name='tareas' />\
                        <FieldRef Name='evaluacion_desarrollo' />\
                        <FieldRef Name='propuesta_valor' />\
                        <FieldRef Name='fuentes_datos' />\
                        <FieldRef Name='caracteristicas_reentrenamiento' />\
                        <FieldRef Name='recoleccion_informacion' />\
                        <FieldRef Name='tiempos_responsables' />\
                        <FieldRef Name='monitoreo_creacion_valor' />\
                        <FieldRef Name='evaluacion' />\
                        <FieldRef Name='usuario_creacion' />\
                        <FieldRef Name='fecha_creacion' />\
                        <FieldRef Name='usuario_ultima_modificacion' />\
                        <FieldRef Name='fecha_ultima_modificacion' />\
                        <FieldRef Name='estado' />\
                        <FieldRef Name='usuarios_permisos' />\
                    </ViewFields>",
    completefunc: function (xData, Status) {
      $(xData.responseXML).find("z\\:row").each(function () {
        const data = {
          idAMC: $(this).attr("ows_id_amc") || "",
          nombreAMC: $(this).attr("ows_nombre_amc") || "",
          areaSolicitante: $(this).attr("ows_area_solicitante") || "",
          sponsor: ($(this).attr("ows_sponsor") || "").toLowerCase(),
          formato: $(this).attr("ows_formato") || "",
          decisiones: $(this).attr("ows_decisiones") || "",
          predicciones: $(this).attr("ows_predicciones") || "",
          tareas: $(this).attr("ows_tareas") || "",
          evaluacionDesarrollo: $(this).attr("ows_evaluacion_desarrollo") || "",
          propuestaValor: $(this).attr("ows_propuesta_valor") || "",
          fuentesDatos: $(this).attr("ows_fuentes_datos") || "",
          caracteristicasReentrenamiento: $(this).attr("ows_caracteristicas_reentrenamiento") || "",
          recoleccionInformacion: $(this).attr("ows_recoleccion_informacion") || "",
          tiemposResponsables: $(this).attr("ows_tiempos_responsables") || "",
          monitoreoCreacionValor: $(this).attr("ows_monitoreo_creacion_valor") || "",
          evaluacion: $(this).attr("ows_evaluacion") || "",
          usuarioCreacion: ($(this).attr("ows_usuario_creacion") || "").toLowerCase(),
          fechaCreacion: $(this).attr("ows_fecha_creacion") || "",
          usuarioUltimaModificacion: $(this).attr("ows_usuario_ultima_modificacion") || "",
          fechaUltimaModificacion: $(this).attr("ows_fecha_ultima_modificacion") || "",
          estado: $(this).attr("ows_estado") || "",
          usuariosPermisos: $(this).attr("ows_usuarios_permisos") || "",
        };
        analyticsModelCanvas.push(data);
      });
    },
  });

  return analyticsModelCanvas;
}

