function setComentariosAMC(comentarios) {
  const folderUrl = `${BASE_URL}docs/AnalyticsModelCanvas`;
  let html = '';
  let respuestas = [];
  document.getElementById("seguimiento-conteo").textContent = comentarios.length + ' Entradas';
  document.getElementById("seguimiento-conteo").textContent = `${comentarios.length} ${comentarios.length === 1 ? "Entrada" : "Entradas"}`;
  if (comentarios.length === 0) {
    return;
  }
  document.getElementById("seguimiento-comentarios").innerHTML = "";

  const sortedComments = comentarios.sort((a, b) => new Date(b.fechaComentario) - new Date(a.fechaComentario))
  $.each(sortedComments, function (index, item) {
    const fechaFormateada = getFormattedDate({ date: parseCommentDate(item.fechaComentario), hour: true })
    if (item.idPadre === "0") {
      const progreso = (parseFloat(item.progresoSeguimiento) * 100);
      // <span style="font-size:10px;" class="font-weight-bold">${progreso}%</span>\
      const comentario = item.comentario.trim() || 'Sin comentarios'
      const commentCard = document.createElement("div")
      commentCard.id = `comment-card-${item.idComentario}`
      commentCard.className = "custom-card mb-2 d-flex p-2 flex-row"
      commentCard.style = "gap:1rem; box-shadow:none !important; background-color: gray !important; background-color:#e7effe !important;"

      commentCard.innerHTML = `
            <div class="avatar">\
              <img src="img/Data Science_38.svg" alt="Author">\
            </div>\
            <div class="d-flex w-100 comentario-text-wrapper">\
              <div class="d-flex flex-column w-75">
                <span class="font-weight-bold comentario-author">${item.autorComentarioNombres}</span>
                <span class="comentario-date">${fechaFormateada}</span>
                <span class="comentario-texto">${comentario}</span>\
                ${item.documentoAdjunto ? `<a class="text-primary comentario-adjunto" href="${folderUrl}/${item.documentoAdjunto}" target="_blank" id="documento-adjunto">Documento Adjunto</a>` : ""}\
              </div>
            </div>\
        `


      const button = document.createElement("button")
      button.className = "d-flex btn-reply-comment comentario-action-btn"
      button.innerHTML = `<i class="iconsminds-left-1 text-primary"></i>`
      button.addEventListener("click", function () {
        responderComentario(item.idComentario)
      })

      commentCard.querySelector(".comentario-text-wrapper").appendChild(button)

      if ((item.autorComentarioUsuario || "").toLowerCase() === (window.current_user || "").toLowerCase()) {
        const editBtn = document.createElement("button")
        editBtn.className = "d-flex btn-edit-comment comentario-action-btn"
        editBtn.innerHTML = `<i class="simple-icon-pencil"></i>`

        const saveBtn = document.createElement("button")
        saveBtn.className = "d-flex btn-save-comment comentario-action-btn"
        saveBtn.style = "display:none;"
        saveBtn.innerHTML = `<i class="simple-icon-check"></i>`

        editBtn.addEventListener("click", function () {
          console.log("EDITAR comentario -> id_comentario:", item.idComentario, "spItemId:", item.spItemId, "id_amc:", item.idAmc, "id_padre:", item.idPadre);
          const textWrapper = commentCard.querySelector(".comentario-text-wrapper .d-flex.flex-column.w-75");
          const span = textWrapper.querySelector(".comentario-texto");
          if (!span) return;
          const textarea = document.createElement("textarea");
          textarea.className = "form-control comentario-edit-textarea";
          textarea.value = item.comentario || "";
          textWrapper.replaceChild(textarea, span);
          editBtn.style.display = "none";
          button.style.display = "none";
          saveBtn.style.display = "flex";
          textarea.focus();
        });

        saveBtn.addEventListener("click", function () {
          const textWrapper = commentCard.querySelector(".comentario-text-wrapper .d-flex.flex-column.w-75");
          const textarea = textWrapper.querySelector("textarea");
          if (!textarea) return;
          const nuevo = (textarea.value || "").trim();
          if (!nuevo) {
            return showNotification("top", "center", "info", "Debe escribir un comentario.", 2000);
          }
          guardarEdicionComentario({
            item,
            nuevoTexto: nuevo,
            onFinish: function () {
              setComentariosAMC(getComentariosAMC({ amcId: item.idAmc }));
            }
          });
        });

        const deleteBtn = document.createElement("button")
        deleteBtn.className = "d-flex btn-delete-comment comentario-action-btn"
        deleteBtn.innerHTML = `<i class="simple-icon-trash"></i>`
        deleteBtn.addEventListener("click", function () {
          const ok = confirm("Se eliminara este comentario. Desea continuar?");
          if (!ok) return;
          updateComentarioOGA_SQL({
            data: { sn_activo: 0 },
            condicion: `id_comentario='${escapeSqlValue(item.idComentario)}' AND id_oga='${escapeSqlValue(item.idAmc)}'`,
            onSuccess: function () {
              setComentariosAMC(getComentariosAMC({ amcId: item.idAmc }));
            }
          });
        });

        commentCard.querySelector(".comentario-text-wrapper").appendChild(editBtn)
        commentCard.querySelector(".comentario-text-wrapper").appendChild(saveBtn)
        commentCard.querySelector(".comentario-text-wrapper").appendChild(deleteBtn)
      }
      document.getElementById("seguimiento-comentarios").appendChild(commentCard);
    } else {
      respuestas.unshift(item)
    }
  })
  $.each(respuestas, function (index, item) {
    const fechaFormateada = getFormattedDate({ date: parseCommentDate(item.fechaComentario), hour: true })
    const comentario = item.comentario.trim() || 'Sin comentarios'
    const respuesta = `<div class="custom-card mb-2 d-flex p-2 flex-row" style="margin-left:4rem !important; gap:1rem; box-shadow:none !important; background-color: gray !important; background-color:#fae5f0 !important;" id="${item.idComentario}">\
            <div class="avatar">\
              <img src="img/Data Science_38.svg" alt="Author">\
            </div>\
            <div class="d-flex w-100 comentario-text-wrapper">\
              <div class="d-flex flex-column w-75 comentario-content">\
                <span class="font-weight-bold comentario-author">${item.autorComentarioNombres}</span>
                <span class="comentario-date">${fechaFormateada}</span>
                <span class="comentario-texto"> ${comentario} </span>\
                  ${item.documentoAdjunto ? `<a class="text-primary comentario-adjunto" href="${folderUrl}/${item.documentoAdjunto}" target="_blank" id="documento-adjunto">Documento Adjunto</a>` : ""}\
              </div>\
              <div class="d-flex align-items-start ml-auto comentario-actions"></div>\
            </div>\
          </div>`
    $(`#comment-card-${item.idPadre}`).after(respuesta);
    if ((item.autorComentarioUsuario || "").toLowerCase() === (window.current_user || "").toLowerCase()) {
      const safeId = (window.CSS && CSS.escape) ? CSS.escape(item.idComentario) : item.idComentario;
      const wrapper = document.querySelector(`#${safeId} .comentario-text-wrapper`);
      const content = document.querySelector(`#${safeId} .comentario-content`);
      const actions = document.querySelector(`#${safeId} .comentario-actions`);
      if (wrapper && content && actions) {
        const editBtn = document.createElement("button")
        editBtn.className = "d-flex btn-edit-comment comentario-action-btn"
        editBtn.innerHTML = `<i class="simple-icon-pencil"></i>`

        const saveBtn = document.createElement("button")
        saveBtn.className = "d-flex btn-save-comment comentario-action-btn"
        saveBtn.style = "display:none;"
        saveBtn.innerHTML = `<i class="simple-icon-check"></i>`

        editBtn.addEventListener("click", function () {
          console.log("EDITAR comentario -> id_comentario:", item.idComentario, "spItemId:", item.spItemId, "id_amc:", item.idAmc, "id_padre:", item.idPadre);
          const span = content.querySelector(".comentario-texto");
          if (!span) return;
          const textarea = document.createElement("textarea");
          textarea.className = "form-control comentario-edit-textarea";
          textarea.value = item.comentario || "";
          content.replaceChild(textarea, span);
          editBtn.style.display = "none";
          saveBtn.style.display = "flex";
          textarea.focus();
        });

        saveBtn.addEventListener("click", function () {
          const textarea = content.querySelector("textarea");
          if (!textarea) return;
          const nuevo = (textarea.value || "").trim();
          if (!nuevo) {
            return showNotification("top", "center", "info", "Debe escribir un comentario.", 2000);
          }
          guardarEdicionComentario({
            item,
            nuevoTexto: nuevo,
            onFinish: function () {
              setComentariosAMC(getComentariosAMC({ amcId: item.idAmc }));
            }
          });
        });

        const deleteBtn = document.createElement("button")
        deleteBtn.className = "d-flex btn-delete-comment comentario-action-btn"
        deleteBtn.innerHTML = `<i class="simple-icon-trash"></i>`
        deleteBtn.addEventListener("click", function () {
          updateComentarioOGA_SQL({
            data: { sn_activo: 0 },
            condicion: `id_comentario='${escapeSqlValue(item.idComentario)}' AND id_oga='${escapeSqlValue(item.idAmc)}'`,
            onSuccess: function () {
              setComentariosAMC(getComentariosAMC({ amcId: item.idAmc }));
            }
          });
        });

        actions.appendChild(editBtn);
        actions.appendChild(saveBtn);
        actions.appendChild(deleteBtn);
      }
    }
  });
}

function AnalyticsModelCanvas() {
  // Load additional scripts if needed
  loadScript("js/custom-js/twitter-text-3.1.0.min.js");

  // Get AMC ID from URL
  const queryString = window.location.search;
  const urlParams = new URLSearchParams(queryString);
  const amcId = urlParams.get("amc") || -1;

  // Fetch AMC data by ID only if valid (avoid useless query)
  const analyticsModelCanvas = amcId !== -1 ? getAnalyticsModelCanvasAPI({ idAMC: amcId, useCache: false })[0] : null;

  // Determine current user
  const currentUser = window.current_user || getUserAndDate()[0][0];

  // Fetch ONLY current user's employee data (cache it if not already)
  if (!window.empleados || window.empleados[0]?.usuario !== currentUser) {
    window.empleados = getEmpleados({ usuario: currentUser });
  }

  // Initialize global variables and UI states
  window.amcSeleccionado = false;
  window.celdaEditada = false;
  window.edited = false;
  window.currentCell = null;
  window.CELL_TITLES = [
    "DECISIONES", "PREDICCIONES", "TAREAS", "EVALUACIÓN EN DESARROLLO",
    "PROPUESTA DE VALOR", "FUENTES DE DATOS", "CARACTERÍSTICAS PARA EL MODELO",
    "RECOLECCIÓN DE INFORMACIÓN", "TIEMPOS Y RESPONSABLES",
    "MONITOREO DE CREACIÓN DE VALOR", "EVALUACIÓN EN LÍNEA"
  ];

  // Set current user in the UI
  document.getElementById("amc-user").textContent = currentUser;
  $("#amc-user").attr("text-value", "");

  // Perform additional setup actions
  clearAMC();
  listenerAMC();

  // Ensure window.objetoAMC exists
  if (!window.objetoAMC) {
    window.objetoAMC = {};
  }

  // If AMC is found, load it into the canvas
  if (analyticsModelCanvas) {
    reloadAMC(amcId);
    window.amcSeleccionado = true;
  }

  // Register visit for tracking purposes
  registrar_visita("Analytics Model Canvas");
}



