function getDocumentsAMC({ amcId = null } = {}) {
  const documents = []
  const comments = getComentariosAMC({ amcId })
  const analyticsModelCanvas = listToObject({ lista: getAnalyticsModelCanvasAPI(), parametroClave: "idAMC" })
  comments.forEach(e => {

    const amc = analyticsModelCanvas[e.idAmc] || {}
    if (e.documentoAdjunto) {

      const data = {
        "nombre": e.documentoAdjunto.split(".")[0],
        "usuario": e.autorComentarioNombres,
        "fecha": formatDate(new Date(e.fechaComentario)),
        "amcId": amc.idAMC || "",
        "amcName": amc.nombreAMC || "",
        "url": `${BASE_URL}docs/AnalyticsModelCanvas/${e.documentoAdjunto}`,
      }
      documents.push(data)
    }

  })
  return documents
}

function getDataFichaAMC({ useCache = true, cacheMs = 15000, forceRefresh = false } = {}) {
  if (useCache && !forceRefresh && AMC_FICHA_CACHE.data && (Date.now() - AMC_FICHA_CACHE.ts) < cacheMs) {
    return AMC_FICHA_CACHE.data;
  }

  const analyticsModelCanvas = getAnalyticsModelCanvasAPI({ useCache: true, cacheMs });
  const commentsIdAMC = {};
  const documentsIdAMC = {};

  getComentariosAMC().forEach((comment) => {
    if (!commentsIdAMC[comment.idAmc]) commentsIdAMC[comment.idAmc] = [];
    commentsIdAMC[comment.idAmc].push(comment);

    if (comment.documentoAdjunto && !documentsIdAMC[comment.idAmc]) documentsIdAMC[comment.idAmc] = [];
    if (comment.documentoAdjunto) documentsIdAMC[comment.idAmc].push(comment);
  });

  // Usa los objetos generados por generarObjetosEmpleados()
  const employeesUser = window.objetoUsuarioEmpleados || {};
  const employeesCode = window.objetoEmpleados || {};

  const formatObject = getCatalogoOGASUITE("10");

  analyticsModelCanvas.forEach((amc, index) => {
    const comments = commentsIdAMC[amc.idAMC] || [];
    const documents = documentsIdAMC[amc.idAMC] || [];

    amc.fechaCreacion = formatDate(new Date(amc.fechaCreacion));
    amc.formato = formatObject[amc.formato] || amc.formato;
    amc.comentarios = comments.length || 0;

    // ?? PASAR SIEMPRE A LOWERCASE LOS USUARIOS QUE VIENEN DE SHAREPOINT
    const usuarioCreacionLower = amc.usuarioCreacion ? amc.usuarioCreacion.toLowerCase() : "";
    const sponsorLower = typeof amc.sponsor === 'string' ? amc.sponsor.toLowerCase() : amc.sponsor;
    amc.areaUsuarioCreacion = (employeesUser[usuarioCreacionLower] || { centroCosto: "" }).centroCosto;
    amc.areaSolicitante = (employeesCode[sponsorLower] || { centroCosto: amc.areaSolicitante }).centroCosto;
    amc.sponsor = (employeesCode[sponsorLower] || { usuario: sponsorLower }).usuario;

    amc["documentosAdjuntos"] = documents.length || 0;
  });

  AMC_FICHA_CACHE.data = analyticsModelCanvas;
  AMC_FICHA_CACHE.ts = Date.now();
  AMC_FICHA_CACHE.ttlMs = cacheMs;
  return analyticsModelCanvas;
}




