function showNotification(placementFrom, placementAlign, type, message, delay) {
  // Si el plugin bootstrap-notify no está cargado, muestra un toast simple.
  if (typeof $ === "undefined" || typeof $.notify !== "function") {
    if (!document.getElementById("ogl-notification-container")) {
      const container = document.createElement("div");
      container.id = "ogl-notification-container";
      container.style.position = "fixed";
      container.style.top = "1rem";
      container.style.left = "50%";
      container.style.transform = "translateX(-50%)";
      container.style.zIndex = "9999";
      container.style.display = "flex";
      container.style.flexDirection = "column";
      container.style.alignItems = "center";
      container.style.gap = "0.35rem";
      container.style.pointerEvents = "none";
      document.body.appendChild(container);
    }
    const container = document.getElementById("ogl-notification-container");
    const toast = document.createElement("div");
    toast.textContent = message || "";
    toast.style.padding = "0.65rem 1rem";
    toast.style.borderRadius = "0.5rem";
    toast.style.minWidth = "220px";
    toast.style.color = "#fff";
    toast.style.boxShadow = "0 8px 16px rgba(0,0,0,0.15)";
    toast.style.opacity = "0";
    toast.style.transition = "all 0.3s ease";
    toast.style.transform = "translateY(4px)";
    switch ((type || "").toLowerCase()) {
      case "success":
        toast.style.background = "#0f9d58";
        break;
      case "warning":
        toast.style.background = "#f4b400";
        break;
      case "danger":
      case "error":
        toast.style.background = "#d93025";
        break;
      default:
        toast.style.background = "#3c4043";
    }
    container.appendChild(toast);
    requestAnimationFrame(() => {
      toast.style.opacity = "1";
      toast.style.transform = "translateY(0)";
    });
    setTimeout(() => {
      toast.style.opacity = "0";
      toast.style.transform = "translateY(-6px)";
      toast.addEventListener("transitionend", () => toast.remove());
    }, delay || 4000);
    return;
  }

  $.notify(
    {
      title: "Notificación",
      message: message
    },
    {
      element: "body",
      type: type,
      placement: {
        from: "top",
        align: "center"
      },
      z_index: 9999,
      animate: {
        enter: "animated fadeInDown",
        exit: "animated fadeOutUp"
      },
      autoHideDelay: delay || 5000,
    }
  );
}

function esNombreDuplicado(nombre, tipo, idActual) {
  if (!nombre) return false;

  const lista = window.glosario?.todos || [];
  const comparacion = nombre.trim().replaceAll("<br>", "").toLowerCase();
  const tipoComparacion = (tipo || "").trim().toUpperCase();

  return lista.some(item => {
    const itemId = item.id || (typeof item.attr === 'function' ? (item.attr("ows_ID") || item.attr("ows_id_metad")) : null);
    if (itemId && idActual && itemId.toString() === idActual.toString()) return false;
    const itemTipoRaw = item.tipo || (typeof item.attr === 'function' ? item.attr("ows_tipo_metad") : "");
    const itemTipo = (itemTipoRaw || "").trim().toUpperCase();
    if (itemTipo !== tipoComparacion) return false;
    const itemNombreRaw = item.nombre || (typeof item.attr === 'function' ? item.attr("ows_nombre_metad") : "");
    const itemNombre = (itemNombreRaw || "").replaceAll("<br>", "").trim().toLowerCase();
    return itemNombre === comparacion;
  });
}

function obtenerDatosUsuario(entrada) {
  let usuario = "";
  let correo = "";
  let datosUsuario = null;

  // Caso 1: Si se pasa correo completo
  if (entrada && entrada.includes("@")) {
    correo = entrada;
    usuario = correo.split("@")[0].toLowerCase();
  }
  // Caso 2: Si se pasa solo el usuario (sin @)
  else if (entrada) {
    usuario = entrada.toLowerCase();
    correo = usuario + "@bancoguayaquil.com"; // ajusta el dominio si es otro
  }
  // Caso 3: No se pasó nada ? obtener usuario actual
  else {
    const loginName = $().SPServices.SPGetCurrentUser(); // ejemplo: "DOMINIO\\usuario"
    usuario = loginName.split("\\").pop().toLowerCase();
    correo = usuario + "@bancoguayaquil.com";
  }

  const query = `<Query>
                     <Where>
                       <Eq>
                         <FieldRef Name="USUARIO"/>
                         <Value Type="Text">${usuario}</Value>
                       </Eq>
                     </Where>
                   </Query>`;

  $().SPServices({
    operation: "GetListItems",
    async: false,
    listName: "Z_DATOS_EMPLEADOS",
    CAMLQuery: query,
    CAMLViewFields:
      "<ViewFields>\
                          <FieldRef Name='CODIGO_EMPLEADO' />\
                          <FieldRef Name='NOMBRE_COMPLETO' />\
                          <FieldRef Name='COD_CENTRO_COSTO' />\
                          <FieldRef Name='CENTRO_COSTO' />\
                          <FieldRef Name='CARGO' />\
                          <FieldRef Name='USUARIO' />\
                          <FieldRef Name='JEFE' />\
                          <FieldRef Name='ESTADO' />\
                          <FieldRef Name='AGENCIA' />\
                          <FieldRef Name='REGION' />\
                          <FieldRef Name='BANCA' />\
                          <FieldRef Name='CORREO' />\
                          <FieldRef Name='NOMBRES' />\
                          <FieldRef Name='APELLIDO_PATERNO' />\
                          <FieldRef Name='APELLIDO_MATERNO' />\
                          <FieldRef Name='FECHA_INGRESO' />\
                          <FieldRef Name='LOCALIDAD' />\
                          <FieldRef Name='CODIGO_CARGO' />\
                      </ViewFields>",
    completefunc: function (xData, Status) {
      const row = $(xData.responseXML).find("z\\:row").first();

      if (row.length > 0) {
        datosUsuario = {
          codigo: row.attr("ows_CODIGO_EMPLEADO") || "",
          nombreCompleto: row.attr("ows_NOMBRE_COMPLETO") || "",
          centroCosto: row.attr("ows_CENTRO_COSTO") || "",
          codCentroCosto: row.attr("ows_COD_CENTRO_COSTO") || "",
          cargo: row.attr("ows_CARGO") || "",
          usuario: (row.attr("ows_USUARIO") || "").toLowerCase(),
          jefe: row.attr("ows_JEFE") || "",
          estado: row.attr("ows_ESTADO") || "",
          area: row.attr("ows_BANCA") || "",
          agencia: row.attr("ows_AGENCIA") || "",
          region: row.attr("ows_REGION") || "",
          correo: correo,
          nombres: row.attr("ows_NOMBRES") || "",
          apellido_paternal: row.attr("ows_APELLIDO_PATERNO") || "",
          apellido_maternal: row.attr("ows_APELLIDO_MATERNO") || "",
          fecha_ingreso: row.attr("ows_FECHA_INGRESO") || "",
          localidad: row.attr("ows_LOCALIDAD") || "",
          codCargo: row.attr("ows_CODIGO_CARGO") || "",
        };
      }
    },
  });

  return datosUsuario;
}

